(258, 'wp_2fa_policy', 'a:38:{s:18:"enforcement-policy";s:14:"do-not-enforce";s:14:"excluded_users";a:0:{}s:14:"excluded_roles";a:0:{}s:14:"enforced_users";a:0:{}s:14:"enforced_roles";a:0:{}s:12:"grace-period";i:3;s:24:"grace-period-denominator";s:4:"days";s:22:"enable_destroy_session";s:0:"";s:12:"limit_access";s:0:"";s:11:"enable_rest";b:0;s:19:"brute_force_disable";s:0:"";s:28:"2fa_settings_last_updated_by";s:0:"";s:13:"2fa_main_user";s:0:"";s:24:"grace-period-expiry-time";s:0:"";s:14:"plugin_version";s:5:"3.1.1";s:26:"delete_data_upon_uninstall";s:0:"";s:21:"skip_2fa_for_passkeys";i:1;s:14:"excluded_sites";a:0:{}s:14:"included_sites";a:0:{}s:23:"create-custom-user-page";s:2:"no";s:25:"redirect-user-custom-page";s:0:"";s:32:"redirect-user-custom-page-global";s:0:"";s:20:"custom-user-page-url";s:0:"";s:19:"custom-user-page-id";s:0:"";s:18:"hide_remove_button";s:0:"";s:27:"separate-multisite-page-url";s:0:"";s:12:"grace-policy";s:16:"use-grace-period";s:20:"superadmins-role-add";s:2:"no";s:24:"superadmins-role-exclude";s:2:"no";s:22:"method_invalid_setting";s:11:"login_block";s:20:"backup_codes_enabled";s:3:"yes";s:12:"enable_email";s:12:"enable_email";s:18:"specify-email_hotp";b:0;s:15:"enable_passkeys";b:0;s:11:"enable_totp";s:11:"enable_totp";s:18:"wp_2fa_white_label";a:51:{s:22:"default-text-code-page";s:343:"<p>Please enter the two-factor authentication (2FA) verification code below to login. Depending on your 2FA setup, you can get the code from the 2FA app or it was sent to you by email.</p><p><strong>Note: if you are supposed to receive an email but did not receive any, please click the Resend Code button to request another code.</strong></p>";s:31:"default-text-pw-reset-code-page";s:361:"<p>You have been sent a one-time code via email. Please enter the code below and then click Get New Password to proceed with the password reset.</p><br><p><strong>Note: If you have not received the code please click the button Resend Code. If you still do not get the code after pressing the button, please contact the website&#039;s administrator.</strong></p>";s:27:"default-2fa-required-notice";s:278:"<p>This website&#039;s administrator requires you to enable two-factor authentication (2FA) {grace_period_remaining}.</p><br><p>Failing to configure 2FA within this time period will result in a locked account. For more information, please contact your website administrator.</p>";s:35:"default-2fa-resetup-required-notice";s:278:"<p>This website&#039;s administrator requires you to enable two-factor authentication (2FA) {grace_period_remaining}.</p><br><p>Failing to configure 2FA within this time period will result in a locked account. For more information, please contact your website administrator.</p>";s:25:"custom-text-app-code-page";s:343:"<p>Please enter the two-factor authentication (2FA) verification code below to login. Depending on your 2FA setup, you can get the code from the 2FA app or it was sent to you by email.</p><p><strong>Note: if you are supposed to receive an email but did not receive any, please click the Resend Code button to request another code.</strong></p>";s:27:"custom-text-email-code-page";s:343:"<p>Please enter the two-factor authentication (2FA) verification code below to login. Depending on your 2FA setup, you can get the code from the 2FA app or it was sent to you by email.</p><p><strong>Note: if you are supposed to receive an email but did not receive any, please click the Resend Code button to request another code.</strong></p>";s:24:"default-backup-code-page";s:33:"Enter a backup verification code.";s:21:"enable_wizard_styling";s:21:"enable_wizard_styling";s:14:"show_help_text";s:14:"show_help_text";s:18:"enable_wizard_logo";s:0:"";s:22:"hide_page_generated_by";b:0;s:14:"enable_welcome";s:0:"";s:7:"welcome";s:0:"";s:16:"method_selection";s:107:"<h3>Choose the 2FA method</h3>There are {available_methods_count} methods available to choose from for 2FA:";s:17:"no_further_action";s:37:"<h3>Congratulations! You are all set.";s:18:"2fa_required_intro";s:476:"<h3>You are required to configure 2FA.</h3><p>In order to keep this site - and your details secure, this website’s administrator requires you to enable 2FA authentication to continue.</p><p>Two factor authentication ensures only you have access to your account by creating an added layer of security when logging in - <a href="https://melapress.com/wordpress-2fa/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=learn_more" target="_blank" rel="noopener">Learn more</a></p>";s:17:"2fa_wizard_cancel";s:62:"<h3>Are you sure?</h3><p>Any unsaved changes will be lost!</p>";s:17:"2fa_wizard_logout";s:88:"<h3>Are you sure?</h3><p>That will terminate your session and log you out of the WP.</p>";s:10:"custom_css";s:0:"";s:16:"login_custom_css";s:0:"";s:14:"logo-code-page";s:0:"";s:18:"logo-code-page-url";s:0:"";s:17:"disable_login_css";s:0:"";s:18:"login-to-view-area";s:59:"<p>You must be logged in to view this page. {login_url}</p>";s:32:"user-profile-form-preamble-title";s:34:"Two-factor authentication settings";s:31:"user-profile-form-preamble-desc";s:78:"Add two-factor authentication to strengthen the security of your user account.";s:22:"use_custom_2fa_message";s:12:"use-defaults";s:24:"backup_codes_intro_multi";s:292:"<h3>Your login just got more secure</h3><p>It is recommended to configure a backup 2FA method in case you do not have access to the primary 2FA method to generate a code to log in. You can configure any of the below. You can always configure any or both from your user profile page later.</p>";s:18:"backup_codes_intro";s:183:"<h3>Your login just got more secure</h3><p>Congratulations! You have enabled two-factor authentication for your user. You’ve just helped towards making this website more secure!</p>";s:27:"backup_codes_intro_continue";s:530:"<h3>Your login just got more secure</h3><p>Congratulations! You have enabled two-factor authentication for your user. You’ve just helped towards making this website more secure!</p><p>You should now generate the list of backup method. Although this is optional, it is highly recommended to have a secondary 2FA method. This can be used as a backup should the primary 2FA method fail. This can happen if, for example, you forget your smartphone, the smartphone runs out of battery, or there are email deliverability problems.</p>";s:27:"backup_codes_generate_intro";s:154:"<h3>Generate list of backup codes</h3><p>It is recommended to generate and print some backup codes in case you lose access to your primary 2FA method.</p>";s:22:"backup_codes_generated";s:65:"<h3>Backup codes generated</h3><p>Here are your backup codes:</p>";s:26:"backup_codes-select-method";s:238:"Login with a backup code: you will get 10 backup codes and you can use one of them when you need to login and you cannot generate a code from the app. <a href="https://melapress.com/2fa-backup-codes/" target="_blank">More information.</a>";s:23:"backup-codes-login-text";s:22:"Or, use a backup code.";s:22:"method_help_hotp_intro";s:125:"<h3>Setting up HOTP ({email-option-label})</h3><p>Please select the email address where the one-time code should be sent:</p>";s:21:"method_help_hotp_help";s:265:"To complete the 2FA configuration you will be sent a one-time code over email, therefore you should have access to the mailbox of this email address. If you do not receive the email with the one-time code please check your spam folder and contact your administrator";s:27:"method_help_hotp_help_email";s:149:"<b>IMPORTANT</b><p>To ensure you always receive the one-time code whitelist the email address from which the codes are sent. This is {from_email}</p>";s:28:"method_verification_hotp_pre";s:112:"<h3>Almost there…</h3><p>Please type in the one-time code sent to your email address to finalize the setup</p>";s:22:"hotp_reconfigure_intro";s:196:"<h3>{reconfigure_or_configure_capitalized} one-time code over email method</h3><p>Click the below button to {reconfigure_or_configure} the email address where the one-time code should be sent.</p>";s:18:"email-option-label";s:23:"One-time code via email";s:23:"email-option-label-hint";s:0:"";s:21:"passkeys-option-label";s:8:"Passkeys";s:22:"method_help_totp_intro";s:48:"<h3>Setting up TOTP (one-time code via app)</h3>";s:23:"method_help_totp_step_1";s:49:"Download and start the application of your choice";s:23:"method_help_totp_step_2";s:131:"From within the application scan the QR code provided on the left. Otherwise, enter the following code manually in the application:";s:23:"method_help_totp_step_3";s:110:"Click the "I\'m ready" button below when you complete the application setup process to proceed with the wizard.";s:28:"method_verification_totp_pre";s:122:"<h3>Almost there…</h3><p>Please type in the one-time code from your chosen authentication app to finalize the setup.</p>";s:22:"totp_reconfigure_intro";s:286:"<h3>{reconfigure_or_configure_capitalized} the 2FA App</h3><p>Click the below button to {reconfigure_or_configure} the current 2FA method. Note that once reset you will have to re-scan the QR code on all devices you want this to work on because the previous codes will stop working.</p>";s:17:"totp-option-label";s:25:"One-time code via 2FA app";s:27:"method_help_totp_more_intro";s:2445:"			<p class="description">Click on the icon of the app that you are using for a detailed guide on how to set it up.</p>\n			<table class="apps-wrapper">\n				<tr>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#authy" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/authy-logo.png"></a>\n					</td>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#google" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/google-logo.png"></a>\n					</td>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#microsoft" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/microsoft-logo.png"></a>\n					</td>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#duo" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/duo-logo.png"></a>\n					</td>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#lastpass" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/lastpass-logo.png"></a>\n					</td>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#freeotp" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/free-otp-logo.png"></a>\n					</td>\n									<td>\n					<a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=authentication_help#okta" target="_blank" class="app-logo"><img src="https://berkhamcouns.wpenginepowered.com/wp-content/plugins/wp-2fa/dist/images/okta-logo.png"></a>\n					</td>\n								</tr>\n			</table>\n			";s:22:"totp-option-label-hint";s:293:"Refer to the <a href="https://melapress.com/support/kb/wp-2fa-configuring-2fa-apps/?&utm_source=plugin&utm_medium=wp2fa&utm_campaign=guide_how_to_setup_2fa_apps_3" target="_blank">guide on how to set up 2FA apps</a> for more information on how to setup these apps and which apps are supported.";}s:30:"grace-policy-notification-show";s:24:"after-login-notification";s:17:"re-login-2fa-show";s:17:"re-login-2fa-show";}', 'off'),
