(312, 'edd_sl_4a8b1ead98ec280b99cdd80f2c62cf4c', 'a:2:{s:7:"timeout";i:1772021267;s:5:"value";s:73006:"{"name":"perfmatters","new_version":"2.5.7","stable_version":"2.5.7","sections":{"description":"<p><a href=\\"https:\\/\\/perfmatters.io\\/\\">Perfmatters<\\/a> is a lightweight web performance plugin designed to help increase Google Core Web Vitals scores and fine-tune how assets load on your site.<\\/p>\\n<h4> Features <\\/h4>\\n<ul>\\n<li>Easy quick toggle options to turn off resources that shouldn\'t be loading. <\\/li>\\n<li>Disable scripts and plugins on a per post\\/page or sitewide basis with the Script Manager. <\\/li>\\n<li>Add and optimize code snippets (PHP, CSS, JS, and HTML), only load where needed.<\\/li>\\n<li>Defer and delay JavaScript, including third-party scripts.<\\/li>\\n<li>Automatically remove unused CSS.<\\/li>\\n<li>Minify JavaScript and CSS.<\\/li>\\n<li>Preload resources, critical images, and prerender links for quicker load times.<\\/li>\\n<li>Lazy load images and enable click-to-play thumbnails on videos.<\\/li>\\n<li>Host Google Analytics and Google Fonts locally.<\\/li>\\n<li>Change your WordPress login URL. <\\/li>\\n<li>Disable and limit WordPress revisions.<\\/li>\\n<li>Add code to your header, body, and footer.<\\/li>\\n<li>Optimize your database.<\\/li>\\n<\\/ul>\\n<h4> Documentation <\\/h4>\\n<p>Check out our <a href=\\"https:\\/\\/perfmatters.io\\/docs\\/\\">documentation<\\/a> for more information on how to use Perfmatters.<\\/p>","changelog":"<h4> 2.5.7 - 02.02.2026 <\\/h4>\\n<ul>\\n<li>Fixed an issue where the auto size attribute value was being added to images with no specified dimensions which could cause the image to display incorrectly.<\\/li>\\n<li>Fixed an issue where the attribute parser would ignore attribute values containing new line characters.<\\/li>\\n<li>Fixed an issue with certain attribute characters being disallowed preventing the attribute from migrating to the final element tag.<\\/li>\\n<\\/ul>\\n<h4> 2.5.6 - 01.28.2026 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_cdn_url filter along with new helper methods in the CDN class.<\\/li>\\n<li>Added the ability to completely disable Perfmatters code features using the new PERFMATTERS_DISABLE_CODE constant.<\\/li>\\n<li>Added confirmation message when turning on FastClick option.<\\/li>\\n<li>Added logic to remove the previous stored author ID when a code snippet is imported.<\\/li>\\n<li>Added host name to global settings and code snippet export files.<\\/li>\\n<li>Added additional logic to add an auto value to lazy loaded images sizes attributes when needed.<\\/li>\\n<li>Added separate used CSS generated files for different WooCommerce product types.<\\/li>\\n<li>Added dynamic request check in heartbeat function to prevent a possible PHP error.<\\/li>\\n<li>Updated lazy loading class to no longer add noscript tags by default for images and iframes to reduce HTML page size. The perfmatters_lazyload_noscript filter can still be used to turn that behavior back on.<\\/li>\\n<li>Updated get_atts_array utility method to use regex instead of wp_kses_hair for better compatibility.<\\/li>\\n<li>Reworked code snippet error handling class to work better with other exception handlers and existing error reporting.<\\/li>\\n<li>Turned off CSSLint in the code snippet editor, as it is outdated and was leading to false positives.<\\/li>\\n<li>Adjusted gutter column layout in the code snippet editor to be more consistent between different code types.<\\/li>\\n<li>Adjusted code snippet priority field to allow both negative and zero input values.<\\/li>\\n<li>Fixed an issue where CSS code snippets set to run in the footer were not having their conditions checked.<\\/li>\\n<li>Fixed an issue where CSS code snippets were not always printing where expected based on the set location and priority.<\\/li>\\n<li>Fixed an issue with certain code snippet input fields not being escaped properly in the UI leading to a broken layout in some cases.<\\/li>\\n<li>Fixed an issue where YouTube iframes rendered with a preview thumbnail that had autoplay forced off in their query string would require a double click.<\\/li>\\n<li>Fixed an issue where the referrerpolicy iframe attribute did not get applied to the generated iframe when using YouTube preview thumbnails.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.5.5 - 12.11.2025 <\\/h4>\\n<ul>\\n<li>Added new Code Settings options to Import and Export Perfmatters code snippets.<\\/li>\\n<li>Added support to export individual snippets, a subset of snippets through a bulk action, or all stored snippets from the new Code Settings export button.<\\/li>\\n<li>Added code snippets admin bar menu item that will show up if at least one snippet is present.<\\/li>\\n<li>Added frontend footer and admin footer locations for CSS code snippets.<\\/li>\\n<li>Added new PMMU_PLUGIN_DIR constant to allow for manipulation of the MU plugin file location for specific setups where the standard WPMU_PLUGIN_DIR may be altered.<\\/li>\\n<li>Added a REST API exception for Mollie.<\\/li>\\n<li>Added additional built-in CSS selector exclusions for Elementor\'s background slideshow.<\\/li>\\n<li>Added support for relative path URLs found inside stylesheets printed inline with our perfmatters_rucss_inline_stylesheets filter.<\\/li>\\n<li>Updated previous Separate Block Styles option which will now show up as a Block Style Behavior dropdown for sites running WordPress 6.9+.<\\/li>\\n<li>Fixed an issue in the code snippets editor where lint markers were not always correctly displaying for HTML and CSS snippets.<\\/li>\\n<li>Fixed an issue where the code snippet editor was pushing new lines off screen in some cases and not automatically scrolling to keep things in view.<\\/li>\\n<li>Fixed an issue where HTML code snippets were not able to save a non-default location.<\\/li>\\n<li>Fixed an issue with general Perfmatters admin notices not displaying correctly.<\\/li>\\n<li>Fixed multiple duplicate ID warnings in the plugin UI.<\\/li>\\n<li>Fixed multiple jQuery deprecation warnings in plugin UI JavaScript.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.5.4 - 11.20.2025 <\\/h4>\\n<ul>\\n<li>Moved code snippet storage location out of cache directory and into the uploads folder to prevent data loss in certain environments.<\\/li>\\n<li>Fixed a code snippets compatibility issue with servers that don\'t support PHP OPcache.<\\/li>\\n<li>Fixed an issue where the CodeMirror editor was not always initializing correctly when editing an individual code snippet.<\\/li>\\n<li>Fixed an issue where the code type tag prefix was not updating when changing the code type while creating a new code snippet.<\\/li>\\n<li>Fixed an issue in the error handling class where the exception handler was looping in certain instances and throwing an error.<\\/li>\\n<\\/ul>\\n<h4> 2.5.3 - 11.19.2025 <\\/h4>\\n<ul>\\n<li>Added new Code Snippets (BETA) feature, which is now the default view in the Code tab. You can now create and manage PHP, JS, CSS, and HTML code snippets from inside Perfmatters. We store and load code snippets using a flat-file method and directly integrate with all of our existing optimization options for the best performance.<\\/li>\\n<li>Moved the existing header, body, and footer code boxes to Code &gt; Global Scripts.<\\/li>\\n<li>Made style adjustments throughout the plugin UI.<\\/li>\\n<li>Added built-in CSS selector exclusion for GeneratePress mobile menu.<\\/li>\\n<li>Added new get_file_path utility method for use in various functions that need to determine the local file path for an asset loading on the front end.<\\/li>\\n<li>Fixed an issue where missing image dimensions were not getting applied correctly for sites inside a subdirectory.<\\/li>\\n<li>Removed BETA tag from Cloudflare Early Hints option.<\\/li>\\n<li>Updated EDD plugin updater class to version 1.9.4.<\\/li>\\n<\\/ul>\\n<h4> 2.5.2 - 10.23.2025 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_rucss_inline_stylesheets filter which allows you to inline any stylesheet already excluded from used CSS.<\\/li>\\n<li>Reworked the Script Manager input change event listener for better compatibility with other JavaScript running while the Script Manager is being used.<\\/li>\\n<li>Added new delay JS quick exclusion for GenerateBlocks Pro.<\\/li>\\n<li>Added built-in CSS selector exclusion for GenerateBlocks mobile menu.<\\/li>\\n<li>Added built-in stylesheet exclusion for GeneratePress local fonts.<\\/li>\\n<li>Updated WS Form Pro delay JS quick exclusion to fix a console error.<\\/li>\\n<li>Fixed some incorrect wording in the clear used CSS tooltip.<\\/li>\\n<\\/ul>\\n<h4> 2.5.1 - 09.29.2025 <\\/h4>\\n<ul>\\n<li>Added a fetchpriority high attribute on critically preloaded image tags to match the preload link attribute.<\\/li>\\n<li>Added new buffer function to check the viewport meta tag position and adjust it if needed when critical image preloads are being used.<\\/li>\\n<li>Added logic to populate critical image preload href attribute with the fallback image src if the preload is for a responsive image srcset.<\\/li>\\n<li>Added built-in stylesheet exclusion for GeneratePress offside menu.<\\/li>\\n<li>Updated delay JS quick exclusion for Elementor to include e-gallery.<\\/li>\\n<li>Fixed a PHP warning that could sometimes happen when calculating the root directory path in the Utilities class.<\\/li>\\n<li>Fixed a trailing slash validation warning coming from critical image preload tags.<\\/li>\\n<li>Disabled Remove Comment URLs toggle when Kadence is active due to an incompatibility.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.5.0 - 08.26.2025 <\\/h4>\\n<ul>\\n<li>Added new WP-CLI subcommands to clear-minified-js, clear-minified-css, and clear-local-fonts.<\\/li>\\n<li>Added support for targeting header element when using parent selector matching functions.<\\/li>\\n<li>Added support to enable and disable the clean uninstall option in WP-CLI.<\\/li>\\n<li>Added a built-in Script Manager rule to prevent dashicons from being dequeued when logged in.<\\/li>\\n<li>Fixed a WP-CLI issue where license activation and deactivation subcommands were not working correctly. <\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.9 - 08.12.2025 <\\/h4>\\n<ul>\\n<li>Rolled back CSS parsing library one version (8.9.0) to fix a conflict with WooCommerce.<\\/li>\\n<\\/ul>\\n<h4> 2.4.8 - 08.11.2025 <\\/h4>\\n<ul>\\n<li>Added built-in stylesheet exclusion for Bricks layer stylesheets.<\\/li>\\n<li>Adjusted emoji_svg_url filter to only return false outside the admin dashboard.<\\/li>\\n<li>Updated delay JS quick exclusion for Bricks to include splide.<\\/li>\\n<li>Updated delay JS quick exclusion for CookieYes to be more compatible.<\\/li>\\n<li>Updated early hint attribute check to include sizes and media attributes.<\\/li>\\n<li>Updated CSS parsing library to the latest version (9.0.0). New features, deprecation removals and bug fixes.<\\/li>\\n<li>Updated deprecated function in CSS class to use current method.<\\/li>\\n<li>Updated minification library to the latest version (1.3.75).<\\/li>\\n<li>Updated minimum PHP version requirement to 7.2.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.7 - 07.15.2025 <\\/h4>\\n<ul>\\n<li>Added support to set the Perfmatters license key via wp-config.php using the PERFMATTERS_LICENSE_KEY constant.<\\/li>\\n<li>Added new perfmatters_fetch_priority filter.<\\/li>\\n<li>Added integration to send an early hint header for used CSS file when both features are enabled.<\\/li>\\n<li>Added additional check for imagesrcset attribute when determining if an image should receive an early hint.<\\/li>\\n<li>Added crossorigin and fetchpriority attributes to early hint headers.<\\/li>\\n<li>Added additional parameters to excluded page builders array for Thrive Quiz Builder and Etch.<\\/li>\\n<li>Added built-in stylesheet exclusions for Elementor and Astra local fonts.<\\/li>\\n<li>Cleaned up leftover test file missed in previous update.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.6 - 06.17.2025 <\\/h4>\\n<ul>\\n<li>Added new advanced preload option to enable Cloudflare Early Hints (BETA) for Perfmatters preloads along with controls to limit which file types will have early hint link headers sent.<\\/li>\\n<li>Added new WP-CLI import-settings subcommand to import a settings configuration from an exported .json file.<\\/li>\\n<li>Added new WP-CLI disable and enable subcommands to modify certain plugin options. Available options can be printed out with the new get-options subcommand.<\\/li>\\n<li>Added new delay JS quick exclusion for SureCart.<\\/li>\\n<li>Added additional logic to disable speculative loading on WooCommerce cart and checkout URLs.<\\/li>\\n<li>Added additional logic to allow fallback deferral exclusions as part of an existing delay JS quick exclusion.<\\/li>\\n<li>Added built-in exclusion for Gravity Forms to prevent optimization features from running on AJAX form requests.<\\/li>\\n<li>Updated CSS parsing library to the latest version (8.8.0). Bug fixes and deprecations.<\\/li>\\n<li>Adjusted placement of perfmatters_preloads filter which was running too early and causing some filter snippets to be ignored.<\\/li>\\n<li>Increased default delay timeout from 10 to 15 seconds to improve compatibility.<\\/li>\\n<li>Fixed an issue with certain parent selector matching functions where a child element selector tag would also be replaced if it had the exact same selector tag HTML as the matched parent tag.<\\/li>\\n<li>Fixed multiple redundant calls to retrieve Script Manager settings row when loading the Script Manager UI.<\\/li>\\n<\\/ul>\\n<h4> 2.4.5 - 05.16.2025 <\\/h4>\\n<ul>\\n<li>Added some compatibility logic to fix an issue with specific caching plugins that were not working correctly with Perfmatters output buffer functions.<\\/li>\\n<li>Fixed a PHP translation warning that was coming from some post meta UI functions running too early.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.4 - 05.08.2025 <\\/h4>\\n<ul>\\n<li>Added new Exclude Leading option for CSS background images.<\\/li>\\n<li>Added new perfmatters_lazyload_parent_exclusions filter.<\\/li>\\n<li>Added new perfmatters_css_background_selectors filter.<\\/li>\\n<li>Added new speculative loading mode option to disable the feature entirely.<\\/li>\\n<li>Refactored lazy element method to be more efficient when searching for multiple element selectors.<\\/li>\\n<li>Reworked the perfmatters_critical_image_parent_exclusions and perfmatters_leading_image_parent_exclusions filters to no longer need to process the page HTML through DOMDocument for better stability, faster parsing, and 30% less code.<\\/li>\\n<li>Fixed an issue with parent selector matching for fetch priority and lazy loading where only the first image tag would match if it was inside a nested container element.<\\/li>\\n<li>Fixed an issue where the CSS Background class would get added to child elements as well if they also contained a matching selector.<\\/li>\\n<li>Fixed a compatibility issue when using Perfmatters preloads alongside WP Rocket.<\\/li>\\n<li>Fixed a spacing issue with input row checkboxes in the plugin UI.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.3 - 04.15.2025 <\\/h4>\\n<ul>\\n<li>Added new preload options to control Speculative Loading mode and eagerness settings for sites running WordPress 6.8+.<\\/li>\\n<li>Deprecated Instant Page option throughout the plugin for sites running WordPress 6.8+.<\\/li>\\n<li>Added a REST API exception for Slider Revolution.<\\/li>\\n<li>Updated delay JS quick exclusions for ShortPixel Adaptive Images and Slider Revolution to be more compatible.<\\/li>\\n<\\/ul>\\n<h4> 2.4.2 - 04.02.2025 <\\/h4>\\n<ul>\\n<li>Fixed an issue where mobile event handlers were sometimes preventing the delayed click from firing.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.1 - 03.26.2025 <\\/h4>\\n<ul>\\n<li>Refactored delay JS inline script, removed pageshow event listener, and uglified final code, reducing the script size by over 15%.<\\/li>\\n<li>Added built-in JS deferral exclusion for Cloudflare Turnstile.<\\/li>\\n<li>Added new delay JS quick exclusion for Plausible Analytics.<\\/li>\\n<li>Updated delay JS quick exclusions for Fluent Forms and Kadence Blocks to be more compatible.<\\/li>\\n<li>Adjusted document.write built-in delay exclusion to prevent false positives.<\\/li>\\n<li>Adjusted MU Mode documentation links in the Script Manager to go to specific anchor link sections.<\\/li>\\n<li>Fixed an issue where encoded data attribute values weren\'t being preserved correctly when converting an elements attribute string to an array.<\\/li>\\n<li>Fixed a multisite issue where the root directory path was not determined correctly when using a custom content directory setup.<\\/li>\\n<li>Deployed a secondary API that can be used when the client has issues communicating with our licensing server (usually due to firewalls).<\\/li>\\n<li>Removed deprecated SVG duotone filter removal actions from global styles toggle and updated tooltip to reflect changes.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.0 - 02.26.2025 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_rucss_async_stylesheets filter which allows you to async any stylesheet already excluded from used CSS.<\\/li>\\n<li>Dashicons and Elementor animation stylesheets are now loaded via async for better performance when Removed Unused CSS is turned on.<\\/li>\\n<li>Added additional logic to better handle stylesheets with media query attributes when including them in used CSS for increased performance. WooCommerce users may need to clear their used CSS if mobile-specific stylesheets are being loaded as they have been removed from our built-in exclusions.<\\/li>\\n<li>Added new built-in stylesheet exclusion for Bricks post-specific CSS.<\\/li>\\n<li>Added new Delay JS quick exclusion for WPBakery.<\\/li>\\n<li>Added a REST API exception for SureCart.<\\/li>\\n<li>Added additional compatibility styles to the Script Manager.<\\/li>\\n<li>Made some changes to be able to start our main output buffer a bit earlier in the load for better compatibility with other plugins that modify the HTML document.<\\/li>\\n<li>Updated clean uninstall function with current post meta options.<\\/li>\\n<li>Fixed an issue where the Clear Used CSS meta button was not working correctly for certain URL types.<\\/li>\\n<li>Fixed a PHP warning coming from certain rewrite rule formats when MU Mode was turned on.<\\/li>\\n<li>Removed BETA tag from preload lazy elements option.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<\\/ul>\\n<h4> 2.3.9 - 02.06.2025 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_preloads_array filter.<\\/li>\\n<li>Added new perfmatters_minify_threshold filter.<\\/li>\\n<li>Added additional swiper JavaScript file to Elementor quick exclusion.<\\/li>\\n<li>Added additional built-in CSS selector exclusion for WP Armour.<\\/li>\\n<li>Added a string check to login URL filter function to prevent a possible PHP error.<\\/li>\\n<li>Fixed an issue where new user email requests were not being allowed through the redirect block when using a custom login URL.<\\/li>\\n<li>Minor adjustment to CDN rewrite regex to fix an issue that was happening when the home URL was different from the site URL.<\\/li>\\n<li>Removed Ezoic quick exclusion and moved to built-in deferral and delay exclusions.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.8 - 01.07.2025 <\\/h4>\\n<ul>\\n<li>Added a REST API exception for SureForms.<\\/li>\\n<li>Added a UI button to cancel the current database optimization process.<\\/li>\\n<li>Added built-in delay JS exclusion for document.write for compatibility.<\\/li>\\n<li>Updated background processing library to the latest version (1.4.0).<\\/li>\\n<li>Fixed an issue where some deliberate redirect requests were not being allowed to access the hidden login URL.<\\/li>\\n<li>Fixed an issue where the database optimization process was not starting correctly in some cases.<\\/li>\\n<li>Fixed a missing anchor link pointing to the license tab in our plugin settings UI.<\\/li>\\n<\\/ul>\\n<h4> 2.3.7 - 01.01.2025 <\\/h4>\\n<ul>\\n<li>Added additional CSS background image inline styles to account for backgrounds set on pseudo-elements of children inside the targeted container.<\\/li>\\n<li>Added WP Rocket filter to disable their critical image optimization when preload critical images is active to prevent conflicts.<\\/li>\\n<li>Added new Delay JS quick exclusion for Ezoic.<\\/li>\\n<li>Added built-in minify JS exclusion for WP Recipe Maker.<\\/li>\\n<li>Updated network default function to preserve the CDN URL if already set on the target subsite.<\\/li>\\n<li>Updated admin bar menu items to show clear all used CSS on the front end.<\\/li>\\n<li>Updated minify exclusion functions to check the entire attribute string of the script or stylesheet instead of just the source URL.<\\/li>\\n<li>Updated CSS parsing library to the latest version (8.7.0). Improves support for PHP 8.4.<\\/li>\\n<li>Updated login URL feature with additional check to prevent access to the hidden login slug via an authentication request redirected from a query string.<\\/li>\\n<li>Updated buffer class to prevent running on Bricks template URLs.<\\/li>\\n<li>Fixed an issue where the Used CSS file was sometimes getting falsely flagged as completely unused on certain speed tests.<\\/li>\\n<li>Removed unnecessary documentWrite handling function from delay JS inline script to reduce the size by over 8%.<\\/li>\\n<li>Removed older changelog entries in readme.txt file and added link to web version.<\\/li>\\n<\\/ul>\\n<h4> 2.3.6 - 11.21.2024 <\\/h4>\\n<ul>\\n<li>Fixed an issue where Delay JS wasn\'t running correctly in some cases.<\\/li>\\n<li>Updated EDD plugin updater class to version 1.9.2.<\\/li>\\n<\\/ul>\\n<h4> 2.3.5 - 11.21.2024 <\\/h4>\\n<ul>\\n<li>Added new local Google Font option to Limit Subsets that are downloaded and included in the stylesheet.<\\/li>\\n<li>Added new local Google font option to change the Print Method with options for file and inline.<\\/li>\\n<li>Added new Priority option to manual preloads which can be used to add a specific fetchpriority attribute value to individual preload tags.<\\/li>\\n<li>Added new perfmatters_lazy_element_selectors filter.<\\/li>\\n<li>Removed unnecessary trailing link tag from delayed stylesheets when using Remove Unused CSS.<\\/li>\\n<li>Removed crossorigin option for manual preloads. The attribute is now automatically added to fetch and font preload tags.<\\/li>\\n<li>Increased action button response message timeout to 10 seconds in plugin UI.<\\/li>\\n<li>Fixed a PHP warning coming from Disable Google Maps function if a post ID was not found on a single post URL.<\\/li>\\n<li>Fixed an issue with WordPress 6.7.1 where the text domain for translations was loading too early.<\\/li>\\n<li>Removed deprecated plugin option to load Google fonts asynchronously.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.4 - 10.10.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_lazy_elements filter.<\\/li>\\n<li>Added new perfmatters_is_woocommerce filter.<\\/li>\\n<li>Added additional built-in stylesheet and selector exclusions for better compatibility with Elementor animations.<\\/li>\\n<li>Added WP Rocket filter to disable lazy render when lazy elements feature is active to prevent conflicts.<\\/li>\\n<li>Added additional parameter to excluded page builders array for tagDiv Composer.<\\/li>\\n<li>Added built-in delay JS exclusion for lazy elements inline script.<\\/li>\\n<li>Moved plugin settings logo SVG back to inline to prevent file_get_contents errors in certain environments.<\\/li>\\n<li>Adjusted built-in CSS dynamic selector exclusions to fix some minor visual issues with a few page builders.<\\/li>\\n<li>Fixed a JavaScript error that would sometimes show up in the console when using Delay JS with click delay enabled.<\\/li>\\n<li>Fixed an issue where a used stylesheet path would still attempt to load even if no used styles had been picked up for the URL.<\\/li>\\n<li>Fixed an issue where browser-specific stylesheets inside HTML comments were getting parsed by our used CSS library.<\\/li>\\n<li>Fixed a MU Mode issue where exceptions would not be applied correctly if a query string was present on the home URL if set to show the latest posts.<\\/li>\\n<li>Fixed an issue where preloading a JS file by the handle was not loading the minified version when necessary.<\\/li>\\n<\\/ul>\\n<h4> 2.3.3 - 08.28.2024 <\\/h4>\\n<ul>\\n<li>Added new lazy loading advanced beta options to manage Lazy Elements which will allow for element chains in the DOM to be lazy loaded until they enter the viewport.<\\/li>\\n<li>Separated out built-in CSS selector exclusions by URL type for increased performance on single and front pages.<\\/li>\\n<li>Optimized plugin logo and other SVG image files.<\\/li>\\n<li>Added fetchpriority high attribute automatically on critically preloaded image links.<\\/li>\\n<li>Added support for delaying script modules.<\\/li>\\n<li>Added additional jQuery sticky JavaScript file to Elementor quick exclusion.<\\/li>\\n<li>Added new Delay JS quick exclusions for Fluent Forms and Fluent Forms Pro.<\\/li>\\n<li>Integrated get_atts_array utility function into lazyload class to prevent redundancy.<\\/li>\\n<li>Fixed an issue where smaller size files were sometimes not being replaced with the minified version for increased performance.<\\/li>\\n<li>Fixed an issue where the preload location label was overlapping the input field for certain languages.<\\/li>\\n<li>Made adjustments to option management to prevent autoloading of certain options going forward where it is not needed.<\\/li>\\n<li>Removed various manual preload types that are no longer supported by most major browsers.<\\/li>\\n<\\/ul>\\n<h4> 2.3.2 - 07.30.2024 <\\/h4>\\n<ul>\\n<li>Updated CSS parsing library to the latest version (8.6.0) which should help with correctly parsing mathematical operations inside CSS property values.<\\/li>\\n<li>Added additional parameter to excluded page builders array for GenerateBlocks and TranslatePress.<\\/li>\\n<li>Added additional built-in deferral exclusion for jqueryParams inline script.<\\/li>\\n<li>Added Delay JS quick exclusion for the Kadence menu.<\\/li>\\n<li>Fixed a MU Mode issue where home page exceptions would not be applied correctly if a query string was present in the requested URL.<\\/li>\\n<li>Fixed an undefined array key warning coming from the minify class.<\\/li>\\n<li>Fixed a minify error that would show up when a prospective file did not have any content.<\\/li>\\n<li>Fixed an issue where having Remove Unused CSS turned on with no stylesheets loading would return a blank screen.<\\/li>\\n<li>Fixed a CSS error that would show up when trying to determine the current page ID when the queried post was null.<\\/li>\\n<li>Fixed an issue where the CSS class would attempt to retrieve the contents of a stylesheet even if it didn\'t exist.<\\/li>\\n<li>Fixed an issue where minified files would not get picked up by the CDN rewriter.<\\/li>\\n<li>Removed unnecessary minify library .git directories from the plugin.<\\/li>\\n<li>Minor style adjustments to the plugin UI.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.1 - 06.27.2024 <\\/h4>\\n<ul>\\n<li>Added new Minify JS and Minify CSS features along with options to exclude specific files from minification and clear generated minified files when necessary.<\\/li>\\n<li>UI Updates: What was previously the Assets tab has now been replaced by three more specific tabs, JavaScript, CSS, and Code. The main Script Manager toggle has been moved to Tools. Additional subheaders have also been added throughout to help with organization.<\\/li>\\n<li>Added new perfmatters_minify_js filter.<\\/li>\\n<li>Added new perfmatters_minify_js_exclusions filter.<\\/li>\\n<li>Added new perfmatters_minify_css filter.<\\/li>\\n<li>Added new perfmatters_minify_css_exclusions filter.<\\/li>\\n<li>Added a REST API exception for Independent Analytics.<\\/li>\\n<li>Added additional request parameter for Divi to excluded page builders array.<\\/li>\\n<li>Added built-in critical image exclusion for WPML flag images.<\\/li>\\n<li>Added Delay JS quick exclusion for Grow for WordPress.<\\/li>\\n<li>Updated used CSS function to generate a separate file for each post type archive instead of a single shared stylesheet.<\\/li>\\n<li>Fixed an issue that was causing an incorrect root directory to be returned for some environments.<\\/li>\\n<li>Fixed an issue with preload and lazyload parent exclusion filters that was preventing them from excluding images correctly in some cases.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.0 - 05.23.2024 <\\/h4>\\n<ul>\\n<li>Added a new function to verify the preferred content type from the HTTP header when determining if JSON is being requested. This should improve compatibility with certain hosting providers.<\\/li>\\n<li>Added an additional check when removing unused CSS to avoid parsing print-only stylesheets.<\\/li>\\n<li>Updated Delay JS quick exclusion for Termageddon + UserCentrics for better compatibility.<\\/li>\\n<li>Removed option to disable wlwmanifest link output as that function was deprecated in WordPress 6.3.<\\/li>\\n<li>Fixed an issue that was preventing lazy loaded images from displaying when defer inline scripts was enabled.<\\/li>\\n<li>Fixed an issue where responsive styles for YouTube preview thumbnails were not printing on certain themes using responsive embeds.<\\/li>\\n<li>Fixed an issue with DOMDocument where HTML entities coming from inline styles would display as their encoded values.<\\/li>\\n<li>Fixed a missing tooltip on the scan database option.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.9 - 05.16.2024 <\\/h4>\\n<ul>\\n<li>Fixed an issue that could cause a conflict with other JS deferral solutions when running at the same time.<\\/li>\\n<\\/ul>\\n<h4> 2.2.8 - 05.16.2024 <\\/h4>\\n<ul>\\n<li>Added new Defer JavaScript option to Include Inline Scripts.<\\/li>\\n<li>Added new option to Separate Block Styles.<\\/li>\\n<li>Added additional built-in CSS selector exclusions for Splide.<\\/li>\\n<li>Updated Delay JS quick exclusion for Kadence Blocks with additional scripts.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Updated deferral exclusion check to work with entire tag instead of just src URL.<\\/li>\\n<li>Moved to printing responsive embed styles for YouTube preview thumbnails in all cases for better compatibility.<\\/li>\\n<li>Fixed an issue where the CDN rewrite was not picking up URLs with a relative protocol.<\\/li>\\n<li>Fixed an issue where an existing data-wp-strategy attribute would prevent a script from being able to be deferred.<\\/li>\\n<li>Fixed an issue where the Script Manager was not giving the right feedback on save when a new line character was showing up in the AJAX response.<\\/li>\\n<li>Fixed an issue on the network settings page where incorrect tab content would show up after saving.<\\/li>\\n<li>Fixed an issue where the license tab was showing up at the subsite level if the plugin was not network activated in a multisite environment.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.7 - 04.19.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_used_css_below filter.<\\/li>\\n<li>Added new perfmatters_defer_js_exclusions filter.<\\/li>\\n<li>Added new perfmatters_delay_js_fastclick filter.<\\/li>\\n<li>Added additional DOMDocument flag to parent exclusion filters for better compatibility.<\\/li>\\n<li>Added GiveWP request parameter to excluded page builders array.<\\/li>\\n<li>Updated Delay JS quick exclusion for WooCommerce Single Product Gallery with additional scripts to help with zoom and lightbox functionality.<\\/li>\\n<li>Updated Delay JS quick exclusion for Cookie Notice with additional scripts.<\\/li>\\n<li>Moved Script Manager CSS to stylesheet printed inline instead of from a PHP file.<\\/li>\\n<\\/ul>\\n<h4> 2.2.6 - 03.18.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_defer_jquery filter.<\\/li>\\n<li>Added Delay JS quick exclusion for Monumetric Ads.<\\/li>\\n<li>Updated content URL reference to use content_url function instead of constant when generating root directory path.<\\/li>\\n<li>Updated local stylesheet URL replace function to be case insensitive.<\\/li>\\n<li>Updated new parent exclusion filters to use DOMDocument instead of regex to allow support for targeting images inside nested containers.<\\/li>\\n<li>Fixed an issue where certain scripts were not being deferred properly when delay JavaScript option was also enabled.<\\/li>\\n<li>Fixed an issue where abnormal image URLs would sometimes generate a warning when trying to parse for image dimensions.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.5 - 02.29.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_critical_image_parent_exclusions filter.<\\/li>\\n<li>Added new perfmatters_leading_image_parent_exclusions filter.<\\/li>\\n<li>Added new Disable Core Fetch option to disable the fetch priority attribute added by WordPress core.<\\/li>\\n<li>Added built-in WooCommerce CSS selector exclusion for better compatibility on single product posts.<\\/li>\\n<li>Added Breakdance request parameters to excluded page builders array.<\\/li>\\n<li>Added a REST API exception for WP Recipe Maker.<\\/li>\\n<li>Added Delay JS quick exclusions for Kadence Blocks and Kadence Blocks Pro.<\\/li>\\n<li>Added CSS Background Image support for the footer element.<\\/li>\\n<li>Fixed an issue where dynamic preload version numbers would sometimes get added to the wrong resource.<\\/li>\\n<li>Fixed an issue with certain multilingual setups where the base URL for generated files was incorrect.<\\/li>\\n<li>Updated background processing library to the latest version (1.3.0).<\\/li>\\n<li>Updated CSS parsing library to the latest version (8.5.1).<\\/li>\\n<li>Minor style updates to plugin UI.<\\/li>\\n<\\/ul>\\n<h4> 2.2.4 - 02.05.2024 <\\/h4>\\n<ul>\\n<li>Added built-in Image Dimensions exclusion for blank placeholder SVGs.<\\/li>\\n<li>Added excluded page builders function check to MU plugin file.<\\/li>\\n<li>Changed method of retrieving root directory in certain classes for better compatibility with more file structures.<\\/li>\\n<li>Fixed PHP warnings coming from local analytics function.<\\/li>\\n<\\/ul>\\n<h4> 2.2.3 - 01.08.2024 <\\/h4>\\n<ul>\\n<li>Fixed an issue where Mediavine and Modula Slider quick exclusions were not working properly.<\\/li>\\n<\\/ul>\\n<h4> 2.2.2 - 01.07.2024 <\\/h4>\\n<ul>\\n<li>Fixed PHP warnings coming from certain local analytics setups.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.1 - 01.04.2024 <\\/h4>\\n<ul>\\n<li>Removed deprecated Universal Analytics options which are no longer available and renamed remaining script type labels. If you still haven\'t updated to Google Analytics 4, make sure to create a new profile and input your new measurement ID.<\\/li>\\n<li>Added new tools option to Disable Optimizations for Logged In Users.<\\/li>\\n<li>Added new perfmatters_leading_image_exclusions filter.<\\/li>\\n<li>Added support for targeting figure elements to CSS Background Images.<\\/li>\\n<li>Added REST route exception for Litespeed.<\\/li>\\n<li>Added and updated Delay JS quick exclusions for Gravity Forms, Mediavine Trellis, Modula Slider, SHE Media Infuse, Thrive Leads, and WP Recipe Maker.<\\/li>\\n<li>Added built-in Delay JS exclusion for Divi link options script.<\\/li>\\n<li>Added generic customizer request parameter to excluded page builders array.<\\/li>\\n<li>Made some adjustments to classes dealing with cache directory files to support non-traditional folder structures such as Bedrock.<\\/li>\\n<li>Fixed a PHP warning related to cache URL declaration that would sometimes display for certain types of requests.<\\/li>\\n<li>Fixed an issue where picture elements were not getting excluded from lazy loading when fetchpriority high was set on a child image.<\\/li>\\n<li>Removed unnecessary script type attribute from our Delay JS inline script.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<p>View the full changelog:\\n<a href=\\"https:\\/\\/perfmatters.io\\/docs\\/changelog\\/\\">https:\\/\\/perfmatters.io\\/docs\\/changelog\\/<\\/a><\\/p>"},"license_check":"","msg":"","homepage":"https:\\/\\/perfmatters.io","package":"https:\\/\\/perfmatters.io\\/edd-sl\\/package_download\\/MTc3MjA3MTY2NjoxMjQzNGM1MzEzMWUxODJhYzYxOTAxYjBjMDNkNDQ5ZTo2OTY6N2Q5ZTA3ZTE5NDYyYzdkMDRmODgzYTA0ZDNiMGVjYTc6aHR0cHNALy9iZXJraGFtY291bnMud3BlbmdpbmVwb3dlcmVkLmNvbTow","icons":{"1x":"https:\\/\\/perfmatters.io\\/wp-content\\/uploads\\/edd\\/2026\\/01\\/perfmatters-logo-250x250-1-128x128.png","2x":"https:\\/\\/perfmatters.io\\/wp-content\\/uploads\\/edd\\/2026\\/01\\/perfmatters-logo-250x250-1.png"},"banners":{"high":"https:\\/\\/perfmatters.io\\/wp-content\\/uploads\\/edd\\/2026\\/01\\/perfmatters-plugin-banner-1544x500-1.png","low":"https:\\/\\/perfmatters.io\\/wp-content\\/uploads\\/edd\\/2026\\/01\\/perfmatters-plugin-banner-772x250-1.png"},"slug":"perfmatters","url":"https:\\/\\/perfmatters.io\\/downloads\\/perfmatters\\/?changelog=1","last_updated":"2026-02-03 22:18:54","download_link":"https:\\/\\/perfmatters.io\\/edd-sl\\/package_download\\/MTc3MjA3MTY2NjoxMjQzNGM1MzEzMWUxODJhYzYxOTAxYjBjMDNkNDQ5ZTo2OTY6N2Q5ZTA3ZTE5NDYyYzdkMDRmODgzYTA0ZDNiMGVjYTc6aHR0cHNALy9iZXJraGFtY291bnMud3BlbmdpbmVwb3dlcmVkLmNvbTow","upgrade_notice":"","tested":"6.9.1","description":["<p><a href=\\"https:\\/\\/perfmatters.io\\/\\">Perfmatters<\\/a> is a lightweight web performance plugin designed to help increase Google Core Web Vitals scores and fine-tune how assets load on your site.<\\/p>\\n<h4> Features <\\/h4>\\n<ul>\\n<li>Easy quick toggle options to turn off resources that shouldn\'t be loading. <\\/li>\\n<li>Disable scripts and plugins on a per post\\/page or sitewide basis with the Script Manager. <\\/li>\\n<li>Add and optimize code snippets (PHP, CSS, JS, and HTML), only load where needed.<\\/li>\\n<li>Defer and delay JavaScript, including third-party scripts.<\\/li>\\n<li>Automatically remove unused CSS.<\\/li>\\n<li>Minify JavaScript and CSS.<\\/li>\\n<li>Preload resources, critical images, and prerender links for quicker load times.<\\/li>\\n<li>Lazy load images and enable click-to-play thumbnails on videos.<\\/li>\\n<li>Host Google Analytics and Google Fonts locally.<\\/li>\\n<li>Change your WordPress login URL. <\\/li>\\n<li>Disable and limit WordPress revisions.<\\/li>\\n<li>Add code to your header, body, and footer.<\\/li>\\n<li>Optimize your database.<\\/li>\\n<\\/ul>\\n<h4> Documentation <\\/h4>\\n<p>Check out our <a href=\\"https:\\/\\/perfmatters.io\\/docs\\/\\">documentation<\\/a> for more information on how to use Perfmatters.<\\/p>"],"changelog":["<h4> 2.5.7 - 02.02.2026 <\\/h4>\\n<ul>\\n<li>Fixed an issue where the auto size attribute value was being added to images with no specified dimensions which could cause the image to display incorrectly.<\\/li>\\n<li>Fixed an issue where the attribute parser would ignore attribute values containing new line characters.<\\/li>\\n<li>Fixed an issue with certain attribute characters being disallowed preventing the attribute from migrating to the final element tag.<\\/li>\\n<\\/ul>\\n<h4> 2.5.6 - 01.28.2026 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_cdn_url filter along with new helper methods in the CDN class.<\\/li>\\n<li>Added the ability to completely disable Perfmatters code features using the new PERFMATTERS_DISABLE_CODE constant.<\\/li>\\n<li>Added confirmation message when turning on FastClick option.<\\/li>\\n<li>Added logic to remove the previous stored author ID when a code snippet is imported.<\\/li>\\n<li>Added host name to global settings and code snippet export files.<\\/li>\\n<li>Added additional logic to add an auto value to lazy loaded images sizes attributes when needed.<\\/li>\\n<li>Added separate used CSS generated files for different WooCommerce product types.<\\/li>\\n<li>Added dynamic request check in heartbeat function to prevent a possible PHP error.<\\/li>\\n<li>Updated lazy loading class to no longer add noscript tags by default for images and iframes to reduce HTML page size. The perfmatters_lazyload_noscript filter can still be used to turn that behavior back on.<\\/li>\\n<li>Updated get_atts_array utility method to use regex instead of wp_kses_hair for better compatibility.<\\/li>\\n<li>Reworked code snippet error handling class to work better with other exception handlers and existing error reporting.<\\/li>\\n<li>Turned off CSSLint in the code snippet editor, as it is outdated and was leading to false positives.<\\/li>\\n<li>Adjusted gutter column layout in the code snippet editor to be more consistent between different code types.<\\/li>\\n<li>Adjusted code snippet priority field to allow both negative and zero input values.<\\/li>\\n<li>Fixed an issue where CSS code snippets set to run in the footer were not having their conditions checked.<\\/li>\\n<li>Fixed an issue where CSS code snippets were not always printing where expected based on the set location and priority.<\\/li>\\n<li>Fixed an issue with certain code snippet input fields not being escaped properly in the UI leading to a broken layout in some cases.<\\/li>\\n<li>Fixed an issue where YouTube iframes rendered with a preview thumbnail that had autoplay forced off in their query string would require a double click.<\\/li>\\n<li>Fixed an issue where the referrerpolicy iframe attribute did not get applied to the generated iframe when using YouTube preview thumbnails.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.5.5 - 12.11.2025 <\\/h4>\\n<ul>\\n<li>Added new Code Settings options to Import and Export Perfmatters code snippets.<\\/li>\\n<li>Added support to export individual snippets, a subset of snippets through a bulk action, or all stored snippets from the new Code Settings export button.<\\/li>\\n<li>Added code snippets admin bar menu item that will show up if at least one snippet is present.<\\/li>\\n<li>Added frontend footer and admin footer locations for CSS code snippets.<\\/li>\\n<li>Added new PMMU_PLUGIN_DIR constant to allow for manipulation of the MU plugin file location for specific setups where the standard WPMU_PLUGIN_DIR may be altered.<\\/li>\\n<li>Added a REST API exception for Mollie.<\\/li>\\n<li>Added additional built-in CSS selector exclusions for Elementor\'s background slideshow.<\\/li>\\n<li>Added support for relative path URLs found inside stylesheets printed inline with our perfmatters_rucss_inline_stylesheets filter.<\\/li>\\n<li>Updated previous Separate Block Styles option which will now show up as a Block Style Behavior dropdown for sites running WordPress 6.9+.<\\/li>\\n<li>Fixed an issue in the code snippets editor where lint markers were not always correctly displaying for HTML and CSS snippets.<\\/li>\\n<li>Fixed an issue where the code snippet editor was pushing new lines off screen in some cases and not automatically scrolling to keep things in view.<\\/li>\\n<li>Fixed an issue where HTML code snippets were not able to save a non-default location.<\\/li>\\n<li>Fixed an issue with general Perfmatters admin notices not displaying correctly.<\\/li>\\n<li>Fixed multiple duplicate ID warnings in the plugin UI.<\\/li>\\n<li>Fixed multiple jQuery deprecation warnings in plugin UI JavaScript.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.5.4 - 11.20.2025 <\\/h4>\\n<ul>\\n<li>Moved code snippet storage location out of cache directory and into the uploads folder to prevent data loss in certain environments.<\\/li>\\n<li>Fixed a code snippets compatibility issue with servers that don\'t support PHP OPcache.<\\/li>\\n<li>Fixed an issue where the CodeMirror editor was not always initializing correctly when editing an individual code snippet.<\\/li>\\n<li>Fixed an issue where the code type tag prefix was not updating when changing the code type while creating a new code snippet.<\\/li>\\n<li>Fixed an issue in the error handling class where the exception handler was looping in certain instances and throwing an error.<\\/li>\\n<\\/ul>\\n<h4> 2.5.3 - 11.19.2025 <\\/h4>\\n<ul>\\n<li>Added new Code Snippets (BETA) feature, which is now the default view in the Code tab. You can now create and manage PHP, JS, CSS, and HTML code snippets from inside Perfmatters. We store and load code snippets using a flat-file method and directly integrate with all of our existing optimization options for the best performance.<\\/li>\\n<li>Moved the existing header, body, and footer code boxes to Code &gt; Global Scripts.<\\/li>\\n<li>Made style adjustments throughout the plugin UI.<\\/li>\\n<li>Added built-in CSS selector exclusion for GeneratePress mobile menu.<\\/li>\\n<li>Added new get_file_path utility method for use in various functions that need to determine the local file path for an asset loading on the front end.<\\/li>\\n<li>Fixed an issue where missing image dimensions were not getting applied correctly for sites inside a subdirectory.<\\/li>\\n<li>Removed BETA tag from Cloudflare Early Hints option.<\\/li>\\n<li>Updated EDD plugin updater class to version 1.9.4.<\\/li>\\n<\\/ul>\\n<h4> 2.5.2 - 10.23.2025 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_rucss_inline_stylesheets filter which allows you to inline any stylesheet already excluded from used CSS.<\\/li>\\n<li>Reworked the Script Manager input change event listener for better compatibility with other JavaScript running while the Script Manager is being used.<\\/li>\\n<li>Added new delay JS quick exclusion for GenerateBlocks Pro.<\\/li>\\n<li>Added built-in CSS selector exclusion for GenerateBlocks mobile menu.<\\/li>\\n<li>Added built-in stylesheet exclusion for GeneratePress local fonts.<\\/li>\\n<li>Updated WS Form Pro delay JS quick exclusion to fix a console error.<\\/li>\\n<li>Fixed some incorrect wording in the clear used CSS tooltip.<\\/li>\\n<\\/ul>\\n<h4> 2.5.1 - 09.29.2025 <\\/h4>\\n<ul>\\n<li>Added a fetchpriority high attribute on critically preloaded image tags to match the preload link attribute.<\\/li>\\n<li>Added new buffer function to check the viewport meta tag position and adjust it if needed when critical image preloads are being used.<\\/li>\\n<li>Added logic to populate critical image preload href attribute with the fallback image src if the preload is for a responsive image srcset.<\\/li>\\n<li>Added built-in stylesheet exclusion for GeneratePress offside menu.<\\/li>\\n<li>Updated delay JS quick exclusion for Elementor to include e-gallery.<\\/li>\\n<li>Fixed a PHP warning that could sometimes happen when calculating the root directory path in the Utilities class.<\\/li>\\n<li>Fixed a trailing slash validation warning coming from critical image preload tags.<\\/li>\\n<li>Disabled Remove Comment URLs toggle when Kadence is active due to an incompatibility.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.5.0 - 08.26.2025 <\\/h4>\\n<ul>\\n<li>Added new WP-CLI subcommands to clear-minified-js, clear-minified-css, and clear-local-fonts.<\\/li>\\n<li>Added support for targeting header element when using parent selector matching functions.<\\/li>\\n<li>Added support to enable and disable the clean uninstall option in WP-CLI.<\\/li>\\n<li>Added a built-in Script Manager rule to prevent dashicons from being dequeued when logged in.<\\/li>\\n<li>Fixed a WP-CLI issue where license activation and deactivation subcommands were not working correctly. <\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.9 - 08.12.2025 <\\/h4>\\n<ul>\\n<li>Rolled back CSS parsing library one version (8.9.0) to fix a conflict with WooCommerce.<\\/li>\\n<\\/ul>\\n<h4> 2.4.8 - 08.11.2025 <\\/h4>\\n<ul>\\n<li>Added built-in stylesheet exclusion for Bricks layer stylesheets.<\\/li>\\n<li>Adjusted emoji_svg_url filter to only return false outside the admin dashboard.<\\/li>\\n<li>Updated delay JS quick exclusion for Bricks to include splide.<\\/li>\\n<li>Updated delay JS quick exclusion for CookieYes to be more compatible.<\\/li>\\n<li>Updated early hint attribute check to include sizes and media attributes.<\\/li>\\n<li>Updated CSS parsing library to the latest version (9.0.0). New features, deprecation removals and bug fixes.<\\/li>\\n<li>Updated deprecated function in CSS class to use current method.<\\/li>\\n<li>Updated minification library to the latest version (1.3.75).<\\/li>\\n<li>Updated minimum PHP version requirement to 7.2.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.7 - 07.15.2025 <\\/h4>\\n<ul>\\n<li>Added support to set the Perfmatters license key via wp-config.php using the PERFMATTERS_LICENSE_KEY constant.<\\/li>\\n<li>Added new perfmatters_fetch_priority filter.<\\/li>\\n<li>Added integration to send an early hint header for used CSS file when both features are enabled.<\\/li>\\n<li>Added additional check for imagesrcset attribute when determining if an image should receive an early hint.<\\/li>\\n<li>Added crossorigin and fetchpriority attributes to early hint headers.<\\/li>\\n<li>Added additional parameters to excluded page builders array for Thrive Quiz Builder and Etch.<\\/li>\\n<li>Added built-in stylesheet exclusions for Elementor and Astra local fonts.<\\/li>\\n<li>Cleaned up leftover test file missed in previous update.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.6 - 06.17.2025 <\\/h4>\\n<ul>\\n<li>Added new advanced preload option to enable Cloudflare Early Hints (BETA) for Perfmatters preloads along with controls to limit which file types will have early hint link headers sent.<\\/li>\\n<li>Added new WP-CLI import-settings subcommand to import a settings configuration from an exported .json file.<\\/li>\\n<li>Added new WP-CLI disable and enable subcommands to modify certain plugin options. Available options can be printed out with the new get-options subcommand.<\\/li>\\n<li>Added new delay JS quick exclusion for SureCart.<\\/li>\\n<li>Added additional logic to disable speculative loading on WooCommerce cart and checkout URLs.<\\/li>\\n<li>Added additional logic to allow fallback deferral exclusions as part of an existing delay JS quick exclusion.<\\/li>\\n<li>Added built-in exclusion for Gravity Forms to prevent optimization features from running on AJAX form requests.<\\/li>\\n<li>Updated CSS parsing library to the latest version (8.8.0). Bug fixes and deprecations.<\\/li>\\n<li>Adjusted placement of perfmatters_preloads filter which was running too early and causing some filter snippets to be ignored.<\\/li>\\n<li>Increased default delay timeout from 10 to 15 seconds to improve compatibility.<\\/li>\\n<li>Fixed an issue with certain parent selector matching functions where a child element selector tag would also be replaced if it had the exact same selector tag HTML as the matched parent tag.<\\/li>\\n<li>Fixed multiple redundant calls to retrieve Script Manager settings row when loading the Script Manager UI.<\\/li>\\n<\\/ul>\\n<h4> 2.4.5 - 05.16.2025 <\\/h4>\\n<ul>\\n<li>Added some compatibility logic to fix an issue with specific caching plugins that were not working correctly with Perfmatters output buffer functions.<\\/li>\\n<li>Fixed a PHP translation warning that was coming from some post meta UI functions running too early.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.4 - 05.08.2025 <\\/h4>\\n<ul>\\n<li>Added new Exclude Leading option for CSS background images.<\\/li>\\n<li>Added new perfmatters_lazyload_parent_exclusions filter.<\\/li>\\n<li>Added new perfmatters_css_background_selectors filter.<\\/li>\\n<li>Added new speculative loading mode option to disable the feature entirely.<\\/li>\\n<li>Refactored lazy element method to be more efficient when searching for multiple element selectors.<\\/li>\\n<li>Reworked the perfmatters_critical_image_parent_exclusions and perfmatters_leading_image_parent_exclusions filters to no longer need to process the page HTML through DOMDocument for better stability, faster parsing, and 30% less code.<\\/li>\\n<li>Fixed an issue with parent selector matching for fetch priority and lazy loading where only the first image tag would match if it was inside a nested container element.<\\/li>\\n<li>Fixed an issue where the CSS Background class would get added to child elements as well if they also contained a matching selector.<\\/li>\\n<li>Fixed a compatibility issue when using Perfmatters preloads alongside WP Rocket.<\\/li>\\n<li>Fixed a spacing issue with input row checkboxes in the plugin UI.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.3 - 04.15.2025 <\\/h4>\\n<ul>\\n<li>Added new preload options to control Speculative Loading mode and eagerness settings for sites running WordPress 6.8+.<\\/li>\\n<li>Deprecated Instant Page option throughout the plugin for sites running WordPress 6.8+.<\\/li>\\n<li>Added a REST API exception for Slider Revolution.<\\/li>\\n<li>Updated delay JS quick exclusions for ShortPixel Adaptive Images and Slider Revolution to be more compatible.<\\/li>\\n<\\/ul>\\n<h4> 2.4.2 - 04.02.2025 <\\/h4>\\n<ul>\\n<li>Fixed an issue where mobile event handlers were sometimes preventing the delayed click from firing.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.1 - 03.26.2025 <\\/h4>\\n<ul>\\n<li>Refactored delay JS inline script, removed pageshow event listener, and uglified final code, reducing the script size by over 15%.<\\/li>\\n<li>Added built-in JS deferral exclusion for Cloudflare Turnstile.<\\/li>\\n<li>Added new delay JS quick exclusion for Plausible Analytics.<\\/li>\\n<li>Updated delay JS quick exclusions for Fluent Forms and Kadence Blocks to be more compatible.<\\/li>\\n<li>Adjusted document.write built-in delay exclusion to prevent false positives.<\\/li>\\n<li>Adjusted MU Mode documentation links in the Script Manager to go to specific anchor link sections.<\\/li>\\n<li>Fixed an issue where encoded data attribute values weren\'t being preserved correctly when converting an elements attribute string to an array.<\\/li>\\n<li>Fixed a multisite issue where the root directory path was not determined correctly when using a custom content directory setup.<\\/li>\\n<li>Deployed a secondary API that can be used when the client has issues communicating with our licensing server (usually due to firewalls).<\\/li>\\n<li>Removed deprecated SVG duotone filter removal actions from global styles toggle and updated tooltip to reflect changes.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.4.0 - 02.26.2025 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_rucss_async_stylesheets filter which allows you to async any stylesheet already excluded from used CSS.<\\/li>\\n<li>Dashicons and Elementor animation stylesheets are now loaded via async for better performance when Removed Unused CSS is turned on.<\\/li>\\n<li>Added additional logic to better handle stylesheets with media query attributes when including them in used CSS for increased performance. WooCommerce users may need to clear their used CSS if mobile-specific stylesheets are being loaded as they have been removed from our built-in exclusions.<\\/li>\\n<li>Added new built-in stylesheet exclusion for Bricks post-specific CSS.<\\/li>\\n<li>Added new Delay JS quick exclusion for WPBakery.<\\/li>\\n<li>Added a REST API exception for SureCart.<\\/li>\\n<li>Added additional compatibility styles to the Script Manager.<\\/li>\\n<li>Made some changes to be able to start our main output buffer a bit earlier in the load for better compatibility with other plugins that modify the HTML document.<\\/li>\\n<li>Updated clean uninstall function with current post meta options.<\\/li>\\n<li>Fixed an issue where the Clear Used CSS meta button was not working correctly for certain URL types.<\\/li>\\n<li>Fixed a PHP warning coming from certain rewrite rule formats when MU Mode was turned on.<\\/li>\\n<li>Removed BETA tag from preload lazy elements option.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<\\/ul>\\n<h4> 2.3.9 - 02.06.2025 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_preloads_array filter.<\\/li>\\n<li>Added new perfmatters_minify_threshold filter.<\\/li>\\n<li>Added additional swiper JavaScript file to Elementor quick exclusion.<\\/li>\\n<li>Added additional built-in CSS selector exclusion for WP Armour.<\\/li>\\n<li>Added a string check to login URL filter function to prevent a possible PHP error.<\\/li>\\n<li>Fixed an issue where new user email requests were not being allowed through the redirect block when using a custom login URL.<\\/li>\\n<li>Minor adjustment to CDN rewrite regex to fix an issue that was happening when the home URL was different from the site URL.<\\/li>\\n<li>Removed Ezoic quick exclusion and moved to built-in deferral and delay exclusions.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.8 - 01.07.2025 <\\/h4>\\n<ul>\\n<li>Added a REST API exception for SureForms.<\\/li>\\n<li>Added a UI button to cancel the current database optimization process.<\\/li>\\n<li>Added built-in delay JS exclusion for document.write for compatibility.<\\/li>\\n<li>Updated background processing library to the latest version (1.4.0).<\\/li>\\n<li>Fixed an issue where some deliberate redirect requests were not being allowed to access the hidden login URL.<\\/li>\\n<li>Fixed an issue where the database optimization process was not starting correctly in some cases.<\\/li>\\n<li>Fixed a missing anchor link pointing to the license tab in our plugin settings UI.<\\/li>\\n<\\/ul>\\n<h4> 2.3.7 - 01.01.2025 <\\/h4>\\n<ul>\\n<li>Added additional CSS background image inline styles to account for backgrounds set on pseudo-elements of children inside the targeted container.<\\/li>\\n<li>Added WP Rocket filter to disable their critical image optimization when preload critical images is active to prevent conflicts.<\\/li>\\n<li>Added new Delay JS quick exclusion for Ezoic.<\\/li>\\n<li>Added built-in minify JS exclusion for WP Recipe Maker.<\\/li>\\n<li>Updated network default function to preserve the CDN URL if already set on the target subsite.<\\/li>\\n<li>Updated admin bar menu items to show clear all used CSS on the front end.<\\/li>\\n<li>Updated minify exclusion functions to check the entire attribute string of the script or stylesheet instead of just the source URL.<\\/li>\\n<li>Updated CSS parsing library to the latest version (8.7.0). Improves support for PHP 8.4.<\\/li>\\n<li>Updated login URL feature with additional check to prevent access to the hidden login slug via an authentication request redirected from a query string.<\\/li>\\n<li>Updated buffer class to prevent running on Bricks template URLs.<\\/li>\\n<li>Fixed an issue where the Used CSS file was sometimes getting falsely flagged as completely unused on certain speed tests.<\\/li>\\n<li>Removed unnecessary documentWrite handling function from delay JS inline script to reduce the size by over 8%.<\\/li>\\n<li>Removed older changelog entries in readme.txt file and added link to web version.<\\/li>\\n<\\/ul>\\n<h4> 2.3.6 - 11.21.2024 <\\/h4>\\n<ul>\\n<li>Fixed an issue where Delay JS wasn\'t running correctly in some cases.<\\/li>\\n<li>Updated EDD plugin updater class to version 1.9.2.<\\/li>\\n<\\/ul>\\n<h4> 2.3.5 - 11.21.2024 <\\/h4>\\n<ul>\\n<li>Added new local Google Font option to Limit Subsets that are downloaded and included in the stylesheet.<\\/li>\\n<li>Added new local Google font option to change the Print Method with options for file and inline.<\\/li>\\n<li>Added new Priority option to manual preloads which can be used to add a specific fetchpriority attribute value to individual preload tags.<\\/li>\\n<li>Added new perfmatters_lazy_element_selectors filter.<\\/li>\\n<li>Removed unnecessary trailing link tag from delayed stylesheets when using Remove Unused CSS.<\\/li>\\n<li>Removed crossorigin option for manual preloads. The attribute is now automatically added to fetch and font preload tags.<\\/li>\\n<li>Increased action button response message timeout to 10 seconds in plugin UI.<\\/li>\\n<li>Fixed a PHP warning coming from Disable Google Maps function if a post ID was not found on a single post URL.<\\/li>\\n<li>Fixed an issue with WordPress 6.7.1 where the text domain for translations was loading too early.<\\/li>\\n<li>Removed deprecated plugin option to load Google fonts asynchronously.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.4 - 10.10.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_lazy_elements filter.<\\/li>\\n<li>Added new perfmatters_is_woocommerce filter.<\\/li>\\n<li>Added additional built-in stylesheet and selector exclusions for better compatibility with Elementor animations.<\\/li>\\n<li>Added WP Rocket filter to disable lazy render when lazy elements feature is active to prevent conflicts.<\\/li>\\n<li>Added additional parameter to excluded page builders array for tagDiv Composer.<\\/li>\\n<li>Added built-in delay JS exclusion for lazy elements inline script.<\\/li>\\n<li>Moved plugin settings logo SVG back to inline to prevent file_get_contents errors in certain environments.<\\/li>\\n<li>Adjusted built-in CSS dynamic selector exclusions to fix some minor visual issues with a few page builders.<\\/li>\\n<li>Fixed a JavaScript error that would sometimes show up in the console when using Delay JS with click delay enabled.<\\/li>\\n<li>Fixed an issue where a used stylesheet path would still attempt to load even if no used styles had been picked up for the URL.<\\/li>\\n<li>Fixed an issue where browser-specific stylesheets inside HTML comments were getting parsed by our used CSS library.<\\/li>\\n<li>Fixed a MU Mode issue where exceptions would not be applied correctly if a query string was present on the home URL if set to show the latest posts.<\\/li>\\n<li>Fixed an issue where preloading a JS file by the handle was not loading the minified version when necessary.<\\/li>\\n<\\/ul>\\n<h4> 2.3.3 - 08.28.2024 <\\/h4>\\n<ul>\\n<li>Added new lazy loading advanced beta options to manage Lazy Elements which will allow for element chains in the DOM to be lazy loaded until they enter the viewport.<\\/li>\\n<li>Separated out built-in CSS selector exclusions by URL type for increased performance on single and front pages.<\\/li>\\n<li>Optimized plugin logo and other SVG image files.<\\/li>\\n<li>Added fetchpriority high attribute automatically on critically preloaded image links.<\\/li>\\n<li>Added support for delaying script modules.<\\/li>\\n<li>Added additional jQuery sticky JavaScript file to Elementor quick exclusion.<\\/li>\\n<li>Added new Delay JS quick exclusions for Fluent Forms and Fluent Forms Pro.<\\/li>\\n<li>Integrated get_atts_array utility function into lazyload class to prevent redundancy.<\\/li>\\n<li>Fixed an issue where smaller size files were sometimes not being replaced with the minified version for increased performance.<\\/li>\\n<li>Fixed an issue where the preload location label was overlapping the input field for certain languages.<\\/li>\\n<li>Made adjustments to option management to prevent autoloading of certain options going forward where it is not needed.<\\/li>\\n<li>Removed various manual preload types that are no longer supported by most major browsers.<\\/li>\\n<\\/ul>\\n<h4> 2.3.2 - 07.30.2024 <\\/h4>\\n<ul>\\n<li>Updated CSS parsing library to the latest version (8.6.0) which should help with correctly parsing mathematical operations inside CSS property values.<\\/li>\\n<li>Added additional parameter to excluded page builders array for GenerateBlocks and TranslatePress.<\\/li>\\n<li>Added additional built-in deferral exclusion for jqueryParams inline script.<\\/li>\\n<li>Added Delay JS quick exclusion for the Kadence menu.<\\/li>\\n<li>Fixed a MU Mode issue where home page exceptions would not be applied correctly if a query string was present in the requested URL.<\\/li>\\n<li>Fixed an undefined array key warning coming from the minify class.<\\/li>\\n<li>Fixed a minify error that would show up when a prospective file did not have any content.<\\/li>\\n<li>Fixed an issue where having Remove Unused CSS turned on with no stylesheets loading would return a blank screen.<\\/li>\\n<li>Fixed a CSS error that would show up when trying to determine the current page ID when the queried post was null.<\\/li>\\n<li>Fixed an issue where the CSS class would attempt to retrieve the contents of a stylesheet even if it didn\'t exist.<\\/li>\\n<li>Fixed an issue where minified files would not get picked up by the CDN rewriter.<\\/li>\\n<li>Removed unnecessary minify library .git directories from the plugin.<\\/li>\\n<li>Minor style adjustments to the plugin UI.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.1 - 06.27.2024 <\\/h4>\\n<ul>\\n<li>Added new Minify JS and Minify CSS features along with options to exclude specific files from minification and clear generated minified files when necessary.<\\/li>\\n<li>UI Updates: What was previously the Assets tab has now been replaced by three more specific tabs, JavaScript, CSS, and Code. The main Script Manager toggle has been moved to Tools. Additional subheaders have also been added throughout to help with organization.<\\/li>\\n<li>Added new perfmatters_minify_js filter.<\\/li>\\n<li>Added new perfmatters_minify_js_exclusions filter.<\\/li>\\n<li>Added new perfmatters_minify_css filter.<\\/li>\\n<li>Added new perfmatters_minify_css_exclusions filter.<\\/li>\\n<li>Added a REST API exception for Independent Analytics.<\\/li>\\n<li>Added additional request parameter for Divi to excluded page builders array.<\\/li>\\n<li>Added built-in critical image exclusion for WPML flag images.<\\/li>\\n<li>Added Delay JS quick exclusion for Grow for WordPress.<\\/li>\\n<li>Updated used CSS function to generate a separate file for each post type archive instead of a single shared stylesheet.<\\/li>\\n<li>Fixed an issue that was causing an incorrect root directory to be returned for some environments.<\\/li>\\n<li>Fixed an issue with preload and lazyload parent exclusion filters that was preventing them from excluding images correctly in some cases.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.3.0 - 05.23.2024 <\\/h4>\\n<ul>\\n<li>Added a new function to verify the preferred content type from the HTTP header when determining if JSON is being requested. This should improve compatibility with certain hosting providers.<\\/li>\\n<li>Added an additional check when removing unused CSS to avoid parsing print-only stylesheets.<\\/li>\\n<li>Updated Delay JS quick exclusion for Termageddon + UserCentrics for better compatibility.<\\/li>\\n<li>Removed option to disable wlwmanifest link output as that function was deprecated in WordPress 6.3.<\\/li>\\n<li>Fixed an issue that was preventing lazy loaded images from displaying when defer inline scripts was enabled.<\\/li>\\n<li>Fixed an issue where responsive styles for YouTube preview thumbnails were not printing on certain themes using responsive embeds.<\\/li>\\n<li>Fixed an issue with DOMDocument where HTML entities coming from inline styles would display as their encoded values.<\\/li>\\n<li>Fixed a missing tooltip on the scan database option.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.9 - 05.16.2024 <\\/h4>\\n<ul>\\n<li>Fixed an issue that could cause a conflict with other JS deferral solutions when running at the same time.<\\/li>\\n<\\/ul>\\n<h4> 2.2.8 - 05.16.2024 <\\/h4>\\n<ul>\\n<li>Added new Defer JavaScript option to Include Inline Scripts.<\\/li>\\n<li>Added new option to Separate Block Styles.<\\/li>\\n<li>Added additional built-in CSS selector exclusions for Splide.<\\/li>\\n<li>Updated Delay JS quick exclusion for Kadence Blocks with additional scripts.<\\/li>\\n<li>Updated our staging site license key exception list with additional formats.<\\/li>\\n<li>Updated deferral exclusion check to work with entire tag instead of just src URL.<\\/li>\\n<li>Moved to printing responsive embed styles for YouTube preview thumbnails in all cases for better compatibility.<\\/li>\\n<li>Fixed an issue where the CDN rewrite was not picking up URLs with a relative protocol.<\\/li>\\n<li>Fixed an issue where an existing data-wp-strategy attribute would prevent a script from being able to be deferred.<\\/li>\\n<li>Fixed an issue where the Script Manager was not giving the right feedback on save when a new line character was showing up in the AJAX response.<\\/li>\\n<li>Fixed an issue on the network settings page where incorrect tab content would show up after saving.<\\/li>\\n<li>Fixed an issue where the license tab was showing up at the subsite level if the plugin was not network activated in a multisite environment.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.7 - 04.19.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_used_css_below filter.<\\/li>\\n<li>Added new perfmatters_defer_js_exclusions filter.<\\/li>\\n<li>Added new perfmatters_delay_js_fastclick filter.<\\/li>\\n<li>Added additional DOMDocument flag to parent exclusion filters for better compatibility.<\\/li>\\n<li>Added GiveWP request parameter to excluded page builders array.<\\/li>\\n<li>Updated Delay JS quick exclusion for WooCommerce Single Product Gallery with additional scripts to help with zoom and lightbox functionality.<\\/li>\\n<li>Updated Delay JS quick exclusion for Cookie Notice with additional scripts.<\\/li>\\n<li>Moved Script Manager CSS to stylesheet printed inline instead of from a PHP file.<\\/li>\\n<\\/ul>\\n<h4> 2.2.6 - 03.18.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_defer_jquery filter.<\\/li>\\n<li>Added Delay JS quick exclusion for Monumetric Ads.<\\/li>\\n<li>Updated content URL reference to use content_url function instead of constant when generating root directory path.<\\/li>\\n<li>Updated local stylesheet URL replace function to be case insensitive.<\\/li>\\n<li>Updated new parent exclusion filters to use DOMDocument instead of regex to allow support for targeting images inside nested containers.<\\/li>\\n<li>Fixed an issue where certain scripts were not being deferred properly when delay JavaScript option was also enabled.<\\/li>\\n<li>Fixed an issue where abnormal image URLs would sometimes generate a warning when trying to parse for image dimensions.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.5 - 02.29.2024 <\\/h4>\\n<ul>\\n<li>Added new perfmatters_critical_image_parent_exclusions filter.<\\/li>\\n<li>Added new perfmatters_leading_image_parent_exclusions filter.<\\/li>\\n<li>Added new Disable Core Fetch option to disable the fetch priority attribute added by WordPress core.<\\/li>\\n<li>Added built-in WooCommerce CSS selector exclusion for better compatibility on single product posts.<\\/li>\\n<li>Added Breakdance request parameters to excluded page builders array.<\\/li>\\n<li>Added a REST API exception for WP Recipe Maker.<\\/li>\\n<li>Added Delay JS quick exclusions for Kadence Blocks and Kadence Blocks Pro.<\\/li>\\n<li>Added CSS Background Image support for the footer element.<\\/li>\\n<li>Fixed an issue where dynamic preload version numbers would sometimes get added to the wrong resource.<\\/li>\\n<li>Fixed an issue with certain multilingual setups where the base URL for generated files was incorrect.<\\/li>\\n<li>Updated background processing library to the latest version (1.3.0).<\\/li>\\n<li>Updated CSS parsing library to the latest version (8.5.1).<\\/li>\\n<li>Minor style updates to plugin UI.<\\/li>\\n<\\/ul>\\n<h4> 2.2.4 - 02.05.2024 <\\/h4>\\n<ul>\\n<li>Added built-in Image Dimensions exclusion for blank placeholder SVGs.<\\/li>\\n<li>Added excluded page builders function check to MU plugin file.<\\/li>\\n<li>Changed method of retrieving root directory in certain classes for better compatibility with more file structures.<\\/li>\\n<li>Fixed PHP warnings coming from local analytics function.<\\/li>\\n<\\/ul>\\n<h4> 2.2.3 - 01.08.2024 <\\/h4>\\n<ul>\\n<li>Fixed an issue where Mediavine and Modula Slider quick exclusions were not working properly.<\\/li>\\n<\\/ul>\\n<h4> 2.2.2 - 01.07.2024 <\\/h4>\\n<ul>\\n<li>Fixed PHP warnings coming from certain local analytics setups.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<h4> 2.2.1 - 01.04.2024 <\\/h4>\\n<ul>\\n<li>Removed deprecated Universal Analytics options which are no longer available and renamed remaining script type labels. If you still haven\'t updated to Google Analytics 4, make sure to create a new profile and input your new measurement ID.<\\/li>\\n<li>Added new tools option to Disable Optimizations for Logged In Users.<\\/li>\\n<li>Added new perfmatters_leading_image_exclusions filter.<\\/li>\\n<li>Added support for targeting figure elements to CSS Background Images.<\\/li>\\n<li>Added REST route exception for Litespeed.<\\/li>\\n<li>Added and updated Delay JS quick exclusions for Gravity Forms, Mediavine Trellis, Modula Slider, SHE Media Infuse, Thrive Leads, and WP Recipe Maker.<\\/li>\\n<li>Added built-in Delay JS exclusion for Divi link options script.<\\/li>\\n<li>Added generic customizer request parameter to excluded page builders array.<\\/li>\\n<li>Made some adjustments to classes dealing with cache directory files to support non-traditional folder structures such as Bedrock.<\\/li>\\n<li>Fixed a PHP warning related to cache URL declaration that would sometimes display for certain types of requests.<\\/li>\\n<li>Fixed an issue where picture elements were not getting excluded from lazy loading when fetchpriority high was set on a child image.<\\/li>\\n<li>Removed unnecessary script type attribute from our Delay JS inline script.<\\/li>\\n<li>Translation updates.<\\/li>\\n<\\/ul>\\n<p>View the full changelog:\\n<a href=\\"https:\\/\\/perfmatters.io\\/docs\\/changelog\\/\\">https:\\/\\/perfmatters.io\\/docs\\/changelog\\/<\\/a><\\/p>"],"plugin":"perfmatters\\/perfmatters.php","id":"perfmatters\\/perfmatters.php","requires":"","requires_php":""}";}', 'off') ;
