32746&Signature=Whn51K%2BGJ6sFo91IIRM7u8gAo54%3D";s:10:"url_latest";s:202:"https://s3.dualstack.us-east-1.amazonaws.com/gravityforms/addons/webhooks/gravityformswebhooks_1.7.0.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signature=Whn51K%2BGJ6sFo91IIRM7u8gAo54%3D";}s:18:"gravityformszapier";a:6:{s:12:"is_available";b:1;s:7:"version";s:5:"4.5.1";s:14:"version_latest";s:5:"4.5.1";s:20:"minimum_requirements";a:0:{}s:3:"url";s:198:"https://s3.dualstack.us-east-1.amazonaws.com/gravityforms/addons/zapier/gravityformszapier_4.5.1.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signature=2Jdai1%2FdUqMjjZ1p48VF6jYCmNw%3D";s:10:"url_latest";s:198:"https://s3.dualstack.us-east-1.amazonaws.com/gravityforms/addons/zapier/gravityformszapier_4.5.1.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signature=2Jdai1%2FdUqMjjZ1p48VF6jYCmNw%3D";}s:19:"gravityformszohocrm";a:6:{s:12:"is_available";b:1;s:7:"version";s:5:"2.4.0";s:14:"version_latest";s:7:"2.4.0.2";s:20:"minimum_requirements";a:0:{}s:3:"url";s:200:"https://s3.dualstack.us-east-1.amazonaws.com/gravityforms/addons/zohocrm/gravityformszohocrm_2.4.0.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signature=YzbHuOCIYceGLhnEpf%2B8NiONWTs%3D";s:10:"url_latest";s:204:"https://s3.dualstack.us-east-1.amazonaws.com/gravityforms/addons/zohocrm/gravityformszohocrm_2.4.0.2.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signature=x%2F9W0RX2R6N0mBVb4WDFn%2Fr6voQ%3D";}s:11:"gravitysmtp";a:6:{s:12:"is_available";b:1;s:7:"version";s:5:"2.1.3";s:14:"version_latest";s:5:"2.1.3";s:20:"minimum_requirements";a:0:{}s:3:"url";s:189:"https://s3.dualstack.us-east-1.amazonaws.com/gravitysmtp/releases/gravitysmtp_2.1.3.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signature=910QmIu7A0zVs%2F41Xn%2FJKBv%2Fevs%3D";s:10:"url_latest";s:189:"https://s3.dualstack.us-east-1.amazonaws.com/gravitysmtp/releases/gravitysmtp_2.1.3.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1772132746&Signatu