 ;
INSERT INTO `wp_options` ( `option_id`, `option_name`, `option_value`, `autoload`) VALUES
(340, 'edd_sl_9868d8b13b46152918b32a51298bc1ec', 'a:2:{s:7:"timeout";i:1772021268;s:5:"value";s:23656:"{"name":"Accessibility Checker Audit History","new_version":"1.4.0","stable_version":"1.4.0","sections":{"description":"<p>Accessibility Checker Audit History is an advanced add-on for Accessibility Checker Pro, designed to enhance your accessibility assessment capabilities. This premium extension enables\\nusers to systematically record and revisit accessibility evaluations, allowing for comprehensive over-time comparisons and in-depth site accessibility analysis.<\\/p>\\n<p>Key Features:<\\/p>\\n<ul>\\n<li><strong>Audit History Dashboard:<\\/strong> Centralized and intuitive dashboard for all your audit records.<\\/li>\\n<li><strong>Exportable Data:<\\/strong> Easily export your audit history to CSV for further analysis or reporting.<\\/li>\\n<li><strong>Visual Data Graphs:<\\/strong> Understand your site\\u2019s accessibility trends with clear and concise data graphs.<\\/li>\\n<li><strong>Comprehensive Audit List:<\\/strong> Quickly refer to your entire audit history from a centralized list.<\\/li>\\n<li><strong>Date Range Filters:<\\/strong> Customize your view and analysis by applying specific date range filters.<\\/li>\\n<li><strong>Change Insight:<\\/strong> Gain valuable insight with calculated percentages showcasing changes in accessibility over time.<\\/li>\\n<li><strong>Enhanced Accessibility Management:<\\/strong> With additional features aimed at providing a more holistic view of your site\\u2019s accessibility status.<\\/li>\\n<\\/ul>\\n<p><strong>Note:<\\/strong> Accessibility Checker Audit History is a premium add-on, and it requires the installation and activation of Accessibility Checker Pro to function properly. To purchase a\\nlicense, visit the <a href=\\"https:\\/\\/equalizedigital.com\\/accessibility-checker\\/pricing\\/?utm_source=EDACAuditHistory&amp;utm_medium=software&amp;utm_campaign=readme\\">Accessibility Checker Pro website<\\/a>.<\\/p>","installation":"<p>This add-on requires both Accessibility Checker Free and Accessibility Checker Pro plugins to be installed and active. You must have a small business or above license for it to work.<\\/p>\\n<h3>Installing Accessibility Checker Audit History Within WordPress<\\/h3>\\n<ol>\\n<li>Navigate to \\u2018Plugins &gt; Add New\\u2019 within your WordPress dashboard.<\\/li>\\n<li>Click the \\"Upload Plugin\\" button on the Add Plugins screen.<\\/li>\\n<li>Upload and install the zipped plugin file you received via your download link.<\\/li>\\n<li>Once uploaded, activate \\u2018Accessibility Checker Audit History\\u2019 from your Plugins page.<\\/li>\\n<\\/ol>\\n<h3>Installing Accessibility Checker Audit History Manually<\\/h3>\\n<ol>\\n<li>Extract the \\u2018accessibility-checker-audit-history\\u2019 folder from the provided zip file.<\\/li>\\n<li>Using FTP, upload the extracted folder to the \\/wp-content\\/plugins\\/ directory on your web server.<\\/li>\\n<li>Activate \\u2018Accessibility Checker: Audit History\\u2019 from your Plugins page within the WordPress dashboard.<\\/li>\\n<\\/ol>","changelog":"<h4> 1.4.0 <\\/h4>\\n<ul>\\n<li>Improved: License messages and handling.<\\/li>\\n<li>Tweaked: Set sslverify to true for license requests.<\\/li>\\n<\\/ul>\\n<h4> 1.3.0 <\\/h4>\\n<ul>\\n<li>Added: New filter to customize the capabilities that can see the audit history page.<\\/li>\\n<\\/ul>\\n<h4> 1.2.0 <\\/h4>\\n<ul>\\n<li>Added: translation files<\\/li>\\n<\\/ul>\\n<h4> 1.1.2 <\\/h4>\\n<ul>\\n<li>Fixes: Handle some situations the audit history page link would not appear in the menu.<\\/li>\\n<\\/ul>\\n<h4> 1.1.1 <\\/h4>\\n<ul>\\n<li>Fixes: Handle notifications in the plugin better.<\\/li>\\n<\\/ul>\\n<h4> 1.1.0 <\\/h4>\\n<ul>\\n<li>Fixes: Handle some cases where tables do not create on activation.<\\/li>\\n<\\/ul>\\n<h4> 1.0.4 <\\/h4>\\n<ul>\\n<li>Added: demo support<\\/li>\\n<\\/ul>\\n<h4> 1.0.3 <\\/h4>\\n<ul>\\n<li>Fixed: check for the existence of the Action Scheduler action at every admin_init and installs if it is not found<\\/li>\\n<\\/ul>\\n<h4> 1.0.2 <\\/h4>\\n<ul>\\n<li>Fixed: automatic updates not working<\\/li>\\n<li>Update: php and js coding standards<\\/li>\\n<li>Update: development and build scripts<\\/li>\\n<\\/ul>\\n<h4> 1.0.1 <\\/h4>\\n<ul>\\n<li>Fixed: invalid date error message not announced to screen readers<\\/li>\\n<li>Fixed: chart \\"too high\\" message<\\/li>\\n<li>Updated: chart labels with better read out for screen readers<\\/li>\\n<li>Updated: chart date format<\\/li>\\n<li>Updated: license admin notice flow and API logic<\\/li>\\n<li>Updated: date modal apply button to not be disabled<\\/li>\\n<li>Added: role and aria-label attributes to the graph<\\/li>\\n<li>Updated: role attribute on modal<\\/li>\\n<li>Added: explainer when plugin is first installed<\\/li>\\n<li>Added: logic to only load classes and assets in admin<\\/li>\\n<li>Added: Action Scheduler performance updates<\\/li>\\n<\\/ul>\\n<h4> 1.0.0 <\\/h4>\\n<ul>\\n<li>Everything is new and shiny.<\\/li>\\n<li>We think it\'s awesome you want to make your website more accessible.<\\/li>\\n<\\/ul>","faq":"<h4>What support is included?<\\/h4>\\n<p>Equalize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and troubleshooting\\nassistance. You may <a href=\\"https:\\/\\/my.equalizedigital.com\\/support\\/pro-support\\/\\">open a support ticket<\\/a> at any time. Plugin support is limited to providing assistance in using the plugin but\\ndoes not include support resolving any specific accessibility issues that have been identified.<\\/p>\\n<h4>Can you help me figure out how to fix an error or warning on my website?<\\/h4>\\n<p>If you have questions about specific errors and warnings on your website or need help fixing problems, we offer remediation support during Office Hours for Small Business and Agency license holders. If you want more personalized auditing and dev help fixing problems on your website, check out our <a href=\\"https:\\/\\/equalizedigital.com\\/services\\/website-accessibility-remediation\\/#pricing-plans\\">audit and remediation plans<\\/a>.<\\/p>\\n<h4>Do I lose functionality if my license key is not active?<\\/h4>\\n<p>To utilize Accessibility Checker Audit History features and receive plugin updates and support, you do need to have an active license key. If your license key has expired, you can\\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.<\\/p>\\n<h4>Can I change how often the audit scan runs?<\\/h4>\\n<p>The audit scan runs daily by default. To change the interval to something else you can use this custom filter: accessibility-checker-audit-history_audit_save_interval.\\nHere is example code to change the interval to once per week:<\\/p>\\n<pre>\\nadd_filter( \'accessibility-checker-audit-history_audit_save_interval\' , function( $minutes ){\\n    return 60 * 24 * 7; \\/\\/ Number of minutes in a week.\\n});\\n<\\/pre>\\n<h4>How can I report security bugs?<\\/h4>\\n<p>You can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. <a href=\\"https:\\/\\/patchstack.com\\/database\\/vdp\\/9e5fbe42-a7e1-4794-ad5f-db248d5ec7ee\\">Report a security vulnerability.<\\/a><\\/p>\\n"},"license_check":"","msg":"","homepage":"https:\\/\\/equalizedigital.com\\/accessibility-checker\\/","package":"https:\\/\\/my.equalizedigital.com\\/edd-sl\\/package_download\\/MTc3MjI0ODA2ODo1OGJiYTIwY2Q2ZTUyYTQ0YWNhMGJmOTQwNmRlNDczYzoxMTk3MDo2OTk0NGIwOTM2NzNmOTEwM2I1ODFkZDUxOTFiNWY1YzpodHRwc0AvL2JlcmtoYW1jb3Vucy53cGVuZ2luZXBvd2VyZWQuY29tOjA=","icons":[],"banners":{"high":"https:\\/\\/my.equalizedigital.com\\/wp-content\\/uploads\\/sites\\/4\\/edd\\/2023\\/11\\/Audit-History.png","low":"https:\\/\\/my.equalizedigital.com\\/wp-content\\/uploads\\/sites\\/4\\/edd\\/2023\\/11\\/Audit-History-Small.png"},"slug":"accessibility-checker-audit-history","url":"https:\\/\\/my.equalizedigital.com\\/downloads\\/accessibility-checker-audit-history\\/?changelog=1","last_updated":"2025-12-17 23:40:22","download_link":"https:\\/\\/my.equalizedigital.com\\/edd-sl\\/package_download\\/MTc3MjI0ODA2ODo1OGJiYTIwY2Q2ZTUyYTQ0YWNhMGJmOTQwNmRlNDczYzoxMTk3MDo2OTk0NGIwOTM2NzNmOTEwM2I1ODFkZDUxOTFiNWY1YzpodHRwc0AvL2JlcmtoYW1jb3Vucy53cGVuZ2luZXBvd2VyZWQuY29tOjA=","tags":["accessibility","accessible","wcag","ada","a11y"],"requires":"6.5","tested":"6.8.0","requires_php":"","contributors":{"equalizedigital":{"display_name":"equalizedigital","profile":"\\/\\/profiles.wordpress.org\\/equalizedigital","avatar":"https:\\/\\/wordpress.org\\/grav-redirect.php?user=equalizedigital"},"alh0319":{"display_name":"alh0319","profile":"\\/\\/profiles.wordpress.org\\/alh0319","avatar":"https:\\/\\/wordpress.org\\/grav-redirect.php?user=alh0319"},"stevejonesdev":{"display_name":"stevejonesdev","profile":"\\/\\/profiles.wordpress.org\\/stevejonesdev","avatar":"https:\\/\\/wordpress.org\\/grav-redirect.php?user=stevejonesdev"}},"stable_tag":"1.3.0","donate_link":"","short_description":"This add-on introduces Audit History to Accessibility Checker, allowing users to monitor and review accessibility assessments over time.","license":"GPLv2 or later","upgrade_notice":"","screenshots":[],"faq":["<h4>What support is included?<\\/h4>\\n<p>Equalize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and troubleshooting\\nassistance. You may <a href=\\"https:\\/\\/my.equalizedigital.com\\/support\\/pro-support\\/\\">open a support ticket<\\/a> at any time. Plugin support is limited to providing assistance in using the plugin but\\ndoes not include support resolving any specific accessibility issues that have been identified.<\\/p>\\n<h4>Can you help me figure out how to fix an error or warning on my website?<\\/h4>\\n<p>If you have questions about specific errors and warnings on your website or need help fixing problems, we offer remediation support during Office Hours for Small Business and Agency license holders. If you want more personalized auditing and dev help fixing problems on your website, check out our <a href=\\"https:\\/\\/equalizedigital.com\\/services\\/website-accessibility-remediation\\/#pricing-plans\\">audit and remediation plans<\\/a>.<\\/p>\\n<h4>Do I lose functionality if my license key is not active?<\\/h4>\\n<p>To utilize Accessibility Checker Audit History features and receive plugin updates and support, you do need to have an active license key. If your license key has expired, you can\\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.<\\/p>\\n<h4>Can I change how often the audit scan runs?<\\/h4>\\n<p>The audit scan runs daily by default. To change the interval to something else you can use this custom filter: accessibility-checker-audit-history_audit_save_interval.\\nHere is example code to change the interval to once per week:<\\/p>\\n<pre>\\nadd_filter( \'accessibility-checker-audit-history_audit_save_interval\' , function( $minutes ){\\n    return 60 * 24 * 7; \\/\\/ Number of minutes in a week.\\n});\\n<\\/pre>\\n<h4>How can I report security bugs?<\\/h4>\\n<p>You can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. <a href=\\"https:\\/\\/patchstack.com\\/database\\/vdp\\/9e5fbe42-a7e1-4794-ad5f-db248d5ec7ee\\">Report a security vulnerability.<\\/a><\\/p>\\n"],"warnings":{"too_many_tags":["section 508","audit","readability","content analysis"]},"expected_sections":["description","installation","faq","screenshots","changelog","upgrade_notice","other_notes"],"alias_sections":{"frequently_asked_questions":"faq","change_log":"changelog","screenshot":"screenshots"},"valid_headers":{"tested":"tested","tested up to":"tested","requires":"requires","requires at least":"requires","requires php":"requires_php","tags":"tags","contributors":"contributors","donate link":"donate_link","stable tag":"stable_tag","license":"license","license uri":"license_uri"},"ignore_tags":["plugin","wordpress"],"maximum_field_lengths":{"short_description":150,"section":2500,"section-changelog":5000,"section-faq":5000},"raw_contents":"=== Accessibility Checker Audit History ===\\nContributors: equalizedigital, alh0319, stevejonesdev\\nTags: accessibility, accessible, wcag, ada, a11y, section 508, audit, readability, content analysis\\nRequires at least: 6.5\\nTested up to: 6.8.0\\nStable tag: 1.3.0\\nLicense: GPLv2 or later\\nLicense URI: https:\\/\\/www.gnu.org\\/licenses\\/gpl-2.0.html\\n\\nThis add-on introduces Audit History to Accessibility Checker, allowing users to monitor and review accessibility assessments over time.\\n\\n== Description ==\\n\\nAccessibility Checker Audit History is an advanced add-on for Accessibility Checker Pro, designed to enhance your accessibility assessment capabilities. This premium extension enables\\nusers to systematically record and revisit accessibility evaluations, allowing for comprehensive over-time comparisons and in-depth site accessibility analysis.\\n\\nKey Features:\\n\\n* **Audit History Dashboard:** Centralized and intuitive dashboard for all your audit records.\\n* **Exportable Data:** Easily export your audit history to CSV for further analysis or reporting.\\n* **Visual Data Graphs:** Understand your site\\u2019s accessibility trends with clear and concise data graphs.\\n* **Comprehensive Audit List:** Quickly refer to your entire audit history from a centralized list.\\n* **Date Range Filters:** Customize your view and analysis by applying specific date range filters.\\n* **Change Insight:** Gain valuable insight with calculated percentages showcasing changes in accessibility over time.\\n* **Enhanced Accessibility Management:** With additional features aimed at providing a more holistic view of your site\\u2019s accessibility status.\\n\\n**Note:** Accessibility Checker Audit History is a premium add-on, and it requires the installation and activation of Accessibility Checker Pro to function properly. To purchase a\\nlicense, visit the [Accessibility Checker Pro website](https:\\/\\/equalizedigital.com\\/accessibility-checker\\/pricing\\/?utm_source=EDACAuditHistory&utm_medium=software&utm_campaign=readme).\\n\\n== Installation ==\\nThis add-on requires both Accessibility Checker Free and Accessibility Checker Pro plugins to be installed and active. You must have a small business or above license for it to work.\\n\\n### Installing Accessibility Checker Audit History Within WordPress\\n1. Navigate to \\u2018Plugins > Add New\\u2019 within your WordPress dashboard.\\n2. Click the \\"Upload Plugin\\" button on the Add Plugins screen.\\n3. Upload and install the zipped plugin file you received via your download link.\\n4. Once uploaded, activate \\u2018Accessibility Checker Audit History\\u2019 from your Plugins page.\\n\\n\\n### Installing Accessibility Checker Audit History Manually\\n\\n1. Extract the \\u2018accessibility-checker-audit-history\\u2019 folder from the provided zip file.\\n2. Using FTP, upload the extracted folder to the \\/wp-content\\/plugins\\/ directory on your web server.\\n3. Activate \\u2018Accessibility Checker: Audit History\\u2019 from your Plugins page within the WordPress dashboard.\\n\\n\\n\\n== Frequently Asked Questions ==\\n\\n= What support is included? =\\n\\nEqualize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and troubleshooting\\nassistance. You may [open a support ticket](https:\\/\\/my.equalizedigital.com\\/support\\/pro-support\\/) at any time. Plugin support is limited to providing assistance in using the plugin but\\ndoes not include support resolving any specific accessibility issues that have been identified.\\n\\n= Can you help me figure out how to fix an error or warning on my website? =\\n\\nIf you have questions about specific errors and warnings on your website or need help fixing problems, we offer remediation support during Office Hours for Small Business and Agency license holders. If you want more personalized auditing and dev help fixing problems on your website, check out our [audit and remediation plans](https:\\/\\/equalizedigital.com\\/services\\/website-accessibility-remediation\\/#pricing-plans).\\n\\n= Do I lose functionality if my license key is not active? =\\n\\nTo utilize Accessibility Checker Audit History features and receive plugin updates and support, you do need to have an active license key. If your license key has expired, you can\\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.\\n\\n= Can I change how often the audit scan runs? =\\n\\nThe audit scan runs daily by default. To change the interval to something else you can use this custom filter: accessibility-checker-audit-history_audit_save_interval.\\nHere is example code to change the interval to once per week:\\n\\n<pre>\\nadd_filter( \'accessibility-checker-audit-history_audit_save_interval\' , function( $minutes ){\\n    return 60 * 24 * 7; \\/\\/ Number of minutes in a week.\\n});\\n<\\/pre>\\n\\n= How can I report security bugs? =\\n\\nYou can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. [Report a security vulnerability.](https:\\/\\/patchstack.com\\/database\\/vdp\\/9e5fbe42-a7e1-4794-ad5f-db248d5ec7ee)\\n\\n== Changelog ==\\n= 1.4.0 =\\n* Improved: License messages and handling.\\n* Tweaked: Set sslverify to true for license requests.\\n\\n= 1.3.0 =\\n* Added: New filter to customize the capabilities that can see the audit history page.\\n\\n= 1.2.0 =\\n* Added: translation files\\n\\n= 1.1.2 =\\n* Fixes: Handle some situations the audit history page link would not appear in the menu.\\n\\n= 1.1.1 =\\n* Fixes: Handle notifications in the plugin better.\\n\\n= 1.1.0 =\\n* Fixes: Handle some cases where tables do not create on activation.\\n\\n= 1.0.4 =\\n* Added: demo support\\n\\n= 1.0.3 =\\n* Fixed: check for the existence of the Action Scheduler action at every admin_init and installs if it is not found\\n\\n= 1.0.2 =\\n* Fixed: automatic updates not working\\n* Update: php and js coding standards\\n* Update: development and build scripts\\n\\n= 1.0.1 =\\n* Fixed: invalid date error message not announced to screen readers\\n* Fixed: chart \\"too high\\" message\\n* Updated: chart labels with better read out for screen readers\\n* Updated: chart date format\\n* Updated: license admin notice flow and API logic\\n* Updated: date modal apply button to not be disabled\\n* Added: role and aria-label attributes to the graph\\n* Updated: role attribute on modal\\n* Added: explainer when plugin is first installed\\n* Added: logic to only load classes and assets in admin\\n* Added: Action Scheduler performance updates\\n\\n= 1.0.0 =\\n* Everything is new and shiny.\\n* We think it\'s awesome you want to make your website more accessible.\\n","description":["<p>Accessibility Checker Audit History is an advanced add-on for Accessibility Checker Pro, designed to enhance your accessibility assessment capabilities. This premium extension enables\\nusers to systematically record and revisit accessibility evaluations, allowing for comprehensive over-time comparisons and in-depth site accessibility analysis.<\\/p>\\n<p>Key Features:<\\/p>\\n<ul>\\n<li><strong>Audit History Dashboard:<\\/strong> Centralized and intuitive dashboard for all your audit records.<\\/li>\\n<li><strong>Exportable Data:<\\/strong> Easily export your audit history to CSV for further analysis or reporting.<\\/li>\\n<li><strong>Visual Data Graphs:<\\/strong> Understand your site\\u2019s accessibility trends with clear and concise data graphs.<\\/li>\\n<li><strong>Comprehensive Audit List:<\\/strong> Quickly refer to your entire audit history from a centralized list.<\\/li>\\n<li><strong>Date Range Filters:<\\/strong> Customize your view and analysis by applying specific date range filters.<\\/li>\\n<li><strong>Change Insight:<\\/strong> Gain valuable insight with calculated percentages showcasing changes in accessibility over time.<\\/li>\\n<li><strong>Enhanced Accessibility Management:<\\/strong> With additional features aimed at providing a more holistic view of your site\\u2019s accessibility status.<\\/li>\\n<\\/ul>\\n<p><strong>Note:<\\/strong> Accessibility Checker Audit History is a premium add-on, and it requires the installation and activation of Accessibility Checker Pro to function properly. To purchase a\\nlicense, visit the <a href=\\"https:\\/\\/equalizedigital.com\\/accessibility-checker\\/pricing\\/?utm_source=EDACAuditHistory&amp;utm_medium=software&amp;utm_campaign=readme\\">Accessibility Checker Pro website<\\/a>.<\\/p>"],"installation":["<p>This add-on requires both Accessibility Checker Free and Accessibility Checker Pro plugins to be installed and active. You must have a small business or above license for it to work.<\\/p>\\n<h3>Installing Accessibility Checker Audit History Within WordPress<\\/h3>\\n<ol>\\n<li>Navigate to \\u2018Plugins &gt; Add New\\u2019 within your WordPress dashboard.<\\/li>\\n<li>Click the \\"Upload Plugin\\" button on the Add Plugins screen.<\\/li>\\n<li>Upload and install the zipped plugin file you received via your download link.<\\/li>\\n<li>Once uploaded, activate \\u2018Accessibility Checker Audit History\\u2019 from your Plugins page.<\\/li>\\n<\\/ol>\\n<h3>Installing Accessibility Checker Audit History Manually<\\/h3>\\n<ol>\\n<li>Extract the \\u2018accessibility-checker-audit-history\\u2019 folder from the provided zip file.<\\/li>\\n<li>Using FTP, upload the extracted folder to the \\/wp-content\\/plugins\\/ directory on your web server.<\\/li>\\n<li>Activate \\u2018Accessibility Checker: Audit History\\u2019 from your Plugins page within the WordPress dashboard.<\\/li>\\n<\\/ol>"],"changelog":["<h4> 1.4.0 <\\/h4>\\n<ul>\\n<li>Improved: License messages and handling.<\\/li>\\n<li>Tweaked: Set sslverify to true for license requests.<\\/li>\\n<\\/ul>\\n<h4> 1.3.0 <\\/h4>\\n<ul>\\n<li>Added: New filter to customize the capabilities that can see the audit history page.<\\/li>\\n<\\/ul>\\n<h4> 1.2.0 <\\/h4>\\n<ul>\\n<li>Added: translation files<\\/li>\\n<\\/ul>\\n<h4> 1.1.2 <\\/h4>\\n<ul>\\n<li>Fixes: Handle some situations the audit history page link would not appear in the menu.<\\/li>\\n<\\/ul>\\n<h4> 1.1.1 <\\/h4>\\n<ul>\\n<li>Fixes: Handle notifications in the plugin better.<\\/li>\\n<\\/ul>\\n<h4> 1.1.0 <\\/h4>\\n<ul>\\n<li>Fixes: Handle some cases where tables do not create on activation.<\\/li>\\n<\\/ul>\\n<h4> 1.0.4 <\\/h4>\\n<ul>\\n<li>Added: demo support<\\/li>\\n<\\/ul>\\n<h4> 1.0.3 <\\/h4>\\n<ul>\\n<li>Fixed: check for the existence of the Action Scheduler action at every admin_init and installs if it is not found<\\/li>\\n<\\/ul>\\n<h4> 1.0.2 <\\/h4>\\n<ul>\\n<li>Fixed: automatic updates not working<\\/li>\\n<li>Update: php and js coding standards<\\/li>\\n<li>Update: development and build scripts<\\/li>\\n<\\/ul>\\n<h4> 1.0.1 <\\/h4>\\n<ul>\\n<li>Fixed: invalid date error message not announced to screen readers<\\/li>\\n<li>Fixed: chart \\"too high\\" message<\\/li>\\n<li>Updated: chart labels with better read out for screen readers<\\/li>\\n<li>Updated: chart date format<\\/li>\\n<li>Updated: license admin notice flow and API logic<\\/li>\\n<li>Updated: date modal apply button to not be disabled<\\/li>\\n<li>Added: role and aria-label attributes to the graph<\\/li>\\n<li>Updated: role attribute on modal<\\/li>\\n<li>Added: explainer when plugin is first installed<\\/li>\\n<li>Added: logic to only load classes and assets in admin<\\/li>\\n<li>Added: Action Scheduler performance updates<\\/li>\\n<\\/ul>\\n<h4> 1.0.0 <\\/h4>\\n<ul>\\n<li>Everything is new and shiny.<\\/li>\\n<li>We think it\'s awesome you want to make your website more accessible.<\\/li>\\n<\\/ul>"],"plugin":"accessibility-checker-audit-history\\/accessibility-checker-audit-history.php","id":"accessibility-checker-audit-history\\/accessibility-checker-audit-history.php"}";}', 'off'),
