}s:6:"tested";s:5:"6.9.1";s:8:"requires";s:3:"5.5";s:12:"requires_php";s:3:"7.4";s:16:"requires_plugins";a:0:{}s:6:"rating";i:92;s:11:"num_ratings";i:159;s:15:"support_threads";i:11;s:24:"support_threads_resolved";i:2;}s:35:"wp-mail-logging/wp-mail-logging.php";O:8:"stdClass":17:{s:2:"id";s:29:"w.org/plugins/wp-mail-logging";s:4:"slug";s:15:"wp-mail-logging";s:6:"plugin";s:35:"wp-mail-logging/wp-mail-logging.php";s:11:"new_version";s:6:"1.16.0";s:3:"url";s:46:"https://wordpress.org/plugins/wp-mail-logging/";s:7:"package";s:78:"https://plugin-updates.wpengine.com/wp-mail-logging/wp-mail-logging.1.16.0.zip";s:5:"icons";a:2:{s:2:"1x";s:75:"https://plugin-updates.wpengine.com/wp-mail-logging/assets/icon-128x128.jpg";s:2:"2x";s:75:"https://plugin-updates.wpengine.com/wp-mail-logging/assets/icon-256x256.jpg";}s:7:"banners";a:2:{s:3:"low";s:89:"https://plugin-updates.wpengine.com/wp-mail-logging/assets/banner-772x250.jpg?rev=2562296";s:4:"high";b:0;}s:11:"banners_rtl";a:0:{}s:6:"tested";s:5:"6.9.1";s:8:"requires";s:3:"5.3";s:12:"requires_php";s:3:"7.4";s:16:"requires_plugins";a:0:{}s:6:"rating";i:94;s:11:"num_ratings";i:346;s:15:"support_threads";i:4;s:24:"support_threads_resolved";i:4;}s:29:"ybug-feedback-widget/ybug.php";O:8:"stdClass":17:{s:2:"id";s:34:"w.org/plugins/ybug-feedback-widget";s:4:"slug";s:20:"ybug-feedback-widget";s:6:"plugin";s:29:"ybug-feedback-widget/ybug.php";s:11:"new_version";s:5:"1.2.2";s:3:"url";s:51:"https://wordpress.org/plugins/ybug-feedback-widget/";s:7:"package";s:87:"https://plugin-updates.wpengine.com/ybug-feedback-widget/ybug-feedback-widget.1.2.2.zip";s:5:"icons";a:2:{s:2:"1x";s:72:"https://plugin-updates.wpengine.com/ybug-feedback-widget/assets/icon.svg";s:3:"svg";s:72:"https://plugin-updates.wpengine.com/ybug-feedback-widget/assets/icon.svg";}s:7:"banners";a:0:{}s:11:"banners_rtl";a:0:{}s:6:"tested";s:5:"6.7.2";s:8:"requires";s:3:"3.1";s:12:"requires_php";s:3:"5.3";s:16:"requires_plugins";a:0:{}s:6:"rating";i:100;s:11:"num_ratings";i:1;s:15:"support_threads";i:0;s:24:"support_threads_resolved";i:0;}s:18:"searchwp/index.php";O:8:"stdClass":19:{s:4:"name";s:10:"SearchWP 4";s:11:"new_version";s:5:"4.5.8";s:14:"stable_version";s:5:"4.5.8";s:8:"sections";O:8:"stdClass":2:{s:11:"description";s:0:"";s:9:"changelog";s:52144:"<p>4.5.8</p>\n<ul>\n<li><strong>[New]</strong> Added voice search to Search Forms.</li>\n<li><strong>[New]</strong> Added support for shortcodes in the Promoted Ads content.</li>\n<li><strong>[Fix]</strong> Unexpected results when the Split Pattern Keywords option is enabled in same cases.</li>\n<li><strong>[Fix]</strong> Advanced search form filters (category, tag, author, post type) not applied when loading more results via AJAX.</li>\n<li><strong>[Fix]</strong> Search Forms post-type filter not displayed if the engine sources are not listed in the forms settings.</li>\n</ul>\n<p>4.5.7</p>\n<ul>\n<li><strong>[Update]</strong> Updated embed wizard tooltips for better visibility.</li>\n<li><strong>[Fix]</strong> Strict AND logic not respected in some cases when synonyms are involved.</li>\n<li><strong>[Fix]</strong> Deprecation notices on PHP 8.3+.</li>\n</ul>\n<p>4.5.6</p>\n<ul>\n<li><strong>[Update]</strong> Updated compatibility with WordPress 6.9.</li>\n<li><strong>[Change]</strong> If a result has no permalink, the Read More link is not displayed, and the result tile will have no link.</li>\n<li><strong>[Fix]</strong> PHP type error in some edge cases.</li>\n<li><strong>[Fix]</strong> Engine Rule\'s value overflowing the parent container.</li>\n<li><strong>[Fix]</strong> Relevance miscalculated when filtering by taxonomy term in some cases.</li>\n</ul>\n<p>4.5.5</p>\n<ul>\n<li><strong>[Fix]</strong> Pro extensions cannot be activated with the All Access Bundle license.</li>\n<li><strong>[Update]</strong> Updated admin notifications to reflect new license types.</li>\n<li><strong>[Update]</strong> Updated Translation files.</li>\n</ul>\n<p>4.5.4</p>\n<ul>\n<li><strong>[New]</strong> Added support for All Access Bundle license.</li>\n<li><strong>[Fix]</strong> Strict AND logic not respected in some cases.</li>\n</ul>\n<p>4.5.3</p>\n<ul>\n<li><strong>[Fix]</strong> Fixed compatibility with PHP 7.4.</li>\n</ul>\n<p>4.5.2</p>\n<ul>\n<li><strong>[New]</strong> Added Template option to open search result links on a new tab/window.</li>\n<li><strong>[New]</strong> Added Template option to link media files directly instead of the attachment page.</li>\n<li><strong>[Improvement]</strong> Forms setting \'Type of search\' is empty by default to allow searches on all engine sources.</li>\n<li><strong>[Improvement]</strong> Forms setting \'Type of search\' updates automatically when the Engine setting is changed.</li>\n<li><strong>[Improvement]</strong> The highlighter now prioritizes exact phrases if they are present.</li>\n<li><strong>[Improvement]</strong> Generate fallback excerpt for attachments.</li>\n<li><strong>[Change]</strong> The Diagnostics \'List Unindexed Entries\' feature now also displays entries excluded using the Exclude UI extension.</li>\n<li><strong>[Fix]</strong> Highlighting not working with the taxonomy source.</li>\n<li><strong>[Fix]</strong> Highlighting not working on PDF content if some special characters are part of the text.</li>\n<li><strong>[Fix]</strong> Synonyms not working with words with accented letters.</li>\n<li><strong>[Fix]</strong> Closest match output notice placement on FSE themes.</li>\n<li><strong>[Fix]</strong> Corrected action hook for debug logging.</li>\n<li><strong>[Fix]</strong> Target page field in Search Forms settings not saving the correct page in some cases.</li>\n</ul>\n<p>4.5.1</p>\n<ul>\n<li><strong>[Fix]</strong> SearchWP embed Wizard appears in admin pages if the block editor is disabled.</li>\n</ul>\n<p>4.5.0</p>\n<ul>\n<li><strong>[New]</strong> Added elements for Search Forms and Results templates for Elementor, Divi, Oxygen, Breakdance, Bricks, WPBakery, Beaver Builder.</li>\n<li><strong>[New]</strong> Promoted Search Ads.</li>\n<li><strong>[Improvement]</strong> Add ARIA attributes to search forms.</li>\n<li><strong>[Improvement]</strong> Improved Forms and Results template embed wizard.</li>\n<li><strong>[Change]</strong> Renamed the editor form block to "SearchWP Form".</li>\n<li><strong>[Fix]</strong> Deprecation notices in the block editor.</li>\n<li><strong>[Fix]</strong> JS error due to a malformed SVG path.</li>\n<li><strong>[Fix]</strong> jQuery Migrate notices.</li>\n<li><strong>[Fix]</strong> Corrected typo in some notification strings.</li>\n<li><strong>[Fix]</strong> Choices.js deprecation notices on some settings pages.</li>\n<li><strong>[Fix]</strong> HTML tags appear in the excerpt generated from the WooCommerce short product description.</li>\n</ul>\n<p>4.4.0</p>\n<ul>\n<li><strong>[New]</strong> Added multiple results templates.</li>\n<li><strong>[New]</strong> Added Gutenberg block, shortcode and PHP function for SearchWP Results templates.</li>\n<li><strong>[New]</strong> Integrated Diagnostics extension into the core plugin.</li>\n<li><strong>[Improvement]</strong> Minified frontend assets.</li>\n<li><strong>[Improvement]</strong> Removed Next/Previous labels from pagination if pagination uses boxed or circular style.</li>\n<li><strong>[Fix]</strong> PHP error when Engine Rule target a non-existent taxonomy.</li>\n<li><strong>[Fix]</strong> Quoted/Phrase searches working only from main site on a multisite installation.</li>\n<li><strong>[Fix]</strong> Unclosed &lt;select&gt; tag in Search Forms Advanced Search.</li>\n</ul>\n<p>4.3.18</p>\n<ul>\n<li><strong>[New]</strong> Quoted/phrase searches are now supported on multisite searches.</li>\n<li><strong>[New]</strong> Added searchwp\\source\\comment\\disable_weight_transfer filter to disable Comment weight transfer.</li>\n<li><strong>[Improvement]</strong> Improved Comments Source notice for clarity.</li>\n<li><strong>[Improvement]</strong> Retry license status check before deactivation on failure.</li>\n<li><strong>[Improvement]</strong> Improved exact matches buoy performance and results.</li>\n<li><strong>[Improvement]</strong> Improved performance of quoted/phrase searches.</li>\n<li><strong>[Update]</strong> Removed use of deprecated MySQL query modifiers and functions.</li>\n<li><strong>[Fix]</strong> Quoted/phrase search string output has redundant quotes in SearchWP template.</li>\n<li><strong>[Fix]</strong> Duplicated highlighting tags in some cases.</li>\n<li><strong>[Fix]</strong> Inconsistent results order when multiple results have the same relevance.</li>\n</ul>\n<p>4.3.17</p>\n<ul>\n<li><strong>[New]</strong> Added SearchWP Source - WPForms to Extensions page.</li>\n<li><strong>[Improvement]</strong> Forms Author dropdown now supports authors from all post types.</li>\n<li><strong>[Update]</strong> Block editor API version on Forms block.</li>\n<li><strong>[Fix]</strong> Highlighter prioritizing partial matches even when partial matches are disabled.</li>\n<li><strong>[Fix]</strong> Highlighter generating wrong excerpt if the text contains \'&lt;\' or \'&gt;\' characters.</li>\n<li><strong>[Fix]</strong> Indexer pausing automatically in some cases.</li>\n<li><strong>[Fix]</strong> Filter to disable Email Summaries not working from theme\'s functions.php file.</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.3.16 that prevented results from displaying in some cases when using the Divi Builder.</li>\n<li><strong>[Fix]</strong> Block editor link search not working.</li>\n<li><strong>[Fix]</strong> Javascript warning due to Exclude UI preview block in some installations.</li>\n<li><strong>[Fix]</strong> Wrong license type recognition during activation in some rare cases.</li>\n<li><strong>[Fix]</strong> Wrong license level displayed in bbPress missing integration notice.</li>\n</ul>\n<p>4.3.16</p>\n<ul>\n<li><strong>[New]</strong> Weekly Email Summaries.</li>\n<li><strong>[New]</strong> Added option to set pagination labels for SearchWP Templates.</li>\n<li><strong>[New]</strong> New filter to disable the Advanced Custom Fields suggestions in the Engine settings.</li>\n<li><strong>[New]</strong> New Relevance tab in the Debugging Console showing relevance for every search result.</li>\n<li><strong>[Change]</strong> Use field name if field label is not set for ACF fields in the Engine settings.</li>\n<li><strong>[Change]</strong> \'searchwp\\index\\process\\enabled\' filter overrides the Pause Indexing setting.</li>\n<li><strong>[Change]</strong> SWP_Query sorting prioritizes URL arguments, then request arguments, then defaults.</li>\n<li><strong>[Change]</strong> Optimised Divi theme integration.</li>\n<li><strong>[Change]</strong> Improved loading of Stopwords in the Global Settings page.</li>\n<li><strong>[Change]</strong> Better performance for partial matches in some cases.</li>\n<li><strong>[Change]</strong> Added multisite support to SearchWP Templates.</li>\n<li><strong>[Change]</strong> Added responsive grid sizing to the results templates.</li>\n<li><strong>[Change]</strong> Dropped support for legacy extensions asset loading.</li>\n<li><strong>[Fix]</strong> Advanced Custom Fields repeatable children not indexed correctly.</li>\n<li><strong>[Fix]</strong> AND logic not working if synonyms are capitalised or have accents.</li>\n<li><strong>[Fix]</strong> PHP error if Weight Transfer ID doesn\'t exit.</li>\n<li><strong>[Fix]</strong> Ignore delta updates during WP All Import imports.</li>\n<li><strong>[Fix]</strong> "true" and "false" search strings converted to boolean in some cases.</li>\n</ul>\n<p>4.3.15</p>\n<ul>\n<li><strong>[Change]</strong> Improved license handling.</li>\n<li><strong>[Fix]</strong> Indexer running even when paused in some cases.</li>\n</ul>\n<p>4.3.14</p>\n<ul>\n<li><strong>[New]</strong> Onboarding Wizard to simplify the initial setup.</li>\n<li><strong>[Change]</strong> Added an attribute to Search Forms to support non-default engine in Live Ajax Search.</li>\n<li><strong>[Change]</strong> SearchWP Results template supports Metrics click tracking.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> SearchWP Results template produces errors in some cases when working with custom sources.</li>\n</ul>\n<p>4.3.13</p>\n<ul>\n<li><strong>[Fix]</strong> Search Form with Default engine and Default results page produces no results in some cases.</li>\n</ul>\n<p>4.3.12</p>\n<ul>\n<li><strong>[Change]</strong> Supplemental Engines with no custom Sources can use the Default results page in Search Forms.</li>\n<li><strong>[Fix]</strong> Installation error on some systems triggered by hidden system files.</li>\n</ul>\n<p>4.3.11</p>\n<ul>\n<li><strong>[Fix]</strong> PHP error in some admin pages.</li>\n</ul>\n<p>4.3.10</p>\n<ul>\n<li><strong>[New]</strong> Product education sections are added throughout the admin area to showcase available SearchWP features.</li>\n<li><strong>[New]</strong> Deprecated extension notices are added to inform the admin and provide the alternatives.</li>\n<li><strong>[Change]</strong> Numerous feature descriptions are rephrased to explain the features better.</li>\n<li><strong>[Change]</strong> Documentation links are added to multiple features to provide additional context.</li>\n<li><strong>[Change]</strong> SearchWP begins indexing website content automatically once activated for the first time.</li>\n<li><strong>[Fix]</strong> Search Form doesn\'t show on the search page if manually included.</li>\n<li><strong>[Fix]</strong> Posts are not dropped entirely from the index when taxonomies are updated.</li>\n<li><strong>[Fix]</strong> PHP error in some edge cases when Users are updated.</li>\n</ul>\n<p>4.3.9</p>\n<ul>\n<li><strong>[Improvement]</strong> Moved the Source Author attribute for better UI/UX.</li>\n<li><strong>[Fix]</strong> Call to undefined function mysql_get_server_info() error in WP 6.4.</li>\n<li><strong>[Fix]</strong> Quoted searches not working on custom fields when wildcards are used.</li>\n<li><strong>[Fix]</strong> Highlighter not working with terms that include special characters in some cases.</li>\n</ul>\n<p>4.3.8</p>\n<ul>\n<li><strong>[Improvement]</strong> Update Media Source labels to match WordPress labels.</li>\n<li><strong>[Improvement]</strong> Reindex Media files when changes are made on Media Library quick edits.</li>\n<li><strong>[Change]</strong> SearchWP results page empty search logic is changed to match the Default results page logic.</li>\n<li><strong>[Fix]</strong> MySQL error if there are no valid tokens.</li>\n<li><strong>[Fix]</strong> PHP error when attempting to encode cookies that store an array as its value.</li>\n</ul>\n<p>4.3.7</p>\n<ul>\n<li><strong>[Fix]</strong> Search Results page \'searchwp\' parameter interferes with the custom templates.</li>\n</ul>\n<p>4.3.6</p>\n<ul>\n<li><strong>[New]</strong> Customizable SearchWP Search Results page.</li>\n<li><strong>[Change]</strong> Add Search Form setting to change button label.</li>\n<li><strong>[Fix]</strong> PHP error when attempting to encode the cookies in some cases.</li>\n</ul>\n<p>4.3.5</p>\n<ul>\n<li><strong>[Change]</strong> Make the Search Form button label translatable.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> PHP error when a taxonomy term is updated if the taxonomy is an Engine source attribute.</li>\n</ul>\n<p>4.3.4</p>\n<ul>\n<li><strong>[New]</strong> Post Author added as an engine source attribute.</li>\n<li><strong>[Improvement]</strong> Added filter for Closest Match notice text.</li>\n<li><strong>[Improvement]</strong> Added support for SVG images.</li>\n<li><strong>[Improvement]</strong> Only log statistics for the first page of results.</li>\n<li><strong>[Change]</strong> Exclude taxonomy sources from default new engine settings.</li>\n<li><strong>[Change]</strong> Order results by relevance first and post date after on empty native searches.</li>\n<li><strong>[Change]</strong> Add a specific notice to the Engines page when the indexer is paused.</li>\n<li><strong>[Update]</strong> Documentation links.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> PHP error if a site uses cookies with forbidden characters.</li>\n<li><strong>[Fix]</strong> Call to a member function on bool when using WP CLI commands.</li>\n<li><strong>[Fix]</strong> Empty searches running slow.</li>\n<li><strong>[Fix]</strong> PHP notice for deprecated use of stripos.</li>\n<li><strong>[Fix]</strong> Invalid category console notice in block editor if Modal Form extension is inactive.</li>\n<li><strong>[Fix]</strong> NOT IN condition on Media rules doesn\'t apply.</li>\n</ul>\n<p>4.3.3</p>\n<ul>\n<li><strong>[New]</strong> Taxonomy Source is added to the Engines configuration.</li>\n<li><strong>[Change]</strong> Replace site_url with home_url in Search Form action on the frontend.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> Empty search queries are logged into the statistics.</li>\n<li><strong>[Fix]</strong> Highlighting is not working if a searched keyword is followed by special characters in the original text.</li>\n<li><strong>[Fix]</strong> Search Form "Type of search" setting affects search results only when Advanced Search is enabled.</li>\n<li><strong>[Fix]</strong> Search Form is not rendering on search results page in some cases.</li>\n<li><strong>[Fix]</strong> PHP notice on Search Form render if a category was saved in form settings but deleted from WP.</li>\n<li><strong>[Fix]</strong> The whole excerpt gets highlighted on empty search if the "Highlight Terms" setting is enabled.</li>\n</ul>\n<p>4.3.2</p>\n<ul>\n<li><strong>[New]</strong> Embeddable Search Forms for a customized search experience</li>\n<li><strong>[Improvement]</strong> Better handling of Synonyms partial matches</li>\n<li><strong>[Change]</strong> SearchWP query runs for empty searches to adhere to engine restrictions</li>\n</ul>\n<p>4.3.1</p>\n<ul>\n<li><strong>[Fix]</strong> "Did you mean?" feature prevents stemming from working</li>\n<li><strong>[Fix]</strong> Strict AND logic set via the filter allows OR results</li>\n<li><strong>[Fix]</strong> Partial matches use a wildcard when it is not needed</li>\n<li><strong>[Fix]</strong> ACF suggestions are missing from the Custom Fields dropdown in the Source Attributes modal</li>\n<li><strong>[Fix]</strong> Settings in the Misc tab are not saving in some cases</li>\n<li><strong>[Fix]</strong> Statistics page shows UI which cannot be used by users with Statistics capability</li>\n<li><strong>[Fix]</strong> Notifications icon is shown to users who cannot use it because of capability restrictions</li>\n<li><strong>[Fix]</strong> Minor styling issues in the plugin settings</li>\n</ul>\n<p>4.3.0</p>\n<ul>\n<li><strong>[Improvement]</strong> Admin settings UI redesign</li>\n</ul>\n<p>4.2.9</p>\n<ul>\n<li><strong>[New]</strong> Debugging Console to view debugging data in a browser panel style</li>\n<li><strong>[Improvement]</strong> Prevent page slowdown when a taxonomy term is updated</li>\n<li><strong>[Improvement]</strong> Set default value for Post Excerpt weight to a minimum</li>\n<li><strong>[Improvement]</strong> Updated Stemmer library for better keyword stemming and PHP 8 compatibility</li>\n<li><strong>[Improvement]</strong> Updated PdfParser library for better PDF parsing</li>\n<li><strong>[Fix]</strong> "Vue is in development mode" console notice on the Settings screen</li>\n<li><strong>[Fix]</strong> Deprecation notices on PHP 8.2</li>\n<li><strong>[Fix]</strong> Plugin text domain is not loading properly</li>\n</ul>\n<p>4.2.8</p>\n<ul>\n<li><strong>[New]</strong> In-plugin notification system to get the latest updates from SearchWP</li>\n</ul>\n<p>4.2.7</p>\n<ul>\n<li><strong>[Improvement]</strong> Highlighter gives precedence to exact phrase search if present</li>\n<li><strong>[Improvement]</strong> Reduced memory usage when generating the excerpt</li>\n<li><strong>[Fix]</strong> Stemming prevents partial matches in some cases</li>\n<li><strong>[Fix]</strong> Highlighting not working with quoted searches in some cases</li>\n</ul>\n<p>4.2.6</p>\n<ul>\n<li><strong>[Improvement]</strong> Improved AJAX actions security</li>\n<li><strong>[Improvement]</strong> Updated the PdfParser library for better PDF parsing and improved compatibility</li>\n<li><strong>[Fix]</strong> Engines errors are not accessible by external code because of the private visibility</li>\n<li><strong>[Fix]</strong> License gets deactivated periodically for some rare server configurations</li>\n</ul>\n<p>4.2.5</p>\n<ul>\n<li><strong>[Improvement]</strong> Exclude taxonomy name from indexed taxonomy term fields</li>\n<li><strong>[Improvement]</strong> Do not index the image src attribute in the post content by default</li>\n<li><strong>[Fix]</strong> No post type exists check during SWP_Query query</li>\n<li><strong>[Fix]</strong> Existing SWP_Query post type can be overridden with $_REQUEST</li>\n<li><strong>[Fix]</strong> Synonyms and stemming affecting AND logic query</li>\n</ul>\n<p>4.2.4</p>\n<ul>\n<li><strong>[Improvement]</strong> Better handling of quoted phrases in synonyms</li>\n<li><strong>[Fix]</strong> Synonyms not working with non-ASCII strings</li>\n<li><strong>[Fix]</strong> Max nesting function when synonyms are applied</li>\n<li><strong>[Fix]</strong> Synonyms are not case-insensitive</li>\n<li><strong>[Fix]</strong> Synonyms affecting the stemming functionality</li>\n<li><strong>[Fix]</strong> Metrics related click tracking error in multisite environment</li>\n<li><strong>[Fix]</strong> Merging words during HTML content tokenization if<br />\nis used in the content</li>\n<li><strong>[Fix]</strong> Hiding SearchWP admin menu via the hook leaves a link to it in the admin bar menu</li>\n<li><strong>[Fix]</strong> MySQL error if engine sources have no attributes</li>\n<li><strong>[Fix]</strong> Error if \'s\' parameter in the request is not a string</li>\n<li><strong>[Fix]</strong> Warning if a custom field is added to the Users in the engine settings</li>\n<li><strong>[Fix]</strong> Return type compatibility notice in PHP 8.1 for jsonSerialize() method</li>\n</ul>\n<p>4.2.3</p>\n<ul>\n<li><strong>[Improvement]</strong> Performance improvement when getting \'post__in\' and \'post__not_in\' ids</li>\n<li><strong>[Fix]</strong> Synonyms work incorrectly when AND search logic is applied</li>\n<li><strong>[Fix]</strong> Posts are not dropped from the index when a taxonomy term is updated</li>\n<li><strong>[Fix]</strong> Quoted searches give too broad results on custom fields</li>\n<li><strong>[Fix]</strong> Quoted searches query has redundant subqueries</li>\n<li><strong>[Fix]</strong> Cross-site search limited results if "all" is passed as site args</li>\n</ul>\n<p>4.2.2</p>\n<ul>\n<li><strong>[New]</strong> Extensions admin page to install, activate and deactivate SearchWP extensions in one click</li>\n<li><strong>[Improvement]</strong> Performance improvement when getting engines configuration</li>\n<li><strong>[Fix]</strong> Search terms highlighting doesn\'t work well with quoted searches</li>\n<li><strong>[Fix]</strong> Posts are not dropped from the index when a taxonomy term is deleted from the site</li>\n<li><strong>[Fix]</strong> Stemming prevents partial matches in some cases</li>\n<li><strong>[Fix]</strong> Search terms highlighting give unexpected results with partial matches</li>\n</ul>\n<p>4.2.1</p>\n<ul>\n<li><strong>[Fix]</strong> Edited document content is not preserved</li>\n<li><strong>[Fix]</strong> Broken URLs for the redirects to the legacy admin settings</li>\n<li><strong>[Fix]</strong> Class prefixing error in smalot/pdfparser lib</li>\n<li><strong>[Fix]</strong> PHP7 static code analyzer error in symfony/polyfill-mbstring lib</li>\n</ul>\n<p>4.2.0</p>\n<ul>\n<li><strong>[Change]</strong> Plugin settings moved to the top-level menu</li>\n<li><strong>[Fix]</strong> Undefined function error during the \'index\' CLI command execution</li>\n<li><strong>[Fix]</strong> Merging words in some cases during HTML content tokenization</li>\n</ul>\n<p>4.1.22</p>\n<ul>\n<li><strong>[Fix]</strong> Synonym application too broad in some cases</li>\n<li><strong>[Fix]</strong> Document content reindexing in some cases</li>\n<li><strong>[Fix]</strong> Missing method reference in Comment source</li>\n<li><strong>[Fix]</strong> Forced phrase search returns no results if the search string doesn\'t contain non-phrase tokens</li>\n<li><strong>[Improvement]</strong> Search string normalization</li>\n<li><strong>[Improvement]</strong> String highlight application when synonyms are applied</li>\n<li><strong>[Improvement]</strong> Handling of double quotes in synonym logic in some cases</li>\n</ul>\n<p>4.1.21</p>\n<ul>\n<li><strong>[Improvement]</strong> Apply AND logic when applicable during quoted search query</li>\n<li><strong>[Fix]</strong> Default application of \'Did you mean?\' functionality in some cases</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.1.19 that prevented some results from displaying in some cases</li>\n<li><strong>[New]</strong> Filter searchwp\\native\\args\\post_type to modify native search post type when necessary</li>\n</ul>\n<p>4.1.20</p>\n<ul>\n<li><strong>[Change]</strong> Synonym processing now stops after first application unless searchwp\\synonyms\\aggressive filter returns false</li>\n<li><strong>[Fix]</strong> Global excerpt and highlighting process now uses original search string, disregarding any filtration in some cases</li>\n</ul>\n<p>4.1.19</p>\n<ul>\n<li><strong>[New]</strong> Consider Excerpt when performing quoted search</li>\n<li><strong>[Fix]</strong> Multisite re/index using WP-CLI</li>\n<li><strong>[Fix]</strong> Highlight application with flanking punctuation in some cases</li>\n<li><strong>[Fix]</strong> Highlight application with stemming enabled in some cases</li>\n<li><strong>[Fix]</strong> PHP 8 compatibility</li>\n<li><strong>[New]</strong> de_DE_formal translation</li>\n<li><strong>[Update]</strong> Dependencies</li>\n</ul>\n<p>4.1.18</p>\n<ul>\n<li><strong>[Fix]</strong> Global excerpt generation due to newline</li>\n<li><strong>[Fix]</strong> Relevance minimum clause implementation</li>\n<li><strong>[Fix]</strong> Prevent search suggestion output outside main query</li>\n<li><strong>[Fix]</strong> Incorrect fields argument definition in some cases (caused FacetWP facets to not render in some cases)</li>\n<li><strong>[Improvement]</strong> Highlight matching in some cases</li>\n</ul>\n<p>4.1.17</p>\n<ul>\n<li><strong>[New]</strong> Added relevance() method to Mods to allow additional manipulation of relevance calculation during searches</li>\n<li><strong>[Improvement]</strong> Refactored WP All Import integration</li>\n<li><strong>[Fix]</strong> Character encoding when finding global excerpts in some cases</li>\n</ul>\n<p>4.1.16</p>\n<ul>\n<li><strong>[New]</strong> searchwp\\index\\source\\add_hooks filter to allow prevention of core hook implementation</li>\n<li><strong>[New]</strong> Integration with WP All Import to better react to import processes</li>\n<li><strong>[Improvement]</strong> Global excerpt generation in some cases</li>\n<li><strong>[Improvement]</strong> Indexer state handling when programmatically pausing/unpausing</li>\n<li><strong>[Fix]</strong> Searching Media in the WordPress Admin in some cases</li>\n<li><strong>[Fix]</strong> Handling (omitting) of entries that failed indexing in some cases</li>\n<li><strong>[Fix]</strong> Statistics migration from SearchWP 3 (if Statistics failed to migrate, please open a support ticket for direct assistance)</li>\n</ul>\n<p>4.1.15</p>\n<ul>\n<li><strong>[Change]</strong> Partial matching in synonyms has been changed, to apply partial matching add a * wildcard where partial matching should be applied</li>\n<li><strong>[Change]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Global excerpt generation in some cases</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.1.12 that prevented results in some cases when setting AND logic to be strict</li>\n</ul>\n<p>4.1.14</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[New]</strong> Rule for Media to consider filename</li>\n<li><strong>[New]</strong> Rule for Pages and hierarchical CPTs to consider ancestry</li>\n<li><strong>[New]</strong> Rule for Pages and hierarchical CPTs to consider post_parent</li>\n<li><strong>[New]</strong> Edit and View actions for omitted entries</li>\n<li><strong>[New]</strong> Support for Beaver Builder Search Module</li>\n<li><strong>[Fix]</strong> Parallel indexing process when rebuilding index using WP-CLI in some cases</li>\n<li><strong>[Fix]</strong> Customization of post stati in some cases</li>\n<li><strong>[Improvement]</strong> Additional background process health check</li>\n<li><strong>[Improvement]</strong> Handling of synonym input strings in some cases</li>\n<li><strong>[Improvement]</strong> Default regular expression patterns</li>\n<li><strong>[Update]</strong> Dependencies</li>\n</ul>\n<p>4.1.13</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Admin search of hierarchical post types</li>\n<li><strong>[Fix]</strong> Support ticket iframe height minimum in some cases</li>\n<li><strong>[Improvement]</strong> Partial match logic in some cases</li>\n</ul>\n<p>4.1.12</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[New]</strong> Upper threshold that prevents AND logic when too many terms make it a performance issue (default is 5 token groups)</li>\n<li><strong>[New]</strong> Filter searchwp\\query\\logic\\and\\token_threshold to control AND logic token threshold (return false to disable threshold consideration)</li>\n<li><strong>[Fix]</strong> Issue with searching Users in the WP Admin</li>\n<li><strong>[Fix]</strong> Issue with setting query fields in some cases</li>\n<li><strong>[Fix]</strong> Statistics CSS issue in Safari in some cases</li>\n</ul>\n<p>4.1.11</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.1.9 that prevented saving parent weight transfer</li>\n<li><strong>[Improved]</strong> PDF parsing in some cases</li>\n</ul>\n<p>4.1.10</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Background process cookie validation in some cases</li>\n</ul>\n<p>4.1.9</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Improvement]</strong> Reduction in index bloat in some cases</li>\n<li><strong>[Fix]</strong> Comment parents being incorrectly returned in some cases</li>\n<li><strong>[Fix]</strong> Error when weight transfer was enabled but no recipient defined</li>\n<li><strong>[Fix]</strong> Error when using PHP8 in some cases</li>\n</ul>\n<p>4.1.8</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Improvement]</strong> Race condition prevention in background process</li>\n<li><strong>[Change]</strong> Index controller no longer observes site switching, if switching sites you will need to first use the searchwp\\auto_update_providers hook</li>\n<li><strong>[Change]</strong> Keyword stemming enabled by default during setup</li>\n<li><strong>[Fix]</strong> Results when keyword stemming and partial matching is enabled and tokens are exact matches and stemmable</li>\n<li><strong>[Fix]</strong> Statistics migration from SearchWP 3 in some cases</li>\n<li><strong>[Fix]</strong> Automatic integration with page builder plugin in some cases</li>\n<li><strong>[Fix]</strong> Issue with ACF Repeatables not appearing in some cases</li>\n<li><strong>[Fix]</strong> Issue with not being able to add custom Custom Field keys to an Engine Source</li>\n</ul>\n<p>4.1.7</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Multisite performance issue that could lead to an Error in some cases</li>\n<li><strong>[Fix]</strong> Statistics migration from SearchWP v3 (Regression introduced in 4.1.0)</li>\n</ul>\n<p>4.1.6</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Database table index optimization introduced in 4.1.5 in some configurations</li>\n<li><strong>[Fix]</strong> Partial matches with stemming enabled during AND logic in some cases</li>\n<li><strong>[Improvement]</strong> AND logic handling in some cases</li>\n</ul>\n<p>4.1.5</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Exact match buoy in partial match logic</li>\n<li><strong>[Fix]</strong> Implementation of query when site is set to \'all\' to search all network sites</li>\n<li><strong>[Improvement]</strong> Partial match logic</li>\n<li><strong>[Improvement]</strong> Handling of invalid tokens when finding partial matches</li>\n<li><strong>[Improvement]</strong> Performance when applying delta index updates</li>\n<li><strong>[Improvement]</strong> Performance when dropping Entries</li>\n<li><strong>[Improvement]</strong> Handling of duplicate tokens in some cases</li>\n<li><strong>[Improvement]</strong> Native integration in non-standard environments (e.g. page builders)</li>\n</ul>\n<p>4.1.4</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Error during partial match application on synonyms in some cases</li>\n<li><strong>[Fix]</strong> Admin search handling in some cases</li>\n</ul>\n<p>4.1.3</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Synonym partial matches in some cases</li>\n<li><strong>[Fix]</strong> Statistics display with Statistics capability but not Settings capability</li>\n<li><strong>[Fix]</strong> HTTP Basic Auth credentials regression introduced in 4.1.0</li>\n<li><strong>[Fix]</strong> AND logic performance regression introduced in 4.1.0 in some cases</li>\n<li><strong>[Improvement]</strong> AND logic performance in some cases</li>\n<li><strong>[Improvement]</strong> Background process health check coverage</li>\n<li><strong>[Improvement]</strong> PHP 8 compatibility</li>\n</ul>\n<p>4.1.2</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Improvement]</strong> Indexer handling of concurrent invocations, health check/restart when process encounters Errors</li>\n<li><strong>[Improvement]</strong> Indexer in multisite environment</li>\n<li><strong>[Fix]</strong> AND logic restrictions in some cases</li>\n</ul>\n<p>4.1.1</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Error when highlighting in some cases</li>\n</ul>\n<p>4.1.0</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[New]</strong> Refactored indexer for stability, reliability, and performance optimization</li>\n<li><strong>[New]</strong> searchwp\\index\\update_entry action when an Entry is updated in the Index</li>\n<li><strong>[New]</strong> searchwp\\debug\\front_end_summary filter to control whether the HTML comment summary is output when debugging is enabled</li>\n<li><strong>[New]</strong> wp searchwp reindex WP-CLI command</li>\n<li><strong>[New]</strong> wp searchwp diagnostics WP-CLI command</li>\n<li><strong>[New]</strong> Primary keys added to database tables <em>for new installs</em> where previously there were none</li>\n<li><strong>[New]</strong> Adds $query property to \\SWP_Query to reference underlying query object</li>\n<li><strong>[New]</strong> searchwp\\source\\comment\\parent_attribution\\strict hook to control whether SearchWP is strict about parent attribution which can introduce overhead in some cases</li>\n<li><strong>[New]</strong> SearchWP will now generate more expected variations of regex pattern matches</li>\n<li><strong>[New]</strong> searchwp\\tokens\\generate_parttern_match_variations filter to control whether additional pattern match variations are generated during indexing</li>\n<li><strong>[New]</strong> Ability to enter custom ignored queries for Statistics (with wildcard * support)</li>\n<li><strong>[New]</strong> Ability to automatically trim Statistics logs</li>\n<li><strong>[New]</strong> Notice when WordPress available memory can be improved</li>\n<li><strong>[New]</strong> Export/import now optionally includes Settings, Stopwords, and Synonyms</li>\n<li><strong>[New]</strong> All ACF fields are displayed in the Custom Fields dropdown when applicable, not only ACF "Repeatables"</li>\n<li><strong>[New]</strong> Synonyms actions: Sort ASC, Sort DESC, Clear</li>\n<li><strong>[Change]</strong> Refines default data indexed for Taxonomy Terms to be: taxonomy name, term name, term slug, and term description</li>\n<li><strong>[Change]</strong> Abstracts Statistics Dashboard Widget from jquery-ui-tabs</li>\n<li><strong>[Improvement]</strong> Indexer auto-scaling when server load is high</li>\n<li><strong>[Improvement]</strong> Handling of HTML-formed content during indexing</li>\n<li><strong>[Improvement]</strong> Integration of partial matches and keyword stemming</li>\n<li><strong>[Improvement]</strong> Indexer delta trigger specificity in some cases</li>\n<li><strong>[Improvement]</strong> Document processing handling, footprint</li>\n<li><strong>[Improvement]</strong> Highlighting when a suggested search has been returned</li>\n<li><strong>[Fix]</strong> Prevent duplicate results during weight transfer in some cases</li>\n<li><strong>[Fix]</strong> AND logic restriction, performance in some cases</li>\n<li><strong>[Fix]</strong> Persistent dismissal of missing integration notice</li>\n<li><strong>[Fix]</strong> Synonyms management in some cases</li>\n<li><strong>[Update]</strong> Dependencies</li>\n<li><strong>[Update]</strong> Translation source</li>\n<li><strong>[Update]</strong> Interface updates and refinements</li>\n</ul>\n<p>4.0.34</p>\n<ul>\n<li><strong>[Fix]</strong> Fixes regression introduced by Shortcodes fix in 4.0.33 (proper fix in Shortcodes 1.8.2)</li>\n<li><strong>[Update]</strong> Updated updater</li>\n</ul>\n<p>4.0.33</p>\n<ul>\n<li><strong>[New]</strong> searchwp\\swp_query\\mods filter to add Mods to SWP_Query</li>\n<li><strong>[Fix]</strong> PHP Warning introduced in 4.0.32</li>\n<li><strong>[Fix]</strong> Prevention of duplicate indexing processes in some cases</li>\n<li><strong>[Fix]</strong> Display issue on Statistics screen</li>\n<li><strong>[Fix]</strong> PHP Warning when Admin color schemes have been removed</li>\n<li><strong>[Fix]</strong> PDF parsing taking place unnecssarily in some cases</li>\n<li><strong>[Improvement]</strong> Disable searchwp_search_results Shortcode when generating excerpts so as to prevent unwanted loop</li>\n</ul>\n<p>4.0.32</p>\n<ul>\n<li><strong>[Fix]</strong> Duplicate indexer processes in some cases</li>\n<li><strong>[Fix]</strong> Inaccurate batch size handling in some cases</li>\n<li><strong>[Fix]</strong> Prevent redundant search suggestion output in some cases</li>\n<li><strong>[Improvement]</strong> Post stati validation when parent attribution is enabled</li>\n<li><strong>[Improvement]</strong> Attachment status handling over time</li>\n<li><strong>[New]</strong> RAND(seed) support by suffixing random Mod order_by with a colon and seed e.g. random:10 will be RAND(10)</li>\n</ul>\n<p>4.0.31</p>\n<ul>\n<li><strong>[Improvement]</strong> Adds NOT IN option to Media File Type Rule</li>\n<li><strong>[Improvement]</strong> Debug HTML comment block output during Admin requests</li>\n<li><strong>[Fix]</strong> Custom Attribute Options not returning proper Label after saving</li>\n<li><strong>[Fix]</strong> Relocate searchwp\\query\\search_string hook to fire earlier</li>\n<li><strong>[Fix]</strong> Issue when performing cross-site Multisite search</li>\n<li><strong>[Fix]</strong> searchwp\\query\\tokens\\limit default value</li>\n<li><strong>[New]</strong> Action searchwp\\query\\core_mods_out_of_bounds fires when core Mods are considered out of bounds</li>\n</ul>\n<p>4.0.30</p>\n<ul>\n<li><strong>[Fix]</strong> UI changes introduced by WordPress 5.5</li>\n<li><strong>[Fix]</strong> Global excerpt generation from search suggestions</li>\n<li><strong>[Fix]</strong> Synonym migration from SearchWP 3.x</li>\n</ul>\n<p>4.0.29</p>\n<ul>\n<li><strong>[Fix]</strong> Token handling in some cases</li>\n<li><strong>[Fix]</strong> Document content handling when using alternate indexer in some cases</li>\n<li><strong>[Improvement]</strong> Tokenization of HTML in some cases</li>\n<li><strong>[New]</strong> searchwp\\entry\\update_data\\before action fired before Entry data is retrieved</li>\n<li><strong>[Update]</strong> Bundle dependencies</li>\n</ul>\n<p>4.0.28</p>\n<ul>\n<li><strong>[Fix]</strong> Prevent inapplicable comment edit events from triggering delta updates</li>\n<li><strong>[Improvement]</strong> Reduced index method checks</li>\n<li><strong>[Improvement]</strong> Reactivity when observing meta updates</li>\n</ul>\n<p>4.0.27</p>\n<ul>\n<li><strong>[Fix]</strong> File Content meta box display in some cases</li>\n<li><strong>[Fix]</strong> Entries not being reintroduced after failing when using alternate indexer</li>\n<li><strong>[Fix]</strong> Display of Source Attribute Options when statically defined</li>\n<li><strong>[Fix]</strong> UI display edge cases</li>\n<li><strong>[Change]</strong> Token handling chunked in more cases so as to avoid issues when hosts limit query character length</li>\n</ul>\n<p>4.0.26</p>\n<ul>\n<li><strong>[Fix]</strong> Handling of SWP_Query tax_query argument</li>\n<li><strong>[New]</strong> Advanced setting checkbox to control whether stored document content is purged and re-indexed during index rebuilds</li>\n<li><strong>[Update]</strong> Translation source</li>\n</ul>\n<p>4.0.25</p>\n<ul>\n<li><strong>[Fix]</strong> Regression introduced in 4.0.24 when utilizing PDF Metadata</li>\n<li><strong>[Improvement]</strong> Note displayed in SearchWP Document Content meta box when document is queued but not yet processed</li>\n<li><strong>[Update]</strong> Translation source</li>\n</ul>\n<p>4.0.24</p>\n<ul>\n<li><strong>[Fix]</strong> Handling of PDF metadata that includes invalid characters</li>\n<li><strong>[Fix]</strong> Searching of hierarchical post types in the Admin</li>\n<li><strong>[Improvement]</strong> Performance when handling documents outside the indexing process</li>\n<li><strong>[Update]</strong> Bundle dependencies</li>\n</ul>\n<p>4.0.23</p>\n<ul>\n<li><strong>[Fix]</strong> Utilize previously extracted PDF metadata instead of parsing it repeatedly</li>\n<li><strong>[Change]</strong> Updated default batch size for Media to 3, can be customized with searchwp\\indexer\\batch_size\\post.attachment hook</li>\n<li><strong>[Improvement]</strong> Handling of urlencoded tokens in some cases</li>\n</ul>\n<p>4.0.22</p>\n<ul>\n<li><strong>[New]</strong> Query parameter support for post_type when using SWP_Query (additional parameter support is planned)</li>\n<li><strong>[Fix]</strong> Issue with partial matching yielding zero results in some cases</li>\n<li><strong>[Fix]</strong> Quoted search support for WP_Post Content, Document Content</li>\n<li><strong>[Improvement]</strong> Reduced debug log volume (logs should be deleted once you\'re done debugging)</li>\n</ul>\n<p>4.0.20</p>\n<ul>\n<li><strong>[New]</strong> New filter searchwp\\source\\post\\db_where to customize global WHERE limits per post type</li>\n<li><strong>[New]</strong> License key is automatically activated when provided via constant or hook</li>\n<li><strong>[Fix]</strong> Error on uninstall when removing all data</li>\n<li><strong>[Fix]</strong> Issue where Mods were not applied to SWP_Query in some cases</li>\n<li><strong>[Change]</strong> No longer relying on excerpt_more when working with excerpts, now using ellipsis filtered by searchwp\\utils\\excerpt_more</li>\n<li><strong>[Improvement]</strong> Handling of rare cases where index would need to be woken up repeatedly in order to build</li>\n<li><strong>[Improvement]</strong> Omits redundant Entry retrieval in some cases</li>\n<li><strong>[Improvement]</strong> Significant performance retrieval when generating excerpts (e.g. Highlighting)</li>\n<li><strong>[Improvement]</strong> Advanced Custom Fields integration support</li>\n</ul>\n<p>4.0.19</p>\n<ul>\n<li><strong>[Notice]</strong> Mods have in part been cleaned up and refined in this release, which may affect your usage. Please review any Mods you are using by testing this update on a staging server. If you are manipulating relevance weight based on date, it is likely you will need to update your hooks. Snippets have been updated on the KB article <a href="https://searchwp.com/?p=222848">https://searchwp.com/?p=222848</a> for review. Please also ensure your SearchWP Extensions are up to date as well.</li>\n<li><strong>[Fix]</strong> Source Mod WHERE clauses causing errors in some cases</li>\n<li><strong>[Fix]</strong> Raw Mod WHERE clauses had no local alias to utilize</li>\n<li><strong>[Fix]</strong> Mod JOIN claus order was not retained causing errors in some cases</li>\n<li><strong>[Improvement]</strong> Optimized Mod handling in SWP_Query</li>\n<li><strong>[Improvement]</strong> Disable integration extension checks when doing AJAX</li>\n</ul>\n<p>4.0.18</p>\n<ul>\n<li><strong>[Fix]</strong> Error when using mod argument of \\SearchWP\\Query parameters array</li>\n<li><strong>[Improvement]</strong> Control over Settings page navigation</li>\n</ul>\n<p>4.0.17</p>\n<ul>\n<li><strong>[Note]</strong> Rebuilding your index using the Rebuild Index button on the Engines tab of the SearchWP settings screen is recommended after updating</li>\n<li><strong>[Fix]</strong> Delta update regression introduced in 4.0.13</li>\n<li><strong>[Fix]</strong> Error when applying delta update to Source that no longer exists</li>\n<li><strong>[Improvement]</strong> Handling of delta update process during failures</li>\n<li><strong>[Improvement]</strong> Delta update queue handling during index rebuild</li>\n</ul>\n<p>4.0.16</p>\n<ul>\n<li><strong>[Fix]</strong> Invalid range in character class introduced in 4.0.15 for PHP 7.3+</li>\n<li><strong>[Change]</strong> searchwp\\tokens\\whitelist\\only_full_matches retagged as searchwp\\tokens\\regex_patterns\\only_full_matches</li>\n<li><strong>[Change]</strong> searchwp\\tokens\\apply_rules_to_whitelist retagged as searchwp\\tokens\\apply_rules_to_pattern_matches</li>\n<li><strong>[Change]</strong> searchwp\\tokens\\whitelist_regex_patterns retagged as searchwp\\tokens\\regex_patterns</li>\n<li><strong>[Change]</strong> Regex pattern matches are now tokenized during indexing (but remain exclusive when searching by default when applicable)</li>\n<li><strong>[New]</strong> Filter searchwp\\tokens\\tokenize_pattern_matches\\indexing to disable new tokenizing of pattern match behavior during indexing</li>\n</ul>\n<p>4.0.15</p>\n<ul>\n<li><strong>[New]</strong> New filter searchwp\\tokens\\string to customize strings before tokenization</li>\n<li><strong>[Fix]</strong> Handling of synonyms when finding partial matches</li>\n<li><strong>[Fix]</strong> Implementation and handling of regex pattern match tokenization setting</li>\n<li><strong>[Improvement]</strong> Dash/hyphen and word match regex patterns</li>\n<li><strong>[Improvement]</strong> searchwp\\source\\post\\excerpt_haystack filter now passes arguments array</li>\n<li><strong>[Update]</strong> Translation source</li>\n</ul>\n<p>4.0.14</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where partial matches from keyword stems were not found in some cases</li>\n<li><strong>[Fix]</strong> Partial match token processing limited to applicable site(s)</li>\n<li><strong>[Fix]</strong> Excerpt generation when handling unregistered Shortcodes</li>\n</ul>\n<p>4.0.13</p>\n<ul>\n<li><strong>[Fix]</strong> Delta update routine when using alternate indexer that caused unwanted exit</li>\n<li><strong>[Fix]</strong> <strong>searchwp\\document\\content</strong> implementation</li>\n<li><strong>[Improvement]</strong> Index integrity check when rebuilding</li>\n<li><strong>[Improvement]</strong> Source hook management in multisite</li>\n<li><strong>[Improvement]</strong> Upgrade routine process</li>\n</ul>\n<p>4.0.12</p>\n<ul>\n<li><strong>[Fix]</strong> Inability to filter searchwp\\settings\\capability</li>\n<li><strong>[Fix]</strong> Issue with Highlighting in some cases</li>\n<li><strong>[Fix]</strong> Document Content not properly considered for global excerpt in some cases</li>\n<li><strong>[Fix]</strong> Warning when reacting to invalid Entry during indexing</li>\n<li><strong>[Fix]</strong> Namespace issue with PDF parsing in some cases</li>\n<li><strong>[Fix]</strong> Unnecessary provider reset when switching to the same site in multisite</li>\n<li><strong>[Update]</strong> Updated updater</li>\n</ul>\n<p>4.0.11</p>\n<ul>\n<li><strong>[Fix]</strong> Loss of tokens when applying partial match logic in some cases</li>\n<li><strong>[Update]</strong> Revised MySQL minimum to 5.6 (MariaDB 10.0) because of utf8mb4_unicode_520_ci collation requirement</li>\n</ul>\n<p>4.0.9</p>\n<ul>\n<li><strong>[Fix]</strong> Regression introduced in 4.0.6 that prevented non WP_Post results from returning</li>\n</ul>\n<p>4.0.8</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where taxonomy Rules for Media were not applied correctly in some cases</li>\n</ul>\n<p>4.0.7</p>\n<ul>\n<li><strong>[Fix]</strong> Mod WHERE clauses not restricted to Source when defined</li>\n</ul>\n<p>4.0.6</p>\n<ul>\n<li><strong>[Change]</strong> Post is now returned when parent weight transfer is enabled but Post has no post_parent</li>\n<li><strong>[Improvement]</strong> Excerpt handling for native results</li>\n<li><strong>[Improvement]</strong> Additional prevention of invalid WP_Post results being returned in one case</li>\n</ul>\n<p>4.0.5</p>\n<ul>\n<li><strong>[New]</strong> Filter to control stemmer locale searchwp\\stemmer\\locale</li>\n<li><strong>[Improvement]</strong> Token stems/partial matches are considered during AND logic pass</li>\n<li><strong>[Fix]</strong> String not sent to searchwp\\stemmer\\custom</li>\n<li><strong>[Change]</strong> searchwp\\query\\partial_matches\\buoy is now opt-in</li>\n</ul>\n<p>4.0.4</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where AND logic would not apply in some cases</li>\n<li><strong>[Fix]</strong> Issue where additional unnecessary query clauses are added in some cases</li>\n<li><strong>[Fix]</strong> Issue with delta updates not processing when HTTP Basic Auth is active</li>\n<li><strong>[Fix]</strong> Minimum PHP version requirement check (which is 7.2)</li>\n</ul>\n<p>4.0.3</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where tokens table was not reset during index rebuild</li>\n</ul>\n<p>4.0.2</p>\n<ul>\n<li><strong>[New]</strong> Support for BETWEEN, NOT BETWEEN, LIKE, and NOT LIKE compare operators for Mod WHERE clauses</li>\n<li><strong>[Fix]</strong> Handling of Mod WHERE clauses in some cases</li>\n<li><strong>[Fix]</strong> Handling of REST parameters when returning search results</li>\n</ul>\n<p>4.0.1</p>\n<ul>\n<li><strong>[New]</strong> Check for remnants of SearchWP 3 that were not removed as per the Migration Guide</li>\n<li><strong>[New]</strong> searchwp\\source\\post\\attributes\\comments action when retrieving Post comments</li>\n<li><strong>[Fix]</strong> Handling of empty search strings in some cases</li>\n</ul>\n<p>4.0.0</p>\n<ul>\n<li><strong>[New]</strong> Complete rewrite of SearchWP</li>\n</ul>\n";}s:13:"license_check";s:0:"";s:3:"msg";s:0:"";s:8:"homepage";s:42:"https://searchwp.com/downloads/searchwp-4/";s:7:"package";s:213:"https://searchwp.com/edd-sl/package_download/MTc3MjEyMjA2NjowOTJjMGMzNjhjN2FkOTZiZjcyOTMzMTlhNjBjYTZiOToyMTYwMjk6NTM4ZmY5ZjRkNGQ1NjE0ZTFkMzRmYTU3NWFkNmE3YWQ6aHR0cHNALy9iZXJraGFtY291bnMud3BlbmdpbmVwb3dlcmVkLmNvbTow";s:5:"icons";a:2:{s:2:"1x";s:79:"https://searchwp.com/wp-content/uploads/2021/02/avatar-searchwp-alt-128x128.png";s:2:"2x";s:79:"https://searchwp.com/wp-content/uploads/2021/02/avatar-searchwp-alt-256x256.png";}s:7:"banners";O:8:"stdClass":2:{s:4:"high";s:0:"";s:3:"low";s:0:"";}s:4:"slug";s:5:"index";s:3:"url";s:54:"https://searchwp.com/downloads/searchwp-4/?changelog=1";s:12:"last_updated";s:19:"2026-02-19 17:52:07";s:13:"download_link";s:213:"https://searchwp.com/edd-sl/package_download/MTc3MjEyMjA2NjowOTJjMGMzNjhjN2FkOTZiZjcyOTMzMTlhNjBjYTZiOToyMTYwMjk6NTM4ZmY5ZjRkNGQ1NjE0ZTFkMzRmYTU3NWFkNmE3YWQ6aHR0cHNALy9iZXJraGFtY291bnMud3BlbmdpbmVwb3dlcmVkLmNvbTow";s:12:"requires_php";s:5:"5.6.0";s:11:"description";a:1:{i:0;s:0:"";}s:9:"changelog";a:1:{i:0;s:52144:"<p>4.5.8</p>\n<ul>\n<li><strong>[New]</strong> Added voice search to Search Forms.</li>\n<li><strong>[New]</strong> Added support for shortcodes in the Promoted Ads content.</li>\n<li><strong>[Fix]</strong> Unexpected results when the Split Pattern Keywords option is enabled in same cases.</li>\n<li><strong>[Fix]</strong> Advanced search form filters (category, tag, author, post type) not applied when loading more results via AJAX.</li>\n<li><strong>[Fix]</strong> Search Forms post-type filter not displayed if the engine sources are not listed in the forms settings.</li>\n</ul>\n<p>4.5.7</p>\n<ul>\n<li><strong>[Update]</strong> Updated embed wizard tooltips for better visibility.</li>\n<li><strong>[Fix]</strong> Strict AND logic not respected in some cases when synonyms are involved.</li>\n<li><strong>[Fix]</strong> Deprecation notices on PHP 8.3+.</li>\n</ul>\n<p>4.5.6</p>\n<ul>\n<li><strong>[Update]</strong> Updated compatibility with WordPress 6.9.</li>\n<li><strong>[Change]</strong> If a result has no permalink, the Read More link is not displayed, and the result tile will have no link.</li>\n<li><strong>[Fix]</strong> PHP type error in some edge cases.</li>\n<li><strong>[Fix]</strong> Engine Rule\'s value overflowing the parent container.</li>\n<li><strong>[Fix]</strong> Relevance miscalculated when filtering by taxonomy term in some cases.</li>\n</ul>\n<p>4.5.5</p>\n<ul>\n<li><strong>[Fix]</strong> Pro extensions cannot be activated with the All Access Bundle license.</li>\n<li><strong>[Update]</strong> Updated admin notifications to reflect new license types.</li>\n<li><strong>[Update]</strong> Updated Translation files.</li>\n</ul>\n<p>4.5.4</p>\n<ul>\n<li><strong>[New]</strong> Added support for All Access Bundle license.</li>\n<li><strong>[Fix]</strong> Strict AND logic not respected in some cases.</li>\n</ul>\n<p>4.5.3</p>\n<ul>\n<li><strong>[Fix]</strong> Fixed compatibility with PHP 7.4.</li>\n</ul>\n<p>4.5.2</p>\n<ul>\n<li><strong>[New]</strong> Added Template option to open search result links on a new tab/window.</li>\n<li><strong>[New]</strong> Added Template option to link media files directly instead of the attachment page.</li>\n<li><strong>[Improvement]</strong> Forms setting \'Type of search\' is empty by default to allow searches on all engine sources.</li>\n<li><strong>[Improvement]</strong> Forms setting \'Type of search\' updates automatically when the Engine setting is changed.</li>\n<li><strong>[Improvement]</strong> The highlighter now prioritizes exact phrases if they are present.</li>\n<li><strong>[Improvement]</strong> Generate fallback excerpt for attachments.</li>\n<li><strong>[Change]</strong> The Diagnostics \'List Unindexed Entries\' feature now also displays entries excluded using the Exclude UI extension.</li>\n<li><strong>[Fix]</strong> Highlighting not working with the taxonomy source.</li>\n<li><strong>[Fix]</strong> Highlighting not working on PDF content if some special characters are part of the text.</li>\n<li><strong>[Fix]</strong> Synonyms not working with words with accented letters.</li>\n<li><strong>[Fix]</strong> Closest match output notice placement on FSE themes.</li>\n<li><strong>[Fix]</strong> Corrected action hook for debug logging.</li>\n<li><strong>[Fix]</strong> Target page field in Search Forms settings not saving the correct page in some cases.</li>\n</ul>\n<p>4.5.1</p>\n<ul>\n<li><strong>[Fix]</strong> SearchWP embed Wizard appears in admin pages if the block editor is disabled.</li>\n</ul>\n<p>4.5.0</p>\n<ul>\n<li><strong>[New]</strong> Added elements for Search Forms and Results templates for Elementor, Divi, Oxygen, Breakdance, Bricks, WPBakery, Beaver Builder.</li>\n<li><strong>[New]</strong> Promoted Search Ads.</li>\n<li><strong>[Improvement]</strong> Add ARIA attributes to search forms.</li>\n<li><strong>[Improvement]</strong> Improved Forms and Results template embed wizard.</li>\n<li><strong>[Change]</strong> Renamed the editor form block to "SearchWP Form".</li>\n<li><strong>[Fix]</strong> Deprecation notices in the block editor.</li>\n<li><strong>[Fix]</strong> JS error due to a malformed SVG path.</li>\n<li><strong>[Fix]</strong> jQuery Migrate notices.</li>\n<li><strong>[Fix]</strong> Corrected typo in some notification strings.</li>\n<li><strong>[Fix]</strong> Choices.js deprecation notices on some settings pages.</li>\n<li><strong>[Fix]</strong> HTML tags appear in the excerpt generated from the WooCommerce short product description.</li>\n</ul>\n<p>4.4.0</p>\n<ul>\n<li><strong>[New]</strong> Added multiple results templates.</li>\n<li><strong>[New]</strong> Added Gutenberg block, shortcode and PHP function for SearchWP Results templates.</li>\n<li><strong>[New]</strong> Integrated Diagnostics extension into the core plugin.</li>\n<li><strong>[Improvement]</strong> Minified frontend assets.</li>\n<li><strong>[Improvement]</strong> Removed Next/Previous labels from pagination if pagination uses boxed or circular style.</li>\n<li><strong>[Fix]</strong> PHP error when Engine Rule target a non-existent taxonomy.</li>\n<li><strong>[Fix]</strong> Quoted/Phrase searches working only from main site on a multisite installation.</li>\n<li><strong>[Fix]</strong> Unclosed &lt;select&gt; tag in Search Forms Advanced Search.</li>\n</ul>\n<p>4.3.18</p>\n<ul>\n<li><strong>[New]</strong> Quoted/phrase searches are now supported on multisite searches.</li>\n<li><strong>[New]</strong> Added searchwp\\source\\comment\\disable_weight_transfer filter to disable Comment weight transfer.</li>\n<li><strong>[Improvement]</strong> Improved Comments Source notice for clarity.</li>\n<li><strong>[Improvement]</strong> Retry license status check before deactivation on failure.</li>\n<li><strong>[Improvement]</strong> Improved exact matches buoy performance and results.</li>\n<li><strong>[Improvement]</strong> Improved performance of quoted/phrase searches.</li>\n<li><strong>[Update]</strong> Removed use of deprecated MySQL query modifiers and functions.</li>\n<li><strong>[Fix]</strong> Quoted/phrase search string output has redundant quotes in SearchWP template.</li>\n<li><strong>[Fix]</strong> Duplicated highlighting tags in some cases.</li>\n<li><strong>[Fix]</strong> Inconsistent results order when multiple results have the same relevance.</li>\n</ul>\n<p>4.3.17</p>\n<ul>\n<li><strong>[New]</strong> Added SearchWP Source - WPForms to Extensions page.</li>\n<li><strong>[Improvement]</strong> Forms Author dropdown now supports authors from all post types.</li>\n<li><strong>[Update]</strong> Block editor API version on Forms block.</li>\n<li><strong>[Fix]</strong> Highlighter prioritizing partial matches even when partial matches are disabled.</li>\n<li><strong>[Fix]</strong> Highlighter generating wrong excerpt if the text contains \'&lt;\' or \'&gt;\' characters.</li>\n<li><strong>[Fix]</strong> Indexer pausing automatically in some cases.</li>\n<li><strong>[Fix]</strong> Filter to disable Email Summaries not working from theme\'s functions.php file.</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.3.16 that prevented results from displaying in some cases when using the Divi Builder.</li>\n<li><strong>[Fix]</strong> Block editor link search not working.</li>\n<li><strong>[Fix]</strong> Javascript warning due to Exclude UI preview block in some installations.</li>\n<li><strong>[Fix]</strong> Wrong license type recognition during activation in some rare cases.</li>\n<li><strong>[Fix]</strong> Wrong license level displayed in bbPress missing integration notice.</li>\n</ul>\n<p>4.3.16</p>\n<ul>\n<li><strong>[New]</strong> Weekly Email Summaries.</li>\n<li><strong>[New]</strong> Added option to set pagination labels for SearchWP Templates.</li>\n<li><strong>[New]</strong> New filter to disable the Advanced Custom Fields suggestions in the Engine settings.</li>\n<li><strong>[New]</strong> New Relevance tab in the Debugging Console showing relevance for every search result.</li>\n<li><strong>[Change]</strong> Use field name if field label is not set for ACF fields in the Engine settings.</li>\n<li><strong>[Change]</strong> \'searchwp\\index\\process\\enabled\' filter overrides the Pause Indexing setting.</li>\n<li><strong>[Change]</strong> SWP_Query sorting prioritizes URL arguments, then request arguments, then defaults.</li>\n<li><strong>[Change]</strong> Optimised Divi theme integration.</li>\n<li><strong>[Change]</strong> Improved loading of Stopwords in the Global Settings page.</li>\n<li><strong>[Change]</strong> Better performance for partial matches in some cases.</li>\n<li><strong>[Change]</strong> Added multisite support to SearchWP Templates.</li>\n<li><strong>[Change]</strong> Added responsive grid sizing to the results templates.</li>\n<li><strong>[Change]</strong> Dropped support for legacy extensions asset loading.</li>\n<li><strong>[Fix]</strong> Advanced Custom Fields repeatable children not indexed correctly.</li>\n<li><strong>[Fix]</strong> AND logic not working if synonyms are capitalised or have accents.</li>\n<li><strong>[Fix]</strong> PHP error if Weight Transfer ID doesn\'t exit.</li>\n<li><strong>[Fix]</strong> Ignore delta updates during WP All Import imports.</li>\n<li><strong>[Fix]</strong> "true" and "false" search strings converted to boolean in some cases.</li>\n</ul>\n<p>4.3.15</p>\n<ul>\n<li><strong>[Change]</strong> Improved license handling.</li>\n<li><strong>[Fix]</strong> Indexer running even when paused in some cases.</li>\n</ul>\n<p>4.3.14</p>\n<ul>\n<li><strong>[New]</strong> Onboarding Wizard to simplify the initial setup.</li>\n<li><strong>[Change]</strong> Added an attribute to Search Forms to support non-default engine in Live Ajax Search.</li>\n<li><strong>[Change]</strong> SearchWP Results template supports Metrics click tracking.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> SearchWP Results template produces errors in some cases when working with custom sources.</li>\n</ul>\n<p>4.3.13</p>\n<ul>\n<li><strong>[Fix]</strong> Search Form with Default engine and Default results page produces no results in some cases.</li>\n</ul>\n<p>4.3.12</p>\n<ul>\n<li><strong>[Change]</strong> Supplemental Engines with no custom Sources can use the Default results page in Search Forms.</li>\n<li><strong>[Fix]</strong> Installation error on some systems triggered by hidden system files.</li>\n</ul>\n<p>4.3.11</p>\n<ul>\n<li><strong>[Fix]</strong> PHP error in some admin pages.</li>\n</ul>\n<p>4.3.10</p>\n<ul>\n<li><strong>[New]</strong> Product education sections are added throughout the admin area to showcase available SearchWP features.</li>\n<li><strong>[New]</strong> Deprecated extension notices are added to inform the admin and provide the alternatives.</li>\n<li><strong>[Change]</strong> Numerous feature descriptions are rephrased to explain the features better.</li>\n<li><strong>[Change]</strong> Documentation links are added to multiple features to provide additional context.</li>\n<li><strong>[Change]</strong> SearchWP begins indexing website content automatically once activated for the first time.</li>\n<li><strong>[Fix]</strong> Search Form doesn\'t show on the search page if manually included.</li>\n<li><strong>[Fix]</strong> Posts are not dropped entirely from the index when taxonomies are updated.</li>\n<li><strong>[Fix]</strong> PHP error in some edge cases when Users are updated.</li>\n</ul>\n<p>4.3.9</p>\n<ul>\n<li><strong>[Improvement]</strong> Moved the Source Author attribute for better UI/UX.</li>\n<li><strong>[Fix]</strong> Call to undefined function mysql_get_server_info() error in WP 6.4.</li>\n<li><strong>[Fix]</strong> Quoted searches not working on custom fields when wildcards are used.</li>\n<li><strong>[Fix]</strong> Highlighter not working with terms that include special characters in some cases.</li>\n</ul>\n<p>4.3.8</p>\n<ul>\n<li><strong>[Improvement]</strong> Update Media Source labels to match WordPress labels.</li>\n<li><strong>[Improvement]</strong> Reindex Media files when changes are made on Media Library quick edits.</li>\n<li><strong>[Change]</strong> SearchWP results page empty search logic is changed to match the Default results page logic.</li>\n<li><strong>[Fix]</strong> MySQL error if there are no valid tokens.</li>\n<li><strong>[Fix]</strong> PHP error when attempting to encode cookies that store an array as its value.</li>\n</ul>\n<p>4.3.7</p>\n<ul>\n<li><strong>[Fix]</strong> Search Results page \'searchwp\' parameter interferes with the custom templates.</li>\n</ul>\n<p>4.3.6</p>\n<ul>\n<li><strong>[New]</strong> Customizable SearchWP Search Results page.</li>\n<li><strong>[Change]</strong> Add Search Form setting to change button label.</li>\n<li><strong>[Fix]</strong> PHP error when attempting to encode the cookies in some cases.</li>\n</ul>\n<p>4.3.5</p>\n<ul>\n<li><strong>[Change]</strong> Make the Search Form button label translatable.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> PHP error when a taxonomy term is updated if the taxonomy is an Engine source attribute.</li>\n</ul>\n<p>4.3.4</p>\n<ul>\n<li><strong>[New]</strong> Post Author added as an engine source attribute.</li>\n<li><strong>[Improvement]</strong> Added filter for Closest Match notice text.</li>\n<li><strong>[Improvement]</strong> Added support for SVG images.</li>\n<li><strong>[Improvement]</strong> Only log statistics for the first page of results.</li>\n<li><strong>[Change]</strong> Exclude taxonomy sources from default new engine settings.</li>\n<li><strong>[Change]</strong> Order results by relevance first and post date after on empty native searches.</li>\n<li><strong>[Change]</strong> Add a specific notice to the Engines page when the indexer is paused.</li>\n<li><strong>[Update]</strong> Documentation links.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> PHP error if a site uses cookies with forbidden characters.</li>\n<li><strong>[Fix]</strong> Call to a member function on bool when using WP CLI commands.</li>\n<li><strong>[Fix]</strong> Empty searches running slow.</li>\n<li><strong>[Fix]</strong> PHP notice for deprecated use of stripos.</li>\n<li><strong>[Fix]</strong> Invalid category console notice in block editor if Modal Form extension is inactive.</li>\n<li><strong>[Fix]</strong> NOT IN condition on Media rules doesn\'t apply.</li>\n</ul>\n<p>4.3.3</p>\n<ul>\n<li><strong>[New]</strong> Taxonomy Source is added to the Engines configuration.</li>\n<li><strong>[Change]</strong> Replace site_url with home_url in Search Form action on the frontend.</li>\n<li><strong>[Update]</strong> Translation files.</li>\n<li><strong>[Fix]</strong> Empty search queries are logged into the statistics.</li>\n<li><strong>[Fix]</strong> Highlighting is not working if a searched keyword is followed by special characters in the original text.</li>\n<li><strong>[Fix]</strong> Search Form "Type of search" setting affects search results only when Advanced Search is enabled.</li>\n<li><strong>[Fix]</strong> Search Form is not rendering on search results page in some cases.</li>\n<li><strong>[Fix]</strong> PHP notice on Search Form render if a category was saved in form settings but deleted from WP.</li>\n<li><strong>[Fix]</strong> The whole excerpt gets highlighted on empty search if the "Highlight Terms" setting is enabled.</li>\n</ul>\n<p>4.3.2</p>\n<ul>\n<li><strong>[New]</strong> Embeddable Search Forms for a customized search experience</li>\n<li><strong>[Improvement]</strong> Better handling of Synonyms partial matches</li>\n<li><strong>[Change]</strong> SearchWP query runs for empty searches to adhere to engine restrictions</li>\n</ul>\n<p>4.3.1</p>\n<ul>\n<li><strong>[Fix]</strong> "Did you mean?" feature prevents stemming from working</li>\n<li><strong>[Fix]</strong> Strict AND logic set via the filter allows OR results</li>\n<li><strong>[Fix]</strong> Partial matches use a wildcard when it is not needed</li>\n<li><strong>[Fix]</strong> ACF suggestions are missing from the Custom Fields dropdown in the Source Attributes modal</li>\n<li><strong>[Fix]</strong> Settings in the Misc tab are not saving in some cases</li>\n<li><strong>[Fix]</strong> Statistics page shows UI which cannot be used by users with Statistics capability</li>\n<li><strong>[Fix]</strong> Notifications icon is shown to users who cannot use it because of capability restrictions</li>\n<li><strong>[Fix]</strong> Minor styling issues in the plugin settings</li>\n</ul>\n<p>4.3.0</p>\n<ul>\n<li><strong>[Improvement]</strong> Admin settings UI redesign</li>\n</ul>\n<p>4.2.9</p>\n<ul>\n<li><strong>[New]</strong> Debugging Console to view debugging data in a browser panel style</li>\n<li><strong>[Improvement]</strong> Prevent page slowdown when a taxonomy term is updated</li>\n<li><strong>[Improvement]</strong> Set default value for Post Excerpt weight to a minimum</li>\n<li><strong>[Improvement]</strong> Updated Stemmer library for better keyword stemming and PHP 8 compatibility</li>\n<li><strong>[Improvement]</strong> Updated PdfParser library for better PDF parsing</li>\n<li><strong>[Fix]</strong> "Vue is in development mode" console notice on the Settings screen</li>\n<li><strong>[Fix]</strong> Deprecation notices on PHP 8.2</li>\n<li><strong>[Fix]</strong> Plugin text domain is not loading properly</li>\n</ul>\n<p>4.2.8</p>\n<ul>\n<li><strong>[New]</strong> In-plugin notification system to get the latest updates from SearchWP</li>\n</ul>\n<p>4.2.7</p>\n<ul>\n<li><strong>[Improvement]</strong> Highlighter gives precedence to exact phrase search if present</li>\n<li><strong>[Improvement]</strong> Reduced memory usage when generating the excerpt</li>\n<li><strong>[Fix]</strong> Stemming prevents partial matches in some cases</li>\n<li><strong>[Fix]</strong> Highlighting not working with quoted searches in some cases</li>\n</ul>\n<p>4.2.6</p>\n<ul>\n<li><strong>[Improvement]</strong> Improved AJAX actions security</li>\n<li><strong>[Improvement]</strong> Updated the PdfParser library for better PDF parsing and improved compatibility</li>\n<li><strong>[Fix]</strong> Engines errors are not accessible by external code because of the private visibility</li>\n<li><strong>[Fix]</strong> License gets deactivated periodically for some rare server configurations</li>\n</ul>\n<p>4.2.5</p>\n<ul>\n<li><strong>[Improvement]</strong> Exclude taxonomy name from indexed taxonomy term fields</li>\n<li><strong>[Improvement]</strong> Do not index the image src attribute in the post content by default</li>\n<li><strong>[Fix]</strong> No post type exists check during SWP_Query query</li>\n<li><strong>[Fix]</strong> Existing SWP_Query post type can be overridden with $_REQUEST</li>\n<li><strong>[Fix]</strong> Synonyms and stemming affecting AND logic query</li>\n</ul>\n<p>4.2.4</p>\n<ul>\n<li><strong>[Improvement]</strong> Better handling of quoted phrases in synonyms</li>\n<li><strong>[Fix]</strong> Synonyms not working with non-ASCII strings</li>\n<li><strong>[Fix]</strong> Max nesting function when synonyms are applied</li>\n<li><strong>[Fix]</strong> Synonyms are not case-insensitive</li>\n<li><strong>[Fix]</strong> Synonyms affecting the stemming functionality</li>\n<li><strong>[Fix]</strong> Metrics related click tracking error in multisite environment</li>\n<li><strong>[Fix]</strong> Merging words during HTML content tokenization if<br />\nis used in the content</li>\n<li><strong>[Fix]</strong> Hiding SearchWP admin menu via the hook leaves a link to it in the admin bar menu</li>\n<li><strong>[Fix]</strong> MySQL error if engine sources have no attributes</li>\n<li><strong>[Fix]</strong> Error if \'s\' parameter in the request is not a string</li>\n<li><strong>[Fix]</strong> Warning if a custom field is added to the Users in the engine settings</li>\n<li><strong>[Fix]</strong> Return type compatibility notice in PHP 8.1 for jsonSerialize() method</li>\n</ul>\n<p>4.2.3</p>\n<ul>\n<li><strong>[Improvement]</strong> Performance improvement when getting \'post__in\' and \'post__not_in\' ids</li>\n<li><strong>[Fix]</strong> Synonyms work incorrectly when AND search logic is applied</li>\n<li><strong>[Fix]</strong> Posts are not dropped from the index when a taxonomy term is updated</li>\n<li><strong>[Fix]</strong> Quoted searches give too broad results on custom fields</li>\n<li><strong>[Fix]</strong> Quoted searches query has redundant subqueries</li>\n<li><strong>[Fix]</strong> Cross-site search limited results if "all" is passed as site args</li>\n</ul>\n<p>4.2.2</p>\n<ul>\n<li><strong>[New]</strong> Extensions admin page to install, activate and deactivate SearchWP extensions in one click</li>\n<li><strong>[Improvement]</strong> Performance improvement when getting engines configuration</li>\n<li><strong>[Fix]</strong> Search terms highlighting doesn\'t work well with quoted searches</li>\n<li><strong>[Fix]</strong> Posts are not dropped from the index when a taxonomy term is deleted from the site</li>\n<li><strong>[Fix]</strong> Stemming prevents partial matches in some cases</li>\n<li><strong>[Fix]</strong> Search terms highlighting give unexpected results with partial matches</li>\n</ul>\n<p>4.2.1</p>\n<ul>\n<li><strong>[Fix]</strong> Edited document content is not preserved</li>\n<li><strong>[Fix]</strong> Broken URLs for the redirects to the legacy admin settings</li>\n<li><strong>[Fix]</strong> Class prefixing error in smalot/pdfparser lib</li>\n<li><strong>[Fix]</strong> PHP7 static code analyzer error in symfony/polyfill-mbstring lib</li>\n</ul>\n<p>4.2.0</p>\n<ul>\n<li><strong>[Change]</strong> Plugin settings moved to the top-level menu</li>\n<li><strong>[Fix]</strong> Undefined function error during the \'index\' CLI command execution</li>\n<li><strong>[Fix]</strong> Merging words in some cases during HTML content tokenization</li>\n</ul>\n<p>4.1.22</p>\n<ul>\n<li><strong>[Fix]</strong> Synonym application too broad in some cases</li>\n<li><strong>[Fix]</strong> Document content reindexing in some cases</li>\n<li><strong>[Fix]</strong> Missing method reference in Comment source</li>\n<li><strong>[Fix]</strong> Forced phrase search returns no results if the search string doesn\'t contain non-phrase tokens</li>\n<li><strong>[Improvement]</strong> Search string normalization</li>\n<li><strong>[Improvement]</strong> String highlight application when synonyms are applied</li>\n<li><strong>[Improvement]</strong> Handling of double quotes in synonym logic in some cases</li>\n</ul>\n<p>4.1.21</p>\n<ul>\n<li><strong>[Improvement]</strong> Apply AND logic when applicable during quoted search query</li>\n<li><strong>[Fix]</strong> Default application of \'Did you mean?\' functionality in some cases</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.1.19 that prevented some results from displaying in some cases</li>\n<li><strong>[New]</strong> Filter searchwp\\native\\args\\post_type to modify native search post type when necessary</li>\n</ul>\n<p>4.1.20</p>\n<ul>\n<li><strong>[Change]</strong> Synonym processing now stops after first application unless searchwp\\synonyms\\aggressive filter returns false</li>\n<li><strong>[Fix]</strong> Global excerpt and highlighting process now uses original search string, disregarding any filtration in some cases</li>\n</ul>\n<p>4.1.19</p>\n<ul>\n<li><strong>[New]</strong> Consider Excerpt when performing quoted search</li>\n<li><strong>[Fix]</strong> Multisite re/index using WP-CLI</li>\n<li><strong>[Fix]</strong> Highlight application with flanking punctuation in some cases</li>\n<li><strong>[Fix]</strong> Highlight application with stemming enabled in some cases</li>\n<li><strong>[Fix]</strong> PHP 8 compatibility</li>\n<li><strong>[New]</strong> de_DE_formal translation</li>\n<li><strong>[Update]</strong> Dependencies</li>\n</ul>\n<p>4.1.18</p>\n<ul>\n<li><strong>[Fix]</strong> Global excerpt generation due to newline</li>\n<li><strong>[Fix]</strong> Relevance minimum clause implementation</li>\n<li><strong>[Fix]</strong> Prevent search suggestion output outside main query</li>\n<li><strong>[Fix]</strong> Incorrect fields argument definition in some cases (caused FacetWP facets to not render in some cases)</li>\n<li><strong>[Improvement]</strong> Highlight matching in some cases</li>\n</ul>\n<p>4.1.17</p>\n<ul>\n<li><strong>[New]</strong> Added relevance() method to Mods to allow additional manipulation of relevance calculation during searches</li>\n<li><strong>[Improvement]</strong> Refactored WP All Import integration</li>\n<li><strong>[Fix]</strong> Character encoding when finding global excerpts in some cases</li>\n</ul>\n<p>4.1.16</p>\n<ul>\n<li><strong>[New]</strong> searchwp\\index\\source\\add_hooks filter to allow prevention of core hook implementation</li>\n<li><strong>[New]</strong> Integration with WP All Import to better react to import processes</li>\n<li><strong>[Improvement]</strong> Global excerpt generation in some cases</li>\n<li><strong>[Improvement]</strong> Indexer state handling when programmatically pausing/unpausing</li>\n<li><strong>[Fix]</strong> Searching Media in the WordPress Admin in some cases</li>\n<li><strong>[Fix]</strong> Handling (omitting) of entries that failed indexing in some cases</li>\n<li><strong>[Fix]</strong> Statistics migration from SearchWP 3 (if Statistics failed to migrate, please open a support ticket for direct assistance)</li>\n</ul>\n<p>4.1.15</p>\n<ul>\n<li><strong>[Change]</strong> Partial matching in synonyms has been changed, to apply partial matching add a * wildcard where partial matching should be applied</li>\n<li><strong>[Change]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Global excerpt generation in some cases</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.1.12 that prevented results in some cases when setting AND logic to be strict</li>\n</ul>\n<p>4.1.14</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[New]</strong> Rule for Media to consider filename</li>\n<li><strong>[New]</strong> Rule for Pages and hierarchical CPTs to consider ancestry</li>\n<li><strong>[New]</strong> Rule for Pages and hierarchical CPTs to consider post_parent</li>\n<li><strong>[New]</strong> Edit and View actions for omitted entries</li>\n<li><strong>[New]</strong> Support for Beaver Builder Search Module</li>\n<li><strong>[Fix]</strong> Parallel indexing process when rebuilding index using WP-CLI in some cases</li>\n<li><strong>[Fix]</strong> Customization of post stati in some cases</li>\n<li><strong>[Improvement]</strong> Additional background process health check</li>\n<li><strong>[Improvement]</strong> Handling of synonym input strings in some cases</li>\n<li><strong>[Improvement]</strong> Default regular expression patterns</li>\n<li><strong>[Update]</strong> Dependencies</li>\n</ul>\n<p>4.1.13</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Admin search of hierarchical post types</li>\n<li><strong>[Fix]</strong> Support ticket iframe height minimum in some cases</li>\n<li><strong>[Improvement]</strong> Partial match logic in some cases</li>\n</ul>\n<p>4.1.12</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[New]</strong> Upper threshold that prevents AND logic when too many terms make it a performance issue (default is 5 token groups)</li>\n<li><strong>[New]</strong> Filter searchwp\\query\\logic\\and\\token_threshold to control AND logic token threshold (return false to disable threshold consideration)</li>\n<li><strong>[Fix]</strong> Issue with searching Users in the WP Admin</li>\n<li><strong>[Fix]</strong> Issue with setting query fields in some cases</li>\n<li><strong>[Fix]</strong> Statistics CSS issue in Safari in some cases</li>\n</ul>\n<p>4.1.11</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Regression introduced in 4.1.9 that prevented saving parent weight transfer</li>\n<li><strong>[Improved]</strong> PDF parsing in some cases</li>\n</ul>\n<p>4.1.10</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Background process cookie validation in some cases</li>\n</ul>\n<p>4.1.9</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Improvement]</strong> Reduction in index bloat in some cases</li>\n<li><strong>[Fix]</strong> Comment parents being incorrectly returned in some cases</li>\n<li><strong>[Fix]</strong> Error when weight transfer was enabled but no recipient defined</li>\n<li><strong>[Fix]</strong> Error when using PHP8 in some cases</li>\n</ul>\n<p>4.1.8</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Improvement]</strong> Race condition prevention in background process</li>\n<li><strong>[Change]</strong> Index controller no longer observes site switching, if switching sites you will need to first use the searchwp\\auto_update_providers hook</li>\n<li><strong>[Change]</strong> Keyword stemming enabled by default during setup</li>\n<li><strong>[Fix]</strong> Results when keyword stemming and partial matching is enabled and tokens are exact matches and stemmable</li>\n<li><strong>[Fix]</strong> Statistics migration from SearchWP 3 in some cases</li>\n<li><strong>[Fix]</strong> Automatic integration with page builder plugin in some cases</li>\n<li><strong>[Fix]</strong> Issue with ACF Repeatables not appearing in some cases</li>\n<li><strong>[Fix]</strong> Issue with not being able to add custom Custom Field keys to an Engine Source</li>\n</ul>\n<p>4.1.7</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Multisite performance issue that could lead to an Error in some cases</li>\n<li><strong>[Fix]</strong> Statistics migration from SearchWP v3 (Regression introduced in 4.1.0)</li>\n</ul>\n<p>4.1.6</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Database table index optimization introduced in 4.1.5 in some configurations</li>\n<li><strong>[Fix]</strong> Partial matches with stemming enabled during AND logic in some cases</li>\n<li><strong>[Improvement]</strong> AND logic handling in some cases</li>\n</ul>\n<p>4.1.5</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Exact match buoy in partial match logic</li>\n<li><strong>[Fix]</strong> Implementation of query when site is set to \'all\' to search all network sites</li>\n<li><strong>[Improvement]</strong> Partial match logic</li>\n<li><strong>[Improvement]</strong> Handling of invalid tokens when finding partial matches</li>\n<li><strong>[Improvement]</strong> Performance when applying delta index updates</li>\n<li><strong>[Improvement]</strong> Performance when dropping Entries</li>\n<li><strong>[Improvement]</strong> Handling of duplicate tokens in some cases</li>\n<li><strong>[Improvement]</strong> Native integration in non-standard environments (e.g. page builders)</li>\n</ul>\n<p>4.1.4</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Error during partial match application on synonyms in some cases</li>\n<li><strong>[Fix]</strong> Admin search handling in some cases</li>\n</ul>\n<p>4.1.3</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Synonym partial matches in some cases</li>\n<li><strong>[Fix]</strong> Statistics display with Statistics capability but not Settings capability</li>\n<li><strong>[Fix]</strong> HTTP Basic Auth credentials regression introduced in 4.1.0</li>\n<li><strong>[Fix]</strong> AND logic performance regression introduced in 4.1.0 in some cases</li>\n<li><strong>[Improvement]</strong> AND logic performance in some cases</li>\n<li><strong>[Improvement]</strong> Background process health check coverage</li>\n<li><strong>[Improvement]</strong> PHP 8 compatibility</li>\n</ul>\n<p>4.1.2</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Improvement]</strong> Indexer handling of concurrent invocations, health check/restart when process encounters Errors</li>\n<li><strong>[Improvement]</strong> Indexer in multisite environment</li>\n<li><strong>[Fix]</strong> AND logic restrictions in some cases</li>\n</ul>\n<p>4.1.1</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[Fix]</strong> Error when highlighting in some cases</li>\n</ul>\n<p>4.1.0</p>\n<ul>\n<li><strong>[IMPORTANT]</strong> Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index</em>, this is not done automatically and should be planned for when updating)</li>\n<li><strong>[New]</strong> Refactored indexer for stability, reliability, and performance optimization</li>\n<li><strong>[New]</strong> searchwp\\index\\update_entry action when an Entry is updated in the Index</li>\n<li><strong>[New]</strong> searchwp\\debug\\front_end_summary filter to control whether the HTML comment summary is output when debugging is enabled</li>\n<li><strong>[New]</strong> wp searchwp reindex WP-CLI command</li>\n<li><strong>[New]</strong> wp searchwp diagnostics WP-CLI command</li>\n<li><strong>[New]</strong> Primary keys added to database tables <em>for new installs</em> where previously there were none</li>\n<li><strong>[New]</strong> Adds $query property to \\SWP_Query to reference underlying query object</li>\n<li><strong>[New]</strong> searchwp\\source\\comment\\parent_attribution\\strict hook to control whether SearchWP is strict about parent attribution which can introduce overhead in some cases</li>\n<li><strong>[New]</strong> SearchWP will now generate more expected variations of regex pattern matches</li>\n<li><strong>[New]</strong> searchwp\\tokens\\generate_parttern_match_variations filter to control whether additional pattern match variations are generated during indexing</li>\n<li><strong>[New]</strong> Ability to enter custom ignored queries for Statistics (with wildcard * support)</li>\n<li><strong>[New]</strong> Ability to automatically trim Statistics logs</li>\n<li><strong>[New]</strong> Notice when WordPress available memory can be improved</li>\n<li><strong>[New]</strong> Export/import now optionally includes Settings, Stopwords, and Synonyms</li>\n<li><strong>[New]</strong> All ACF fields are displayed in the Custom Fields dropdown when applicable, not only ACF "Repeatables"</li>\n<li><strong>[New]</strong> Synonyms actions: Sort ASC, Sort DESC, Clear</li>\n<li><strong>[Change]</strong> Refines default data indexed for Taxonomy Terms to be: taxonomy name, term name, term slug, and term description</li>\n<li><strong>[Change]</strong> Abstracts Statistics Dashboard Widget from jquery-ui-tabs</li>\n<li><strong>[Improvement]</strong> Indexer auto-scaling when server load is high</li>\n<li><strong>[Improvement]</strong> Handling of HTML-formed content during indexing</li>\n<li><strong>[Improvement]</strong> Integration of partial matches and keyword stemming</li>\n<li><strong>[Improvement]</strong> Indexer delta trigger specificity in some cases</li>\n<li><strong>[Improvement]</strong> Document processing handling, footprint</li>\n<li><strong>[Improvement]</strong> Highlighting when a suggested search has been returned</li>\n<li><strong>[Fix]</strong> Prevent duplicate results during weight transfer in some cases</li>\n<li><strong>[Fix]</strong> AND logic restriction, performance in some cases</li>\n<li><strong>[Fix]</strong> Persistent dismissal of missing integration notice</li>\n<li><strong>[Fix]</strong> Synonyms management in some cases</li>\n<li><strong>[Update]</strong> Dependencies</li>\n<li><strong>[Update]</strong> Translation source</li>\n<li><strong>[Update]</strong> Interface updates and refinements</li>\n</ul>\n<p>4.0.34</p>\n<ul>\n<li><strong>[Fix]</strong> Fixes regression introduced by Shortcodes fix in 4.0.33 (proper fix in Shortcodes 1.8.2)</li>\n<li><strong>[Update]</strong> Updated updater</li>\n</ul>\n<p>4.0.33</p>\n<ul>\n<li><strong>[New]</strong> searchwp\\swp_query\\mods filter to add Mods to SWP_Query</li>\n<li><strong>[Fix]</strong> PHP Warning introduced in 4.0.32</li>\n<li><strong>[Fix]</strong> Prevention of duplicate indexing processes in some cases</li>\n<li><strong>[Fix]</strong> Display issue on Statistics screen</li>\n<li><strong>[Fix]</strong> PHP Warning when Admin color schemes have been removed</li>\n<li><strong>[Fix]</strong> PDF parsing taking place unnecssarily in some cases</li>\n<li><strong>[Improvement]</strong> Disable searchwp_search_results Shortcode when generating excerpts so as to prevent unwanted loop</li>\n</ul>\n<p>4.0.32</p>\n<ul>\n<li><strong>[Fix]</strong> Duplicate indexer processes in some cases</li>\n<li><strong>[Fix]</strong> Inaccurate batch size handling in some cases</li>\n<li><strong>[Fix]</strong> Prevent redundant search suggestion output in some cases</li>\n<li><strong>[Improvement]</strong> Post stati validation when parent attribution is enabled</li>\n<li><strong>[Improvement]</strong> Attachment status handling over time</li>\n<li><strong>[New]</strong> RAND(seed) support by suffixing random Mod order_by with a colon and seed e.g. random:10 will be RAND(10)</li>\n</ul>\n<p>4.0.31</p>\n<ul>\n<li><strong>[Improvement]</strong> Adds NOT IN option to Media File Type Rule</li>\n<li><strong>[Improvement]</strong> Debug HTML comment block output during Admin requests</li>\n<li><strong>[Fix]</strong> Custom Attribute Options not returning proper Label after saving</li>\n<li><strong>[Fix]</strong> Relocate searchwp\\query\\search_string hook to fire earlier</li>\n<li><strong>[Fix]</strong> Issue when performing cross-site Multisite search</li>\n<li><strong>[Fix]</strong> searchwp\\query\\tokens\\limit default value</li>\n<li><strong>[New]</strong> Action searchwp\\query\\core_mods_out_of_bounds fires when core Mods are considered out of bounds</li>\n</ul>\n<p>4.0.30</p>\n<ul>\n<li><strong>[Fix]</strong> UI changes introduced by WordPress 5.5</li>\n<li><strong>[Fix]</strong> Global excerpt generation from search suggestions</li>\n<li><strong>[Fix]</strong> Synonym migration from SearchWP 3.x</li>\n</ul>\n<p>4.0.29</p>\n<ul>\n<li><strong>[Fix]</strong> Token handling in some cases</li>\n<li><strong>[Fix]</strong> Document content handling when using alternate indexer in some cases</li>\n<li><strong>[Improvement]</strong> Tokenization of HTML in some cases</li>\n<li><strong>[New]</strong> searchwp\\entry\\update_data\\before action fired before Entry data is retrieved</li>\n<li><strong>[Update]</strong> Bundle dependencies</li>\n</ul>\n<p>4.0.28</p>\n<ul>\n<li><strong>[Fix]</strong> Prevent inapplicable comment edit events from triggering delta updates</li>\n<li><strong>[Improvement]</strong> Reduced index method checks</li>\n<li><strong>[Improvement]</strong> Reactivity when observing meta updates</li>\n</ul>\n<p>4.0.27</p>\n<ul>\n<li><strong>[Fix]</strong> File Content meta box display in some cases</li>\n<li><strong>[Fix]</strong> Entries not being reintroduced after failing when using alternate indexer</li>\n<li><strong>[Fix]</strong> Display of Source Attribute Options when statically defined</li>\n<li><strong>[Fix]</strong> UI display edge cases</li>\n<li><strong>[Change]</strong> Token handling chunked in more cases so as to avoid issues when hosts limit query character length</li>\n</ul>\n<p>4.0.26</p>\n<ul>\n<li><strong>[Fix]</strong> Handling of SWP_Query tax_query argument</li>\n<li><strong>[New]</strong> Advanced setting checkbox to control whether stored document content is purged and re-indexed during index rebuilds</li>\n<li><strong>[Update]</strong> Translation source</li>\n</ul>\n<p>4.0.25</p>\n<ul>\n<li><strong>[Fix]</strong> Regression introduced in 4.0.24 when utilizing PDF Metadata</li>\n<li><strong>[Improvement]</strong> Note displayed in SearchWP Document Content meta box when document is queued but not yet processed</li>\n<li><strong>[Update]</strong> Translation source</li>\n</ul>\n<p>4.0.24</p>\n<ul>\n<li><strong>[Fix]</strong> Handling of PDF metadata that includes invalid characters</li>\n<li><strong>[Fix]</strong> Searching of hierarchical post types in the Admin</li>\n<li><strong>[Improvement]</strong> Performance when handling documents outside the indexing process</li>\n<li><strong>[Update]</strong> Bundle dependencies</li>\n</ul>\n<p>4.0.23</p>\n<ul>\n<li><strong>[Fix]</strong> Utilize previously extracted PDF metadata instead of parsing it repeatedly</li>\n<li><strong>[Change]</strong> Updated default batch size for Media to 3, can be customized with searchwp\\indexer\\batch_size\\post.attachment hook</li>\n<li><strong>[Improvement]</strong> Handling of urlencoded tokens in some cases</li>\n</ul>\n<p>4.0.22</p>\n<ul>\n<li><strong>[New]</strong> Query parameter support for post_type when using SWP_Query (additional parameter support is planned)</li>\n<li><strong>[Fix]</strong> Issue with partial matching yielding zero results in some cases</li>\n<li><strong>[Fix]</strong> Quoted search support for WP_Post Content, Document Content</li>\n<li><strong>[Improvement]</strong> Reduced debug log volume (logs should be deleted once you\'re done debugging)</li>\n</ul>\n<p>4.0.20</p>\n<ul>\n<li><strong>[New]</strong> New filter searchwp\\source\\post\\db_where to customize global WHERE limits per post type</li>\n<li><strong>[New]</strong> License key is automatically activated when provided via constant or hook</li>\n<li><strong>[Fix]</strong> Error on uninstall when removing all data</li>\n<li><strong>[Fix]</strong> Issue where Mods were not applied to SWP_Query in some cases</li>\n<li><strong>[Change]</strong> No longer relying on excerpt_more when working with excerpts, now using ellipsis filtered by searchwp\\utils\\excerpt_more</li>\n<li><strong>[Improvement]</strong> Handling of rare cases where index would need to be woken up repeatedly in order to build</li>\n<li><strong>[Improvement]</strong> Omits redundant Entry retrieval in some cases</li>\n<li><strong>[Improvement]</strong> Significant performance retrieval when generating excerpts (e.g. Highlighting)</li>\n<li><strong>[Improvement]</strong> Advanced Custom Fields integration support</li>\n</ul>\n<p>4.0.19</p>\n<ul>\n<li><strong>[Notice]</strong> Mods have in part been cleaned up and refined in this release, which may affect your usage. Please review any Mods you are using by testing this update on a staging server. If you are manipulating relevance weight based on date, it is likely you will need to update your hooks. Snippets have been updated on the KB article <a href="https://searchwp.com/?p=222848">https://searchwp.com/?p=222848</a> for review. Please also ensure your SearchWP Extensions are up to date as well.</li>\n<li><strong>[Fix]</strong> Source Mod WHERE clauses causing errors in some cases</li>\n<li><strong>[Fix]</strong> Raw Mod WHERE clauses had no local alias to utilize</li>\n<li><strong>[Fix]</strong> Mod JOIN claus order was not retained causing errors in some cases</li>\n<li><strong>[Improvement]</strong> Optimized Mod handling in SWP_Query</li>\n<li><strong>[Improvement]</strong> Disable integration extension checks when doing AJAX</li>\n</ul>\n<p>4.0.18</p>\n<ul>\n<li><strong>[Fix]</strong> Error when using mod argument of \\SearchWP\\Query parameters array</li>\n<li><strong>[Improvement]</strong> Control over Settings page navigation</li>\n</ul>\n<p>4.0.17</p>\n<ul>\n<li><strong>[Note]</strong> Rebuilding your index using the Rebuild Index button on the Engines tab of the SearchWP settings screen is recommended after updating</li>\n<li><strong>[Fix]</strong> Delta update regression introduced in 4.0.13</li>\n<li><strong>[Fix]</strong> Error when applying delta update to Source that no longer exists</li>\n<li><strong>[Improvement]</strong> Handling of delta update process during failures</li>\n<li><strong>[Improvement]</strong> Delta update queue handling during index rebuild</li>\n</ul>\n<p>4.0.16</p>\n<ul>\n<li><strong>[Fix]</strong> Invalid range in character class introduced in 4.0.15 for PHP 7.3+</li>\n<li><strong>[Change]</strong> searchwp\\tokens\\whitelist\\only_full_matches retagged as searchwp\\tokens\\regex_patterns\\only_full_matches</li>\n<li><strong>[Change]</strong> searchwp\\tokens\\apply_rules_to_whitelist retagged as searchwp\\tokens\\apply_rules_to_pattern_matches</li>\n<li><strong>[Change]</strong> searchwp\\tokens\\whitelist_regex_patterns retagged as searchwp\\tokens\\regex_patterns</li>\n<li><strong>[Change]</strong> Regex pattern matches are now tokenized during indexing (but remain exclusive when searching by default when applicable)</li>\n<li><strong>[New]</strong> Filter searchwp\\tokens\\tokenize_pattern_matches\\indexing to disable new tokenizing of pattern match behavior during indexing</li>\n</ul>\n<p>4.0.15</p>\n<ul>\n<li><strong>[New]</strong> New filter searchwp\\tokens\\string to customize strings before tokenization</li>\n<li><strong>[Fix]</strong> Handling of synonyms when finding partial matches</li>\n<li><strong>[Fix]</strong> Implementation and handling of regex pattern match tokenization setting</li>\n<li><strong>[Improvement]</strong> Dash/hyphen and word match regex patterns</li>\n<li><strong>[Improvement]</strong> searchwp\\source\\post\\excerpt_haystack filter now passes arguments array</li>\n<li><strong>[Update]</strong> Translation source</li>\n</ul>\n<p>4.0.14</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where partial matches from keyword stems were not found in some cases</li>\n<li><strong>[Fix]</strong> Partial match token processing limited to applicable site(s)</li>\n<li><strong>[Fix]</strong> Excerpt generation when handling unregistered Shortcodes</li>\n</ul>\n<p>4.0.13</p>\n<ul>\n<li><strong>[Fix]</strong> Delta update routine when using alternate indexer that caused unwanted exit</li>\n<li><strong>[Fix]</strong> <strong>searchwp\\document\\content</strong> implementation</li>\n<li><strong>[Improvement]</strong> Index integrity check when rebuilding</li>\n<li><strong>[Improvement]</strong> Source hook management in multisite</li>\n<li><strong>[Improvement]</strong> Upgrade routine process</li>\n</ul>\n<p>4.0.12</p>\n<ul>\n<li><strong>[Fix]</strong> Inability to filter searchwp\\settings\\capability</li>\n<li><strong>[Fix]</strong> Issue with Highlighting in some cases</li>\n<li><strong>[Fix]</strong> Document Content not properly considered for global excerpt in some cases</li>\n<li><strong>[Fix]</strong> Warning when reacting to invalid Entry during indexing</li>\n<li><strong>[Fix]</strong> Namespace issue with PDF parsing in some cases</li>\n<li><strong>[Fix]</strong> Unnecessary provider reset when switching to the same site in multisite</li>\n<li><strong>[Update]</strong> Updated updater</li>\n</ul>\n<p>4.0.11</p>\n<ul>\n<li><strong>[Fix]</strong> Loss of tokens when applying partial match logic in some cases</li>\n<li><strong>[Update]</strong> Revised MySQL minimum to 5.6 (MariaDB 10.0) because of utf8mb4_unicode_520_ci collation requirement</li>\n</ul>\n<p>4.0.9</p>\n<ul>\n<li><strong>[Fix]</strong> Regression introduced in 4.0.6 that prevented non WP_Post results from returning</li>\n</ul>\n<p>4.0.8</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where taxonomy Rules for Media were not applied correctly in some cases</li>\n</ul>\n<p>4.0.7</p>\n<ul>\n<li><strong>[Fix]</strong> Mod WHERE clauses not restricted to Source when defined</li>\n</ul>\n<p>4.0.6</p>\n<ul>\n<li><strong>[Change]</strong> Post is now returned when parent weight transfer is enabled but Post has no post_parent</li>\n<li><strong>[Improvement]</strong> Excerpt handling for native results</li>\n<li><strong>[Improvement]</strong> Additional prevention of invalid WP_Post results being returned in one case</li>\n</ul>\n<p>4.0.5</p>\n<ul>\n<li><strong>[New]</strong> Filter to control stemmer locale searchwp\\stemmer\\locale</li>\n<li><strong>[Improvement]</strong> Token stems/partial matches are considered during AND logic pass</li>\n<li><strong>[Fix]</strong> String not sent to searchwp\\stemmer\\custom</li>\n<li><strong>[Change]</strong> searchwp\\query\\partial_matches\\buoy is now opt-in</li>\n</ul>\n<p>4.0.4</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where AND logic would not apply in some cases</li>\n<li><strong>[Fix]</strong> Issue where additional unnecessary query clauses are added in some cases</li>\n<li><strong>[Fix]</strong> Issue with delta updates not processing when HTTP Basic Auth is active</li>\n<li><strong>[Fix]</strong> Minimum PHP version requirement check (which is 7.2)</li>\n</ul>\n<p>4.0.3</p>\n<ul>\n<li><strong>[Fix]</strong> Issue where tokens table was not reset during index rebuild</li>\n</ul>\n<p>4.0.2</p>\n<ul>\n<li><strong>[New]</strong> Support for BETWEEN, NOT BETWEEN, LIKE, and NOT LIKE compare operators for Mod WHERE clauses</li>\n<li><strong>[Fix]</strong> Handling of Mod WHERE clauses in some cases</li>\n<li><strong>[Fix]</strong> Handling of REST parameters when returning search results</li>\n</ul>\n<p>4.0.1</p>\n<ul>\n<li><strong>[New]</strong> Check for remnants of SearchWP 3 that were not removed as per the Migration Guide</li>\n<li><strong>[New]</strong> searchwp\\source\\post\\attributes\\comments action when retrieving Post comments</li>\n<li><strong>[Fix]</strong> Handling of empty search strings in some cases</li>\n</ul>\n<p>4.0.0</p>\n<ul>\n<li><strong>[New]</strong> Complete rewrite of SearchWP</li>\n</ul>\n";}s:6:"plugin";s:18:"searchwp/index.php";s:2:"id";s:18:"searchwp/index.php";}s:27:"perfmatters/perfmatters.php";O:8:"stdClass":10:{s:4:"slug";s:11:"perfmatters";s:6:"plugin";s:27:"perfmatters/perfmatters.php";s:3:"url";s:57:"https://perfmatters.io/downloads/perfmatters/?changelog=1";s:7:"package";s:211:"https://perfmatters.io/edd-sl/package_download/MTc3MjA3MTY2NjoxMjQzNGM1MzEzMWUxODJhYzYxOTAxYjBjMDNkNDQ5ZTo2OTY6N2Q5ZTA3ZTE5NDYyYzdkMDRmODgzYTA0ZDNiMGVjYTc6aHR0cHNALy9iZXJraGFtY291bnMud3BlbmdpbmVwb3dlcmVkLmNvbTow";s:5:"icons";a:2:{s:2:"1x";s:92:"https://perfmatters.io/wp-content/uploads/edd/2026/01/perfmatters-logo-250x250-1-128x128.png";s:2:"2x";s:84:"https://perfmatters.io/wp-content/uploads/edd/2026/01/perfmatters-logo-250x250-1.png";}s:7:"banners";a:2:{s:4:"high";s:94:"https://perfmatters.io/wp-content/uploads/edd/2026/01/perfmatters-plugin-banner-1544x500-1.png";s:3:"low";s:93:"https://perfmatters.io/wp-content/uploads/edd/2026/01/perfmatters-plugin-banner-772x250-1.png";}s:11:"new_version";s:5:"2.5.7";s:6:"tested";s:5:"6.9.1";s:8:"requires";s:0:"";s:12:"requires_php";s:0:"";}s:55:"accessibility-checker-pro/accessibility-checker-pro.php";O:8:"stdClass":38:{s:4:"name";s:21:"Accessibility Checker";s:11:"new_version";s:6:"1.20.0";s:14:"stable_version";s:6:"1.20.0";s:8:"sections";O:8:"stdClass":4:{s:11:"description";s:732:"<p>Accessibility Check Pro is a premium plugin that expands the free Accessibility Checker available in the WordPress.org plugin directory.\nAccessibility Checker Pro adds vital features that allow comprehensive accessibility audits to be run within your WordPress dashboard.\nFeatures include:</p>\n<ul>\n<li>Full site scanning</li>\n<li>Ignore Log</li>\n<li>Bulk Ignore</li>\n<li>User restrictions on ignore</li>\n<li>Centralized list of all open issues</li>\n<li>Admin columns</li>\n<li>...and more</li>\n</ul>\n<p>Please note: Accessibility Checker Pro requires an active license to function. For a full list of features or to purchase a license, visit the\n<a href="https://my.equalizedigital.com">Accessibility Checker Pro website</a>.</p>";s:12:"installation";s:1312:"<p>Getting started with Accessibility Checker Pro is as easy as installing and activating the plugin, then configuring a few basic settings.</p>\n<h3>Installing Accessibility Checker Pro Within WordPress</h3>\n<ol>\n<li>Visit the plugins page within your dashboard and select ‘Add New’.</li>\n<li>On the Add Plugins screen, click the "Upload Plugin" button.</li>\n<li>Upload the zipped plugin file from your download link.</li>\n<li>Activate Accessibility Checker Pro from your Plugins page.</li>\n<li>Follow the ‘after activation’ steps listed below.</li>\n</ol>\n<h3>Installing Accessibility Checker Pro Manually</h3>\n<p>1.Upload the unzipped ‘accessibility-checker’ folder to the /wp-content/plugins/ directory on your website via FTP.\n2. Activate Accessibility Checker Pro from your Plugins page.\n3. Follow the ‘after activation’ steps listed below.</p>\n<h3>After Activation</h3>\n<ol>\n<li>If you do not have Accessibility Checker Free installed and active, Accessibility Checker Pro will prompt you to install and activate it. Follow the prompts to install Accessibility Checker.</li>\n<li>After activating the plugin, go to the Accessibility Checker settings page in your WordPress admin (found at \'/wp-admin/admin.php?page=accessibility_checker_settings\') to configure the\nplugin settings.</li>\n</ol>";s:9:"changelog";s:11843:"<h4> 1.20.0 </h4>\n<ul>\n<li>Fixed: sorting order on open issues tab is now by severity and count by default.</li>\n<li>Improved: fast track better shows that several of the same issue can exist on one page now.</li>\n</ul>\n<h4> 1.19.0 </h4>\n<ul>\n<li>Add: Sorting indicators to rule table headers.</li>\n<li>Improved: Times now use a UTC helper function to ensure consistency across timezones.</li>\n<li>Tweaked: Set sslverify to true for license requests.</li>\n<li>Tweaked: Improved license messages and handling based on user capabilities.</li>\n</ul>\n<h4> 1.18.0 </h4>\n<ul>\n<li>New: Added a WP-CLI command to do license activations and deactivations for sites that use WP-CLI.</li>\n</ul>\n<h4> 1.17.0 </h4>\n<ul>\n<li>Updated: Changed some icon file names to avoid spaces in file names.</li>\n<li>Improved: Added additional security hardening when processing data passed in.</li>\n</ul>\n<h4> 1.16.0 </h4>\n<ul>\n<li>New: Archive scanning capability in full site scanner.</li>\n<li>New: Can now scan Post Type Archives.</li>\n<li>New: Can now scan Taxonomy Term Archives.</li>\n<li>Updated: Increased the scan posts cache time default from 5 min to 20 minutes.</li>\n</ul>\n<h4> 1.15.0 </h4>\n<ul>\n<li>New: Ability to filter post status that is scanned in full site scanner.</li>\n<li>New: Improved licence key entering by including form on the plugins page.</li>\n<li>Fixed: Resolved issue that blocked pausing or stopping the full site scan and restarting it immediately.</li>\n<li>Fixed: Prevent php warning when pagination isn\'t possible on the log page.</li>\n<li>Improved: Removed some unneeded settings for password protection (htaccess password is no longer a blocker for the scanner).</li>\n</ul>\n<h4> 1.14.0 </h4>\n<ul>\n<li>New: Improved rule descriptions and metadata.</li>\n<li>New: Landmark selector added to issues in tables</li>\n<li>Added: Primary key added to global ignores table for better indexing</li>\n</ul>\n<h4> 1.13.0 </h4>\n<ul>\n<li>Improved: translation issues with some JS strings</li>\n<li>Improved: updated readme with security bug reporting information</li>\n</ul>\n<h4> 1.12.0 </h4>\n<ul>\n<li>Removed: unused action hooks and related functions</li>\n<li>Fixed: untranslatable text</li>\n<li>Added: translation files</li>\n<li>Updated: EDAC_ANWW_ACTIVE checks with ANWW_VERSION definition</li>\n</ul>\n<h4> 1.11.1 </h4>\n<ul>\n<li>Fixed: updated call to remove str_get_html function with new edac_parse_html_for_media function.</li>\n</ul>\n<h4> 1.11.0 </h4>\n<ul>\n<li>New: Ability to filter by post status on the open issues page.</li>\n<li>Improved: Swapped to more accurate scan rules that check the page more reliably.</li>\n<li>Improved: Removed the need to run the first stage of the full site scan - this speeds up a full site scan by a large amount.</li>\n</ul>\n<h4> 1.10.1 </h4>\n<ul>\n<li>Fixed: Handle notices better from the plugin.</li>\n</ul>\n<h4> 1.10.0 </h4>\n<ul>\n<li>Improved: Full site scan performance for very large sites with lots of metadata</li>\n<li>Improved: Add message for when fixes are changed in the open issues modal</li>\n<li>Fixed: Use a more loose regex to detect file links for file size and type fix</li>\n</ul>\n<h4> 1.9.1 </h4>\n<ul>\n<li>Fixed: Issue with the ignore permission role handling</li>\n<li>Fixed: Potential error when metadata was retrieved early</li>\n</ul>\n<h4> 1.9.0 </h4>\n<ul>\n<li>New: Intorduced a new \'fixes\' system to help solve issues that the scanner detects.</li>\n<li>New: Fix to ensure empty or missing  elements get added to the document.</li>\n<li>New: Fix to block users from uploading pdf files without permission</li>\n<li>New: Fix to add file size and type to file links</li>\n<li>New: Fix to add missing form labels to form elements where they can be generated.</li>\n<li>Improved: Added better aria labeling in some locations.</li>\n</ul>\n<h4> 1.8.2 </h4>\n<ul>\n<li>Fixed: Don\'t reference button by color and instead reference by text.</li>\n</ul>\n<h4> 1.8.1 </h4>\n<ul>\n<li>Fixed: Namespaced updater class could result in fatal error in some situations.</li>\n</ul>\n<h4> 1.8.0 </h4>\n<ul>\n<li>Enhancement: Performance improvements to full site scan - large sites will see big speed improvements</li>\n<li>Enhancement: Add a fail timeout in full site scan to prevent scan blocking on pages that error</li>\n<li>Added: Surface pages that fail to scan in the full site scan</li>\n<li>Improved: Accessibility of select label on open issues page</li>\n<li>Improved: Accessibility of labels for fast track documentation links</li>\n<li>Improved: Accessibility of view pages and review issues buttons</li>\n<li>Fixed: Prevent php warning when there is no pages to paginate on log page</li>\n<li>Fixed: Resolved escaped html in the ignore text output</li>\n<li>Fixed: Allow bulk ignores to handle very large batches of ignores with alt query</li>\n</ul>\n<h4> 1.7.0 </h4>\n<ul>\n<li>Updated: Tested up to WP 6.5.2</li>\n<li>Updated: logic on asset loading</li>\n<li>Added: full site scan speed setting</li>\n<li>Fixed: full site scan API alert showing when no post types are selected</li>\n</ul>\n<h4> 1.6.0 </h4>\n<ul>\n<li>Added: scan_start, scan_reset and scan_progress WP Rest API calls to replace admin-ajax calls</li>\n<li>Added: start-new-scan rest call</li>\n<li>Moved: <code>edacp_scan_start</code> from accessibility-checker-pro to <code>EDACP\\Scans::start_php_scan</code></li>\n<li>Updated: <code>activation.php</code> to use <code>EDACP\\Scans::start_php_scan</code></li>\n<li>Deleted: CSS for log from full site scan page</li>\n<li>Moved: <code>getScanStats</code> code from <code>/src/fullSiteScanApp/checkPages.js</code> to <code>/src/fullSiteScanApp/fullSiteScanUI.js</code></li>\n<li>Deleted: jquery from <code>/src/fullSiteScanApp/fullSiteScanUI.js</code></li>\n<li>Added: a page reload every ten minutes to full site scan a page</li>\n<li>Deleted: setting authorization header in rest calls</li>\n<li>Fixed:  mismatched number of URLs scanned</li>\n<li>Fixed: type in global ignore title</li>\n<li>Fixed: pluralization of full site summary stats</li>\n</ul>\n<h4> 1.5.2 </h4>\n<ul>\n<li>Added: Audit History 1.0.0 and 1.0.1 update fix</li>\n<li>Fixed: variable casting</li>\n</ul>\n<h4> 1.5.1 </h4>\n<ul>\n<li>Fixed: open issues descriptions output</li>\n</ul>\n<h4> 1.5.0 </h4>\n<ul>\n<li>Fixed: Issues with JavaScript assets not loading</li>\n<li>Updated: Full-site scan now supports JavaScript scanning</li>\n<li>Added: \'Stop\' button for full-site scanning</li>\n<li>Updated: Posts to scan function optimized for paging and using only IDs</li>\n<li>Removed: \'accessibility_checker_logs\' database table</li>\n<li>Added: Code improvements in the database update function</li>\n<li>Removed: Full site scan log to enhance performance</li>\n<li>Removed: Background scan schedule to align with new full site scanning</li>\n<li>Updated: Full site scan completion message updated to reflect log removal</li>\n</ul>\n<h4> 1.4.3 </h4>\n<ul>\n<li>Updated: version and readme</li>\n</ul>\n<h4> 1.4.2 </h4>\n<ul>\n<li>Updated: readme</li>\n</ul>\n<h4> 1.4.1 </h4>\n<ul>\n<li>Fixed: delete all data on uninstall option</li>\n<li>Fixed: misnamed authorization options and added migration function</li>\n<li>Update: password protection to pass authorization to wp-cron</li>\n<li>Fixed: expired license notice after key renews</li>\n<li>Added: image column to individual open issues and fast track</li>\n<li>Fixed: incorrect fieldname "objectid" in SQL call when clicking affected code in the table header on the issue log.</li>\n</ul>\n<h4> 1.4.0 </h4>\n<ul>\n<li>Fixed: adherence to coding standards</li>\n<li>Fixed: full-site scan stop button issue</li>\n<li>Fixed: settings page tab order</li>\n<li>Fixed: full-site scan error when no custom post types are configured for scanning in settings</li>\n<li>Fixed: activation issue when no custom post types are designated for scanning in settings</li>\n<li>Added: warnings when no custom post types are configured for scanning in settings</li>\n<li>Updated: full-site scan completion date now uses site\'s localized timezone</li>\n<li>Updated: refresh and caching for reports dashboard widget and welcome page</li>\n</ul>\n<h4> 1.3.1 </h4>\n<ul>\n<li>Fixed - scan log output</li>\n<li>Fixed - ignore log not filtering by issue</li>\n</ul>\n<h4> 1.3.0 </h4>\n<ul>\n<li>Added: plugin architecture for converting PHP checks to JavaScript</li>\n<li>Added: JavaScript scanning for color contrast check</li>\n<li>Updated: full-site scan with a secondary JavaScript pass</li>\n<li>Updated: full-site scan log output for better performance</li>\n<li>Added: full-site scan stop button</li>\n<li>Updated: open issues table with accessibility improvements</li>\n<li>Added: frontend highlighting view on-page links</li>\n</ul>\n<h4> 1.2.9 </h4>\n<ul>\n<li>Fixed: activation issue with the valid table name function and the dependency installer</li>\n</ul>\n<h4> 1.2.8 </h4>\n<ul>\n<li>Fixed: issue with zip file name</li>\n</ul>\n<h4> 1.2.7 </h4>\n<ul>\n<li>Added: filterable query limit to the full site scan log</li>\n<li>Updated: full site scan to only run if a custom post type is selected in the settings</li>\n<li>Updated: full site scan to delete data for post types no longer selected in the settings</li>\n<li>Fixed: bug with global ignores being added to all individually ignored issue count</li>\n<li>Fixed: usort deprecated notice on ignore log</li>\n</ul>\n<h4> 1.2.6 </h4>\n<ul>\n<li>Fixed: open issues with no errors to show as passed</li>\n<li>Updated: Action Scheduler to latest version</li>\n<li>Update: Action Scheduler to load via Composer</li>\n</ul>\n<h4> 1.2.5 </h4>\n<ul>\n<li>Fixed: post type count on full size scan</li>\n</ul>\n<h4> 1.2.4 </h4>\n<ul>\n<li>Updated: admin notice output</li>\n</ul>\n<h4> 1.2.3 </h4>\n<ul>\n<li>Added: license tab</li>\n<li>Updated: license check to run via cronjob</li>\n<li>Updated: EDD license class</li>\n</ul>\n<h4> 1.2.2 </h4>\n<ul>\n<li>Added: security updates</li>\n</ul>\n<h4> 1.2.1 </h4>\n<ul>\n<li>Added: Support for the Restricted Access Plugin</li>\n<li>Added: Password protection settings</li>\n</ul>\n<h4> 1.2.0 </h4>\n<ul>\n<li>Update: Heading order on Open Issues, Fast Track, Ignore Log and Global Ignores pages</li>\n<li>Added: Initial rule list page ordered by count to the Open Issues and Ignore Log pages</li>\n<li>Added: Individual rule pages with count, issue summary and rule select to quickly switched between issues to the Open Issues and Ignore Log pages</li>\n<li>Added: Custom Post Type select to Fast Track to reduce query load and improve performance</li>\n</ul>\n<h4> 1.1.9 </h4>\n<ul>\n<li>Update dependency installer to latest version fixing dismiss-notice.js 404</li>\n</ul>\n<h4> 1.1.8 </h4>\n<ul>\n<li>Update log filter admin url</li>\n</ul>\n<h4> 1.1.7 </h4>\n<ul>\n<li>Show Open Issues and Ignore Log admin pages to users with ignore permissions</li>\n</ul>\n<h4> 1.1.6 </h4>\n<ul>\n<li>Add support for PHP 8</li>\n</ul>\n<h4> 1.1.5 </h4>\n<ul>\n<li>Move accessibility statement free plugin</li>\n</ul>\n<h4> 1.1.4 </h4>\n<ul>\n<li>Update license domain and product name</li>\n</ul>\n<h4> 1.1.3 </h4>\n<ul>\n<li>Improvements to license activation/deactivation settings</li>\n</ul>\n<h4> 1.1.2 </h4>\n<ul>\n<li>Add support for Accessibility New Window Warning Plugin</li>\n<li>Plugin dependency installer</li>\n</ul>\n<h4> 1.1.1 </h4>\n<ul>\n<li>Fix to allow ignores database to be deleted on uninstall</li>\n</ul>\n<h4> 1.1.0 </h4>\n<ul>\n<li>Fast Track</li>\n</ul>\n<h4> 1.0.3 </h4>\n<ul>\n<li>Updates to database creation/updates</li>\n<li>Updates to plugin updater</li>\n<li>Deprecated jQuery fixes</li>\n</ul>\n<h4> 1.0.2 </h4>\n<ul>\n<li>Full site scan and background scan</li>\n</ul>\n<h4> 1.0.1 </h4>\n<ul>\n<li>Removed content hook</li>\n<li>Fixed issue with log search if post type has been Removed</li>\n<li>Fixed duplicate column names in screen options</li>\n</ul>\n<h4> 1.0.0 </h4>\n<ul>\n<li>Everything is new and shiny.</li>\n<li>We think it\'s awesome you want to make your website more accessible.</li>\n<li>Thank you for purchasing Accessibility Checker Pro.</li>\n</ul>";s:3:"faq";s:1768:"<h4>What support is included?</h4>\n<p>Equalize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and\ntroubleshooting assistance. You may <a href="https://my.equalizedigital.com/support/pro-support/">open a support ticket</a> at any time. Plugin support is limited to\nproviding assistance in using the plugin but does not include support resolving any specific accessibility issues that have been identified.</p>\n<h4>Can you help me figure out how to fix an error or warning on my website?</h4>\n<p>If you have questions about specific errors and warnings on your website or need help fixing problems, we offer <a href="https://my.equalizedigital.com/priority-support/">priority support packages</a>\nthat include full (phone and email) access to our accessibility specialists and developers. If you need more in-depth auditing, user testing, and remediation, or would like to\nget your website certified as accessible, <a href="https://equalizedigital.com/">we can help with that too</a>.</p>\n<h4>Do I lose functionality if my license key is not active?</h4>\n<p>To utilize Accessibility Checker Pro features, receive plugin updates, and support, you do need to have an active license key. If your license key has expired, you can\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.</p>\n<h4>How can I report security bugs?</h4>\n<p>You can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. <a href="https://patchstack.com/database/vdp/9e5fbe42-43e5-4644-89f5-04340fd263a4">Report a security vulnerability.</a></p>\n";}s:13:"license_check";s:0:"";s:3:"msg";s:0:"";s:8:"homepage";s:23:"https://a11ychecker.com";s:7:"package";s:219:"https://my.equalizedigital.com/edd-sl/package_download/MTc3MjI0ODA2Nzo1OGJiYTIwY2Q2ZTUyYTQ0YWNhMGJmOTQwNmRlNDczYzoyNDo5ZGM2OWZhYTZhY2RjOGFiZjdjNjRjNWI3MGY5NmQ1YzpodHRwc0AvL2JlcmtoYW1jb3Vucy53cGVuZ2luZXBvd2VyZWQuY29tOjA=";s:5:"icons";a:0:{}s:7:"banners";O:8:"stdClass":2:{s:4:"high";s:93:"https://my.equalizedigital.com/wp-content/uploads/sites/4/edd/2020/12/plugin-banner-large.png";s:3:"low";s:93:"https://my.equalizedigital.com/wp-content/uploads/sites/4/edd/2020/12/plugin-banner-small.png";}s:4:"slug";s:25:"accessibility-checker-pro";s:3:"url";s:79:"https://my.equalizedigital.com/downloads/accessibility-checker-pro/?changelog=1";s:12:"last_updated";s:19:"2026-02-13 18:11:25";s:13:"download_link";s:219:"https://my.equalizedigital.com/edd-sl/package_download/MTc3MjI0ODA2Nzo1OGJiYTIwY2Q2ZTUyYTQ0YWNhMGJmOTQwNmRlNDczYzoyNDo5ZGM2OWZhYTZhY2RjOGFiZjdjNjRjNWI3MGY5NmQ1YzpodHRwc0AvL2JlcmtoYW1jb3Vucy53cGVuZ2luZXBvd2VyZWQuY29tOjA=";s:4:"tags";a:5:{i:0;s:13:"accessibility";i:1;s:10:"accessible";i:2;s:4:"wcag";i:3;s:3:"ada";i:4;s:4:"a11y";}s:8:"requires";s:3:"6.2";s:6:"tested";s:3:"6.8";s:12:"requires_php";s:0:"";s:12:"contributors";O:8:"stdClass":3:{s:15:"equalizedigital";O:8:"stdClass":3:{s:12:"display_name";s:15:"equalizedigital";s:7:"profile";s:40:"//profiles.wordpress.org/equalizedigital";s:6:"avatar";s:60:"https://wordpress.org/grav-redirect.php?user=equalizedigital";}s:7:"alh0319";O:8:"stdClass":3:{s:12:"display_name";s:7:"alh0319";s:7:"profile";s:32:"//profiles.wordpress.org/alh0319";s:6:"avatar";s:52:"https://wordpress.org/grav-redirect.php?user=alh0319";}s:13:"stevejonesdev";O:8:"stdClass":3:{s:12:"display_name";s:13:"stevejonesdev";s:7:"profile";s:38:"//profiles.wordpress.org/stevejonesdev";s:6:"avatar";s:58:"https://wordpress.org/grav-redirect.php?user=stevejonesdev";}}s:10:"stable_tag";s:6:"1.20.0";s:11:"donate_link";s:0:"";s:17:"short_description";s:95:"This plugin adds pro features to the Acessibility Checker plugin, including full site scanning.";s:7:"license";s:14:"GPLv2 or later";s:14:"upgrade_notice";s:0:"";s:11:"screenshots";a:0:{}s:3:"faq";a:1:{i:0;s:1768:"<h4>What support is included?</h4>\n<p>Equalize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and\ntroubleshooting assistance. You may <a href="https://my.equalizedigital.com/support/pro-support/">open a support ticket</a> at any time. Plugin support is limited to\nproviding assistance in using the plugin but does not include support resolving any specific accessibility issues that have been identified.</p>\n<h4>Can you help me figure out how to fix an error or warning on my website?</h4>\n<p>If you have questions about specific errors and warnings on your website or need help fixing problems, we offer <a href="https://my.equalizedigital.com/priority-support/">priority support packages</a>\nthat include full (phone and email) access to our accessibility specialists and developers. If you need more in-depth auditing, user testing, and remediation, or would like to\nget your website certified as accessible, <a href="https://equalizedigital.com/">we can help with that too</a>.</p>\n<h4>Do I lose functionality if my license key is not active?</h4>\n<p>To utilize Accessibility Checker Pro features, receive plugin updates, and support, you do need to have an active license key. If your license key has expired, you can\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.</p>\n<h4>How can I report security bugs?</h4>\n<p>You can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. <a href="https://patchstack.com/database/vdp/9e5fbe42-43e5-4644-89f5-04340fd263a4">Report a security vulnerability.</a></p>\n";}s:8:"warnings";O:8:"stdClass":1:{s:13:"too_many_tags";a:4:{i:0;s:11:"section 508";i:1;s:5:"audit";i:2;s:11:"readability";i:3;s:16:"content analysis";}}s:17:"expected_sections";a:7:{i:0;s:11:"description";i:1;s:12:"installation";i:2;s:3:"faq";i:3;s:11:"screenshots";i:4;s:9:"changelog";i:5;s:14:"upgrade_notice";i:6;s:11:"other_notes";}s:14:"alias_sections";O:8:"stdClass":3:{s:26:"frequently_asked_questions";s:3:"faq";s:10:"change_log";s:9:"changelog";s:10:"screenshot";s:11:"screenshots";}s:13:"valid_headers";O:8:"stdClass":11:{s:6:"tested";s:6:"tested";s:12:"tested up to";s:6:"tested";s:8:"requires";s:8:"requires";s:17:"requires at least";s:8:"requires";s:12:"requires php";s:12:"requires_php";s:4:"tags";s:4:"tags";s:12:"contributors";s:12:"contributors";s:11:"donate link";s:11:"donate_link";s:10:"stable tag";s:10:"stable_tag";s:7:"license";s:7:"license";s:11:"license uri";s:11:"license_uri";}s:11:"ignore_tags";a:2:{i:0;s:6:"plugin";i:1;s:9:"wordpress";}s:21:"maximum_field_lengths";O:8:"stdClass":4:{s:17:"short_description";i:150;s:7:"section";i:2500;s:17:"section-changelog";i:5000;s:11:"section-faq";i:5000;}s:12:"raw_contents";s:13885:"=== Accessibility Checker Pro ===\nContributors: equalizedigital, alh0319, stevejonesdev\nTags: accessibility, accessible, wcag, ada, a11y, section 508, audit, readability, content analysis\nRequires at least: 6.2\nTested up to: 6.8\nStable tag: 1.20.0\nLicense: GPLv2 or later\nLicense URI: http://www.gnu.org/licenses/gpl-2.0.html\n\n\nThis plugin adds pro features to the Acessibility Checker plugin, including full site scanning.\n\n== Description ==\n\nAccessibility Check Pro is a premium plugin that expands the free Accessibility Checker available in the WordPress.org plugin directory.\nAccessibility Checker Pro adds vital features that allow comprehensive accessibility audits to be run within your WordPress dashboard.\nFeatures include:\n\n* Full site scanning\n* Ignore Log\n* Bulk Ignore\n* User restrictions on ignore\n* Centralized list of all open issues\n* Admin columns\n* ...and more\n\nPlease note: Accessibility Checker Pro requires an active license to function. For a full list of features or to purchase a license, visit the\n[Accessibility Checker Pro website](https://my.equalizedigital.com).\n\n== Installation ==\nGetting started with Accessibility Checker Pro is as easy as installing and activating the plugin, then configuring a few basic settings.\n\n### Installing Accessibility Checker Pro Within WordPress\n1. Visit the plugins page within your dashboard and select ‘Add New’.\n2. On the Add Plugins screen, click the "Upload Plugin" button.\n3. Upload the zipped plugin file from your download link.\n4. Activate Accessibility Checker Pro from your Plugins page.\n5. Follow the ‘after activation’ steps listed below.\n\n### Installing Accessibility Checker Pro Manually\n\n1.Upload the unzipped ‘accessibility-checker’ folder to the /wp-content/plugins/ directory on your website via FTP.\n2. Activate Accessibility Checker Pro from your Plugins page.\n3. Follow the ‘after activation’ steps listed below.\n\n### After Activation\n1. If you do not have Accessibility Checker Free installed and active, Accessibility Checker Pro will prompt you to install and activate it. Follow the prompts to install Accessibility Checker.\n2. After activating the plugin, go to the Accessibility Checker settings page in your WordPress admin (found at \'/wp-admin/admin.php?page=accessibility_checker_settings\') to configure the\nplugin settings.\n\n== Frequently Asked Questions ==\n\n= What support is included? =\n\nEqualize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and\ntroubleshooting assistance. You may [open a support ticket](https://my.equalizedigital.com/support/pro-support/) at any time. Plugin support is limited to\nproviding assistance in using the plugin but does not include support resolving any specific accessibility issues that have been identified.\n\n= Can you help me figure out how to fix an error or warning on my website? =\n\nIf you have questions about specific errors and warnings on your website or need help fixing problems, we offer [priority support packages](https://my.equalizedigital.com/priority-support/)\nthat include full (phone and email) access to our accessibility specialists and developers. If you need more in-depth auditing, user testing, and remediation, or would like to\nget your website certified as accessible, [we can help with that too](https://equalizedigital.com/).\n\n= Do I lose functionality if my license key is not active? =\n\nTo utilize Accessibility Checker Pro features, receive plugin updates, and support, you do need to have an active license key. If your license key has expired, you can\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.\n\n= How can I report security bugs? =\n\nYou can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. [Report a security vulnerability.](https://patchstack.com/database/vdp/9e5fbe42-43e5-4644-89f5-04340fd263a4)\n\n== Changelog ==\n\n= 1.20.0 =\n* Fixed: sorting order on open issues tab is now by severity and count by default.\n* Improved: fast track better shows that several of the same issue can exist on one page now.\n\n= 1.19.0 =\n* Add: Sorting indicators to rule table headers.\n* Improved: Times now use a UTC helper function to ensure consistency across timezones.\n* Tweaked: Set sslverify to true for license requests.\n* Tweaked: Improved license messages and handling based on user capabilities.\n\n= 1.18.0 =\n* New: Added a WP-CLI command to do license activations and deactivations for sites that use WP-CLI.\n\n= 1.17.0 =\n* Updated: Changed some icon file names to avoid spaces in file names.\n* Improved: Added additional security hardening when processing data passed in.\n\n= 1.16.0 =\n* New: Archive scanning capability in full site scanner.\n* New: Can now scan Post Type Archives.\n* New: Can now scan Taxonomy Term Archives.\n* Updated: Increased the scan posts cache time default from 5 min to 20 minutes.\n\n= 1.15.0 =\n* New: Ability to filter post status that is scanned in full site scanner.\n* New: Improved licence key entering by including form on the plugins page.\n* Fixed: Resolved issue that blocked pausing or stopping the full site scan and restarting it immediately.\n* Fixed: Prevent php warning when pagination isn\'t possible on the log page.\n* Improved: Removed some unneeded settings for password protection (htaccess password is no longer a blocker for the scanner).\n\n= 1.14.0 =\n* New: Improved rule descriptions and metadata.\n* New: Landmark selector added to issues in tables\n* Added: Primary key added to global ignores table for better indexing\n\n= 1.13.0 =\n* Improved: translation issues with some JS strings\n* Improved: updated readme with security bug reporting information\n\n= 1.12.0 =\n* Removed: unused action hooks and related functions\n* Fixed: untranslatable text\n* Added: translation files\n* Updated: EDAC_ANWW_ACTIVE checks with ANWW_VERSION definition\n\n= 1.11.1 =\n* Fixed: updated call to remove str_get_html function with new edac_parse_html_for_media function.\n\n= 1.11.0 =\n* New: Ability to filter by post status on the open issues page.\n* Improved: Swapped to more accurate scan rules that check the page more reliably.\n* Improved: Removed the need to run the first stage of the full site scan - this speeds up a full site scan by a large amount.\n\n= 1.10.1 =\n* Fixed: Handle notices better from the plugin.\n\n= 1.10.0 =\n* Improved: Full site scan performance for very large sites with lots of metadata\n* Improved: Add message for when fixes are changed in the open issues modal\n* Fixed: Use a more loose regex to detect file links for file size and type fix\n\n= 1.9.1 =\n* Fixed: Issue with the ignore permission role handling\n* Fixed: Potential error when metadata was retrieved early\n\n= 1.9.0 =\n* New: Intorduced a new \'fixes\' system to help solve issues that the scanner detects.\n* New: Fix to ensure empty or missing <title> elements get added to the document.\n* New: Fix to block users from uploading pdf files without permission\n* New: Fix to add file size and type to file links\n* New: Fix to add missing form labels to form elements where they can be generated.\n* Improved: Added better aria labeling in some locations.\n\n= 1.8.2 =\n* Fixed: Don\'t reference button by color and instead reference by text.\n\n= 1.8.1 =\n* Fixed: Namespaced updater class could result in fatal error in some situations.\n\n= 1.8.0 =\n* Enhancement: Performance improvements to full site scan - large sites will see big speed improvements\n* Enhancement: Add a fail timeout in full site scan to prevent scan blocking on pages that error\n* Added: Surface pages that fail to scan in the full site scan\n* Improved: Accessibility of select label on open issues page\n* Improved: Accessibility of labels for fast track documentation links\n* Improved: Accessibility of view pages and review issues buttons\n* Fixed: Prevent php warning when there is no pages to paginate on log page\n* Fixed: Resolved escaped html in the ignore text output\n* Fixed: Allow bulk ignores to handle very large batches of ignores with alt query\n\n= 1.7.0 =\n* Updated: Tested up to WP 6.5.2\n* Updated: logic on asset loading\n* Added: full site scan speed setting\n* Fixed: full site scan API alert showing when no post types are selected\n\n= 1.6.0 =\n* Added: scan_start, scan_reset and scan_progress WP Rest API calls to replace admin-ajax calls\n* Added: start-new-scan rest call\n* Moved: `edacp_scan_start` from accessibility-checker-pro to `EDACP\\Scans::start_php_scan`\n* Updated: `activation.php` to use `EDACP\\Scans::start_php_scan`\n* Deleted: CSS for log from full site scan page\n* Moved: `getScanStats` code from `/src/fullSiteScanApp/checkPages.js` to `/src/fullSiteScanApp/fullSiteScanUI.js`\n* Deleted: jquery from `/src/fullSiteScanApp/fullSiteScanUI.js`\n* Added: a page reload every ten minutes to full site scan a page\n* Deleted: setting authorization header in rest calls\n* Fixed:  mismatched number of URLs scanned\n* Fixed: type in global ignore title\n* Fixed: pluralization of full site summary stats\n\n= 1.5.2 =\n* Added: Audit History 1.0.0 and 1.0.1 update fix\n* Fixed: variable casting\n\n= 1.5.1 =\n* Fixed: open issues descriptions output\n\n= 1.5.0 =\n* Fixed: Issues with JavaScript assets not loading\n* Updated: Full-site scan now supports JavaScript scanning\n* Added: \'Stop\' button for full-site scanning\n* Updated: Posts to scan function optimized for paging and using only IDs\n* Removed: \'accessibility_checker_logs\' database table\n* Added: Code improvements in the database update function\n* Removed: Full site scan log to enhance performance\n* Removed: Background scan schedule to align with new full site scanning\n* Updated: Full site scan completion message updated to reflect log removal\n\n= 1.4.3 =\n* Updated: version and readme\n\n= 1.4.2 =\n* Updated: readme\n\n= 1.4.1 =\n* Fixed: delete all data on uninstall option\n* Fixed: misnamed authorization options and added migration function\n* Update: password protection to pass authorization to wp-cron\n* Fixed: expired license notice after key renews\n* Added: image column to individual open issues and fast track\n* Fixed: incorrect fieldname "objectid" in SQL call when clicking affected code in the table header on the issue log.\n\n= 1.4.0 =\n* Fixed: adherence to coding standards\n* Fixed: full-site scan stop button issue\n* Fixed: settings page tab order\n* Fixed: full-site scan error when no custom post types are configured for scanning in settings\n* Fixed: activation issue when no custom post types are designated for scanning in settings\n* Added: warnings when no custom post types are configured for scanning in settings\n* Updated: full-site scan completion date now uses site\'s localized timezone\n* Updated: refresh and caching for reports dashboard widget and welcome page\n\n= 1.3.1 =\n* Fixed - scan log output\n* Fixed - ignore log not filtering by issue\n\n= 1.3.0 =\n* Added: plugin architecture for converting PHP checks to JavaScript\n* Added: JavaScript scanning for color contrast check\n* Updated: full-site scan with a secondary JavaScript pass\n* Updated: full-site scan log output for better performance\n* Added: full-site scan stop button\n* Updated: open issues table with accessibility improvements\n* Added: frontend highlighting view on-page links\n\n= 1.2.9 =\n* Fixed: activation issue with the valid table name function and the dependency installer\n\n= 1.2.8 =\n* Fixed: issue with zip file name\n\n= 1.2.7 =\n* Added: filterable query limit to the full site scan log\n* Updated: full site scan to only run if a custom post type is selected in the settings\n* Updated: full site scan to delete data for post types no longer selected in the settings\n* Fixed: bug with global ignores being added to all individually ignored issue count\n* Fixed: usort deprecated notice on ignore log\n\n= 1.2.6 =\n* Fixed: open issues with no errors to show as passed\n* Updated: Action Scheduler to latest version\n* Update: Action Scheduler to load via Composer\n\n= 1.2.5 =\n* Fixed: post type count on full size scan\n\n= 1.2.4 =\n* Updated: admin notice output\n\n= 1.2.3 =\n* Added: license tab\n* Updated: license check to run via cronjob\n* Updated: EDD license class\n\n= 1.2.2 =\n* Added: security updates\n\n= 1.2.1 =\n* Added: Support for the Restricted Access Plugin\n* Added: Password protection settings\n\n= 1.2.0 =\n* Update: Heading order on Open Issues, Fast Track, Ignore Log and Global Ignores pages\n* Added: Initial rule list page ordered by count to the Open Issues and Ignore Log pages\n* Added: Individual rule pages with count, issue summary and rule select to quickly switched between issues to the Open Issues and Ignore Log pages\n* Added: Custom Post Type select to Fast Track to reduce query load and improve performance\n\n= 1.1.9 =\n* Update dependency installer to latest version fixing dismiss-notice.js 404\n\n= 1.1.8 =\n* Update log filter admin url\n\n= 1.1.7 =\n* Show Open Issues and Ignore Log admin pages to users with ignore permissions\n\n= 1.1.6 =\n* Add support for PHP 8\n\n= 1.1.5 =\n* Move accessibility statement free plugin\n\n= 1.1.4 =\n* Update license domain and product name\n\n= 1.1.3 =\n* Improvements to license activation/deactivation settings\n\n= 1.1.2 =\n* Add support for Accessibility New Window Warning Plugin\n* Plugin dependency installer\n\n= 1.1.1 =\n* Fix to allow ignores database to be deleted on uninstall\n\n= 1.1.0 =\n* Fast Track\n\n= 1.0.3 =\n* Updates to database creation/updates\n* Updates to plugin updater\n* Deprecated jQuery fixes\n\n= 1.0.2 =\n* Full site scan and background scan\n\n= 1.0.1 =\n* Removed content hook\n* Fixed issue with log search if post type has been Removed\n* Fixed duplicate column names in screen options\n\n= 1.0.0 =\n* Everything is new and shiny.\n* We think it\'s awesome you want to make your website more accessible.\n* Thank you for purchasing Accessibility Checker Pro.\n";s:11:"description";a:1:{i:0;s:732:"<p>Accessibility Check Pro is a premium plugin that expands the free Accessibility Checker available in the WordPress.org plugin directory.\nAccessibility Checker Pro adds vital features that allow comprehensive accessibility audits to be run within your WordPress dashboard.\nFeatures include:</p>\n<ul>\n<li>Full site scanning</li>\n<li>Ignore Log</li>\n<li>Bulk Ignore</li>\n<li>User restrictions on ignore</li>\n<li>Centralized list of all open issues</li>\n<li>Admin columns</li>\n<li>...and more</li>\n</ul>\n<p>Please note: Accessibility Checker Pro requires an active license to function. For a full list of features or to purchase a license, visit the\n<a href="https://my.equalizedigital.com">Accessibility Checker Pro website</a>.</p>";}s:12:"installation";a:1:{i:0;s:1312:"<p>Getting started with Accessibility Checker Pro is as easy as installing and activating the plugin, then configuring a few basic settings.</p>\n<h3>Installing Accessibility Checker Pro Within WordPress</h3>\n<ol>\n<li>Visit the plugins page within your dashboard and select ‘Add New’.</li>\n<li>On the Add Plugins screen, click the "Upload Plugin" button.</li>\n<li>Upload the zipped plugin file from your download link.</li>\n<li>Activate Accessibility Checker Pro from your Plugins page.</li>\n<li>Follow the ‘after activation’ steps listed below.</li>\n</ol>\n<h3>Installing Accessibility Checker Pro Manually</h3>\n<p>1.Upload the unzipped ‘accessibility-checker’ folder to the /wp-content/plugins/ directory on your website via FTP.\n2. Activate Accessibility Checker Pro from your Plugins page.\n3. Follow the ‘after activation’ steps listed below.</p>\n<h3>After Activation</h3>\n<ol>\n<li>If you do not have Accessibility Checker Free installed and active, Accessibility Checker Pro will prompt you to install and activate it. Follow the prompts to install Accessibility Checker.</li>\n<li>After activating the plugin, go to the Accessibility Checker settings page in your WordPress admin (found at \'/wp-admin/admin.php?page=accessibility_checker_settings\') to configure the\nplugin settings.</li>\n</ol>";}s:9:"changelog";a:1:{i:0;s:11843:"<h4> 1.20.0 </h4>\n<ul>\n<li>Fixed: sorting order on open issues tab is now by severity and count by default.</li>\n<li>Improved: fast track better shows that several of the same issue can exist on one page now.</li>\n</ul>\n<h4> 1.19.0 </h4>\n<ul>\n<li>Add: Sorting indicators to rule table headers.</li>\n<li>Improved: Times now use a UTC helper function to ensure consistency across timezones.</li>\n<li>Tweaked: Set sslverify to true for license requests.</li>\n<li>Tweaked: Improved license messages and handling based on user capabilities.</li>\n</ul>\n<h4> 1.18.0 </h4>\n<ul>\n<li>New: Added a WP-CLI command to do license activations and deactivations for sites that use WP-CLI.</li>\n</ul>\n<h4> 1.17.0 </h4>\n<ul>\n<li>Updated: Changed some icon file names to avoid spaces in file names.</li>\n<li>Improved: Added additional security hardening when processing data passed in.</li>\n</ul>\n<h4> 1.16.0 </h4>\n<ul>\n<li>New: Archive scanning capability in full site scanner.</li>\n<li>New: Can now scan Post Type Archives.</li>\n<li>New: Can now scan Taxonomy Term Archives.</li>\n<li>Updated: Increased the scan posts cache time default from 5 min to 20 minutes.</li>\n</ul>\n<h4> 1.15.0 </h4>\n<ul>\n<li>New: Ability to filter post status that is scanned in full site scanner.</li>\n<li>New: Improved licence key entering by including form on the plugins page.</li>\n<li>Fixed: Resolved issue that blocked pausing or stopping the full site scan and restarting it immediately.</li>\n<li>Fixed: Prevent php warning when pagination isn\'t possible on the log page.</li>\n<li>Improved: Removed some unneeded settings for password protection (htaccess password is no longer a blocker for the scanner).</li>\n</ul>\n<h4> 1.14.0 </h4>\n<ul>\n<li>New: Improved rule descriptions and metadata.</li>\n<li>New: Landmark selector added to issues in tables</li>\n<li>Added: Primary key added to global ignores table for better indexing</li>\n</ul>\n<h4> 1.13.0 </h4>\n<ul>\n<li>Improved: translation issues with some JS strings</li>\n<li>Improved: updated readme with security bug reporting information</li>\n</ul>\n<h4> 1.12.0 </h4>\n<ul>\n<li>Removed: unused action hooks and related functions</li>\n<li>Fixed: untranslatable text</li>\n<li>Added: translation files</li>\n<li>Updated: EDAC_ANWW_ACTIVE checks with ANWW_VERSION definition</li>\n</ul>\n<h4> 1.11.1 </h4>\n<ul>\n<li>Fixed: updated call to remove str_get_html function with new edac_parse_html_for_media function.</li>\n</ul>\n<h4> 1.11.0 </h4>\n<ul>\n<li>New: Ability to filter by post status on the open issues page.</li>\n<li>Improved: Swapped to more accurate scan rules that check the page more reliably.</li>\n<li>Improved: Removed the need to run the first stage of the full site scan - this speeds up a full site scan by a large amount.</li>\n</ul>\n<h4> 1.10.1 </h4>\n<ul>\n<li>Fixed: Handle notices better from the plugin.</li>\n</ul>\n<h4> 1.10.0 </h4>\n<ul>\n<li>Improved: Full site scan performance for very large sites with lots of metadata</li>\n<li>Improved: Add message for when fixes are changed in the open issues modal</li>\n<li>Fixed: Use a more loose regex to detect file links for file size and type fix</li>\n</ul>\n<h4> 1.9.1 </h4>\n<ul>\n<li>Fixed: Issue with the ignore permission role handling</li>\n<li>Fixed: Potential error when metadata was retrieved early</li>\n</ul>\n<h4> 1.9.0 </h4>\n<ul>\n<li>New: Intorduced a new \'fixes\' system to help solve issues that the scanner detects.</li>\n<li>New: Fix to ensure empty or missing  elements get added to the document.</li>\n<li>New: Fix to block users from uploading pdf files without permission</li>\n<li>New: Fix to add file size and type to file links</li>\n<li>New: Fix to add missing form labels to form elements where they can be generated.</li>\n<li>Improved: Added better aria labeling in some locations.</li>\n</ul>\n<h4> 1.8.2 </h4>\n<ul>\n<li>Fixed: Don\'t reference button by color and instead reference by text.</li>\n</ul>\n<h4> 1.8.1 </h4>\n<ul>\n<li>Fixed: Namespaced updater class could result in fatal error in some situations.</li>\n</ul>\n<h4> 1.8.0 </h4>\n<ul>\n<li>Enhancement: Performance improvements to full site scan - large sites will see big speed improvements</li>\n<li>Enhancement: Add a fail timeout in full site scan to prevent scan blocking on pages that error</li>\n<li>Added: Surface pages that fail to scan in the full site scan</li>\n<li>Improved: Accessibility of select label on open issues page</li>\n<li>Improved: Accessibility of labels for fast track documentation links</li>\n<li>Improved: Accessibility of view pages and review issues buttons</li>\n<li>Fixed: Prevent php warning when there is no pages to paginate on log page</li>\n<li>Fixed: Resolved escaped html in the ignore text output</li>\n<li>Fixed: Allow bulk ignores to handle very large batches of ignores with alt query</li>\n</ul>\n<h4> 1.7.0 </h4>\n<ul>\n<li>Updated: Tested up to WP 6.5.2</li>\n<li>Updated: logic on asset loading</li>\n<li>Added: full site scan speed setting</li>\n<li>Fixed: full site scan API alert showing when no post types are selected</li>\n</ul>\n<h4> 1.6.0 </h4>\n<ul>\n<li>Added: scan_start, scan_reset and scan_progress WP Rest API calls to replace admin-ajax calls</li>\n<li>Added: start-new-scan rest call</li>\n<li>Moved: <code>edacp_scan_start</code> from accessibility-checker-pro to <code>EDACP\\Scans::start_php_scan</code></li>\n<li>Updated: <code>activation.php</code> to use <code>EDACP\\Scans::start_php_scan</code></li>\n<li>Deleted: CSS for log from full site scan page</li>\n<li>Moved: <code>getScanStats</code> code from <code>/src/fullSiteScanApp/checkPages.js</code> to <code>/src/fullSiteScanApp/fullSiteScanUI.js</code></li>\n<li>Deleted: jquery from <code>/src/fullSiteScanApp/fullSiteScanUI.js</code></li>\n<li>Added: a page reload every ten minutes to full site scan a page</li>\n<li>Deleted: setting authorization header in rest calls</li>\n<li>Fixed:  mismatched number of URLs scanned</li>\n<li>Fixed: type in global ignore title</li>\n<li>Fixed: pluralization of full site summary stats</li>\n</ul>\n<h4> 1.5.2 </h4>\n<ul>\n<li>Added: Audit History 1.0.0 and 1.0.1 update fix</li>\n<li>Fixed: variable casting</li>\n</ul>\n<h4> 1.5.1 </h4>\n<ul>\n<li>Fixed: open issues descriptions output</li>\n</ul>\n<h4> 1.5.0 </h4>\n<ul>\n<li>Fixed: Issues with JavaScript assets not loading</li>\n<li>Updated: Full-site scan now supports JavaScript scanning</li>\n<li>Added: \'Stop\' button for full-site scanning</li>\n<li>Updated: Posts to scan function optimized for paging and using only IDs</li>\n<li>Removed: \'accessibility_checker_logs\' database table</li>\n<li>Added: Code improvements in the database update function</li>\n<li>Removed: Full site scan log to enhance performance</li>\n<li>Removed: Background scan schedule to align with new full site scanning</li>\n<li>Updated: Full site scan completion message updated to reflect log removal</li>\n</ul>\n<h4> 1.4.3 </h4>\n<ul>\n<li>Updated: version and readme</li>\n</ul>\n<h4> 1.4.2 </h4>\n<ul>\n<li>Updated: readme</li>\n</ul>\n<h4> 1.4.1 </h4>\n<ul>\n<li>Fixed: delete all data on uninstall option</li>\n<li>Fixed: misnamed authorization options and added migration function</li>\n<li>Update: password protection to pass authorization to wp-cron</li>\n<li>Fixed: expired license notice after key renews</li>\n<li>Added: image column to individual open issues and fast track</li>\n<li>Fixed: incorrect fieldname "objectid" in SQL call when clicking affected code in the table header on the issue log.</li>\n</ul>\n<h4> 1.4.0 </h4>\n<ul>\n<li>Fixed: adherence to coding standards</li>\n<li>Fixed: full-site scan stop button issue</li>\n<li>Fixed: settings page tab order</li>\n<li>Fixed: full-site scan error when no custom post types are configured for scanning in settings</li>\n<li>Fixed: activation issue when no custom post types are designated for scanning in settings</li>\n<li>Added: warnings when no custom post types are configured for scanning in settings</li>\n<li>Updated: full-site scan completion date now uses site\'s localized timezone</li>\n<li>Updated: refresh and caching for reports dashboard widget and welcome page</li>\n</ul>\n<h4> 1.3.1 </h4>\n<ul>\n<li>Fixed - scan log output</li>\n<li>Fixed - ignore log not filtering by issue</li>\n</ul>\n<h4> 1.3.0 </h4>\n<ul>\n<li>Added: plugin architecture for converting PHP checks to JavaScript</li>\n<li>Added: JavaScript scanning for color contrast check</li>\n<li>Updated: full-site scan with a secondary JavaScript pass</li>\n<li>Updated: full-site scan log output for better performance</li>\n<li>Added: full-site scan stop button</li>\n<li>Updated: open issues table with accessibility improvements</li>\n<li>Added: frontend highlighting view on-page links</li>\n</ul>\n<h4> 1.2.9 </h4>\n<ul>\n<li>Fixed: activation issue with the valid table name function and the dependency installer</li>\n</ul>\n<h4> 1.2.8 </h4>\n<ul>\n<li>Fixed: issue with zip file name</li>\n</ul>\n<h4> 1.2.7 </h4>\n<ul>\n<li>Added: filterable query limit to the full site scan log</li>\n<li>Updated: full site scan to only run if a custom post type is selected in the settings</li>\n<li>Updated: full site scan to delete data for post types no longer selected in the settings</li>\n<li>Fixed: bug with global ignores being added to all individually ignored issue count</li>\n<li>Fixed: usort deprecated notice on ignore log</li>\n</ul>\n<h4> 1.2.6 </h4>\n<ul>\n<li>Fixed: open issues with no errors to show as passed</li>\n<li>Updated: Action Scheduler to latest version</li>\n<li>Update: Action Scheduler to load via Composer</li>\n</ul>\n<h4> 1.2.5 </h4>\n<ul>\n<li>Fixed: post type count on full size scan</li>\n</ul>\n<h4> 1.2.4 </h4>\n<ul>\n<li>Updated: admin notice output</li>\n</ul>\n<h4> 1.2.3 </h4>\n<ul>\n<li>Added: license tab</li>\n<li>Updated: license check to run via cronjob</li>\n<li>Updated: EDD license class</li>\n</ul>\n<h4> 1.2.2 </h4>\n<ul>\n<li>Added: security updates</li>\n</ul>\n<h4> 1.2.1 </h4>\n<ul>\n<li>Added: Support for the Restricted Access Plugin</li>\n<li>Added: Password protection settings</li>\n</ul>\n<h4> 1.2.0 </h4>\n<ul>\n<li>Update: Heading order on Open Issues, Fast Track, Ignore Log and Global Ignores pages</li>\n<li>Added: Initial rule list page ordered by count to the Open Issues and Ignore Log pages</li>\n<li>Added: Individual rule pages with count, issue summary and rule select to quickly switched between issues to the Open Issues and Ignore Log pages</li>\n<li>Added: Custom Post Type select to Fast Track to reduce query load and improve performance</li>\n</ul>\n<h4> 1.1.9 </h4>\n<ul>\n<li>Update dependency installer to latest version fixing dismiss-notice.js 404</li>\n</ul>\n<h4> 1.1.8 </h4>\n<ul>\n<li>Update log filter admin url</li>\n</ul>\n<h4> 1.1.7 </h4>\n<ul>\n<li>Show Open Issues and Ignore Log admin pages to users with ignore permissions</li>\n</ul>\n<h4> 1.1.6 </h4>\n<ul>\n<li>Add support for PHP 8</li>\n</ul>\n<h4> 1.1.5 </h4>\n<ul>\n<li>Move accessibility statement free plugin</li>\n</ul>\n<h4> 1.1.4 </h4>\n<ul>\n<li>Update license domain and product name</li>\n</ul>\n<h4> 1.1.3 </h4>\n<ul>\n<li>Improvements to license activation/deactivation settings</li>\n</ul>\n<h4> 1.1.2 </h4>\n<ul>\n<li>Add support for Accessibility New Window Warning Plugin</li>\n<li>Plugin dependency installer</li>\n</ul>\n<h4> 1.1.1 </h4>\n<ul>\n<li>Fix to allow ignores database to be deleted on uninstall</li>\n</ul>\n<h4> 1.1.0 </h4>\n<ul>\n<li>Fast Track</li>\n</ul>\n<h4> 1.0.3 </h4>\n<ul>\n<li>Updates to database creation/updates</li>\n<li>Updates to plugin updater</li>\n<li>Deprecated jQuery fixes</li>\n</ul>\n<h4> 1.0.2 </h4>\n<ul>\n<li>Full site scan and background scan</li>\n</ul>\n<h4> 1.0.1 </h4>\n<ul>\n<li>Removed content hook</li>\n<li>Fixed issue with log search if post type has been Removed</li>\n<li>Fixed duplicate column names in screen options</li>\n</ul>\n<h4> 1.0.0 </h4>\n<ul>\n<li>Everything is new and shiny.</li>\n<li>We think it\'s awesome you want to make your website more accessible.</li>\n<li>Thank you for purchasing Accessibility Checker Pro.</li>\n</ul>";}s:6:"plugin";s:55:"accessibility-checker-pro/accessibility-checker-pro.php";s:2:"id";s:55:"accessibility-checker-pro/accessibility-checker-pro.php";}s:75:"accessibility-checker-audit-history/accessibility-checker-audit-history.php";O:8:"stdClass":38:{s:4:"name";s:35:"Accessibility Checker Audit History";s:11:"new_version";s:5:"1.4.0";s:14:"stable_version";s:5:"1.4.0";s:8:"sections";O:8:"stdClass":4:{s:11:"description";s:1691:"<p>Accessibility Checker Audit History is an advanced add-on for Accessibility Checker Pro, designed to enhance your accessibility assessment capabilities. This premium extension enables\nusers to systematically record and revisit accessibility evaluations, allowing for comprehensive over-time comparisons and in-depth site accessibility analysis.</p>\n<p>Key Features:</p>\n<ul>\n<li><strong>Audit History Dashboard:</strong> Centralized and intuitive dashboard for all your audit records.</li>\n<li><strong>Exportable Data:</strong> Easily export your audit history to CSV for further analysis or reporting.</li>\n<li><strong>Visual Data Graphs:</strong> Understand your site’s accessibility trends with clear and concise data graphs.</li>\n<li><strong>Comprehensive Audit List:</strong> Quickly refer to your entire audit history from a centralized list.</li>\n<li><strong>Date Range Filters:</strong> Customize your view and analysis by applying specific date range filters.</li>\n<li><strong>Change Insight:</strong> Gain valuable insight with calculated percentages showcasing changes in accessibility over time.</li>\n<li><strong>Enhanced Accessibility Management:</strong> With additional features aimed at providing a more holistic view of your site’s accessibility status.</li>\n</ul>\n<p><strong>Note:</strong> Accessibility Checker Audit History is a premium add-on, and it requires the installation and activation of Accessibility Checker Pro to function properly. To purchase a\nlicense, visit the <a href="https://equalizedigital.com/accessibility-checker/pricing/?utm_source=EDACAuditHistory&amp;utm_medium=software&amp;utm_campaign=readme">Accessibility Checker Pro website</a>.</p>";s:12:"installation";s:1006:"<p>This add-on requires both Accessibility Checker Free and Accessibility Checker Pro plugins to be installed and active. You must have a small business or above license for it to work.</p>\n<h3>Installing Accessibility Checker Audit History Within WordPress</h3>\n<ol>\n<li>Navigate to ‘Plugins &gt; Add New’ within your WordPress dashboard.</li>\n<li>Click the "Upload Plugin" button on the Add Plugins screen.</li>\n<li>Upload and install the zipped plugin file you received via your download link.</li>\n<li>Once uploaded, activate ‘Accessibility Checker Audit History’ from your Plugins page.</li>\n</ol>\n<h3>Installing Accessibility Checker Audit History Manually</h3>\n<ol>\n<li>Extract the ‘accessibility-checker-audit-history’ folder from the provided zip file.</li>\n<li>Using FTP, upload the extracted folder to the /wp-content/plugins/ directory on your web server.</li>\n<li>Activate ‘Accessibility Checker: Audit History’ from your Plugins page within the WordPress dashboard.</li>\n</ol>";s:9:"changelog";s:1802:"<h4> 1.4.0 </h4>\n<ul>\n<li>Improved: License messages and handling.</li>\n<li>Tweaked: Set sslverify to true for license requests.</li>\n</ul>\n<h4> 1.3.0 </h4>\n<ul>\n<li>Added: New filter to customize the capabilities that can see the audit history page.</li>\n</ul>\n<h4> 1.2.0 </h4>\n<ul>\n<li>Added: translation files</li>\n</ul>\n<h4> 1.1.2 </h4>\n<ul>\n<li>Fixes: Handle some situations the audit history page link would not appear in the menu.</li>\n</ul>\n<h4> 1.1.1 </h4>\n<ul>\n<li>Fixes: Handle notifications in the plugin better.</li>\n</ul>\n<h4> 1.1.0 </h4>\n<ul>\n<li>Fixes: Handle some cases where tables do not create on activation.</li>\n</ul>\n<h4> 1.0.4 </h4>\n<ul>\n<li>Added: demo support</li>\n</ul>\n<h4> 1.0.3 </h4>\n<ul>\n<li>Fixed: check for the existence of the Action Scheduler action at every admin_init and installs if it is not found</li>\n</ul>\n<h4> 1.0.2 </h4>\n<ul>\n<li>Fixed: automatic updates not working</li>\n<li>Update: php and js coding standards</li>\n<li>Update: development and build scripts</li>\n</ul>\n<h4> 1.0.1 </h4>\n<ul>\n<li>Fixed: invalid date error message not announced to screen readers</li>\n<li>Fixed: chart "too high" message</li>\n<li>Updated: chart labels with better read out for screen readers</li>\n<li>Updated: chart date format</li>\n<li>Updated: license admin notice flow and API logic</li>\n<li>Updated: date modal apply button to not be disabled</li>\n<li>Added: role and aria-label attributes to the graph</li>\n<li>Updated: role attribute on modal</li>\n<li>Added: explainer when plugin is first installed</li>\n<li>Added: logic to only load classes and assets in admin</li>\n<li>Added: Action Scheduler performance updates</li>\n</ul>\n<h4> 1.0.0 </h4>\n<ul>\n<li>Everything is new and shiny.</li>\n<li>We think it\'s awesome you want to make your website more accessible.</li>\n</ul>";s:3:"faq";s:2175:"<h4>What support is included?</h4>\n<p>Equalize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and troubleshooting\nassistance. You may <a href="https://my.equalizedigital.com/support/pro-support/">open a support ticket</a> at any time. Plugin support is limited to providing assistance in using the plugin but\ndoes not include support resolving any specific accessibility issues that have been identified.</p>\n<h4>Can you help me figure out how to fix an error or warning on my website?</h4>\n<p>If you have questions about specific errors and warnings on your website or need help fixing problems, we offer remediation support during Office Hours for Small Business and Agency license holders. If you want more personalized auditing and dev help fixing problems on your website, check out our <a href="https://equalizedigital.com/services/website-accessibility-remediation/#pricing-plans">audit and remediation plans</a>.</p>\n<h4>Do I lose functionality if my license key is not active?</h4>\n<p>To utilize Accessibility Checker Audit History features and receive plugin updates and support, you do need to have an active license key. If your license key has expired, you can\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.</p>\n<h4>Can I change how often the audit scan runs?</h4>\n<p>The audit scan runs daily by default. To change the interval to something else you can use this custom filter: accessibility-checker-audit-history_audit_save_interval.\nHere is example code to change the interval to once per week:</p>\n<pre>\nadd_filter( \'accessibility-checker-audit-history_audit_save_interval\' , function( $minutes ){\n    return 60 * 24 * 7; // Number of minutes in a week.\n});\n</pre>\n<h4>How can I report security bugs?</h4>\n<p>You can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. <a href="https://patchstack.com/database/vdp/9e5fbe42-a7e1-4794-ad5f-db248d5ec7ee">Report a security vulnerability.</a></p>\n";}s:13:"license_check";s:0:"";s:3:"msg";s:0:"";s:8:"homepage";s:50:"https://equalizedigital.com/accessibility-checker/";s:7:"package";s:223:"https://my.equalizedigital.com/edd-sl/package_download/MTc3MjI0ODA2ODo1OGJiYTIwY2Q2ZTUyYTQ0YWNhMGJmOTQwNmRlNDczYzoxMTk3MDo2OTk0NGIwOTM2NzNmOTEwM2I1ODFkZDUxOTFiNWY1YzpodHRwc0AvL2JlcmtoYW1jb3Vucy53cGVuZ2luZXBvd2VyZWQuY29tOjA=";s:5:"icons";a:0:{}s:7:"banners";O:8:"stdClass":2:{s:4:"high";s:87:"https://my.equalizedigital.com/wp-content/uploads/sites/4/edd/2023/11/Audit-History.png";s:3:"low";s:93:"https://my.equalizedigital.com/wp-content/uploads/sites/4/edd/2023/11/Audit-History-Small.png";}s:4:"slug";s:35:"accessibility-checker-audit-history";s:3:"url";s:89:"https://my.equalizedigital.com/downloads/accessibility-checker-audit-history/?changelog=1";s:12:"last_updated";s:19:"2025-12-17 23:40:22";s:13:"download_link";s:223:"https://my.equalizedigital.com/edd-sl/package_download/MTc3MjI0ODA2ODo1OGJiYTIwY2Q2ZTUyYTQ0YWNhMGJmOTQwNmRlNDczYzoxMTk3MDo2OTk0NGIwOTM2NzNmOTEwM2I1ODFkZDUxOTFiNWY1YzpodHRwc0AvL2JlcmtoYW1jb3Vucy53cGVuZ2luZXBvd2VyZWQuY29tOjA=";s:4:"tags";a:5:{i:0;s:13:"accessibility";i:1;s:10:"accessible";i:2;s:4:"wcag";i:3;s:3:"ada";i:4;s:4:"a11y";}s:8:"requires";s:3:"6.5";s:6:"tested";s:5:"6.8.0";s:12:"requires_php";s:0:"";s:12:"contributors";O:8:"stdClass":3:{s:15:"equalizedigital";O:8:"stdClass":3:{s:12:"display_name";s:15:"equalizedigital";s:7:"profile";s:40:"//profiles.wordpress.org/equalizedigital";s:6:"avatar";s:60:"https://wordpress.org/grav-redirect.php?user=equalizedigital";}s:7:"alh0319";O:8:"stdClass":3:{s:12:"display_name";s:7:"alh0319";s:7:"profile";s:32:"//profiles.wordpress.org/alh0319";s:6:"avatar";s:52:"https://wordpress.org/grav-redirect.php?user=alh0319";}s:13:"stevejonesdev";O:8:"stdClass":3:{s:12:"display_name";s:13:"stevejonesdev";s:7:"profile";s:38:"//profiles.wordpress.org/stevejonesdev";s:6:"avatar";s:58:"https://wordpress.org/grav-redirect.php?user=stevejonesdev";}}s:10:"stable_tag";s:5:"1.3.0";s:11:"donate_link";s:0:"";s:17:"short_description";s:136:"This add-on introduces Audit History to Accessibility Checker, allowing users to monitor and review accessibility assessments over time.";s:7:"license";s:14:"GPLv2 or later";s:14:"upgrade_notice";s:0:"";s:11:"screenshots";a:0:{}s:3:"faq";a:1:{i:0;s:2175:"<h4>What support is included?</h4>\n<p>Equalize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and troubleshooting\nassistance. You may <a href="https://my.equalizedigital.com/support/pro-support/">open a support ticket</a> at any time. Plugin support is limited to providing assistance in using the plugin but\ndoes not include support resolving any specific accessibility issues that have been identified.</p>\n<h4>Can you help me figure out how to fix an error or warning on my website?</h4>\n<p>If you have questions about specific errors and warnings on your website or need help fixing problems, we offer remediation support during Office Hours for Small Business and Agency license holders. If you want more personalized auditing and dev help fixing problems on your website, check out our <a href="https://equalizedigital.com/services/website-accessibility-remediation/#pricing-plans">audit and remediation plans</a>.</p>\n<h4>Do I lose functionality if my license key is not active?</h4>\n<p>To utilize Accessibility Checker Audit History features and receive plugin updates and support, you do need to have an active license key. If your license key has expired, you can\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.</p>\n<h4>Can I change how often the audit scan runs?</h4>\n<p>The audit scan runs daily by default. To change the interval to something else you can use this custom filter: accessibility-checker-audit-history_audit_save_interval.\nHere is example code to change the interval to once per week:</p>\n<pre>\nadd_filter( \'accessibility-checker-audit-history_audit_save_interval\' , function( $minutes ){\n    return 60 * 24 * 7; // Number of minutes in a week.\n});\n</pre>\n<h4>How can I report security bugs?</h4>\n<p>You can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. <a href="https://patchstack.com/database/vdp/9e5fbe42-a7e1-4794-ad5f-db248d5ec7ee">Report a security vulnerability.</a></p>\n";}s:8:"warnings";O:8:"stdClass":1:{s:13:"too_many_tags";a:4:{i:0;s:11:"section 508";i:1;s:5:"audit";i:2;s:11:"readability";i:3;s:16:"content analysis";}}s:17:"expected_sections";a:7:{i:0;s:11:"description";i:1;s:12:"installation";i:2;s:3:"faq";i:3;s:11:"screenshots";i:4;s:9:"changelog";i:5;s:14:"upgrade_notice";i:6;s:11:"other_notes";}s:14:"alias_sections";O:8:"stdClass":3:{s:26:"frequently_asked_questions";s:3:"faq";s:10:"change_log";s:9:"changelog";s:10:"screenshot";s:11:"screenshots";}s:13:"valid_headers";O:8:"stdClass":11:{s:6:"tested";s:6:"tested";s:12:"tested up to";s:6:"tested";s:8:"requires";s:8:"requires";s:17:"requires at least";s:8:"requires";s:12:"requires php";s:12:"requires_php";s:4:"tags";s:4:"tags";s:12:"contributors";s:12:"contributors";s:11:"donate link";s:11:"donate_link";s:10:"stable tag";s:10:"stable_tag";s:7:"license";s:7:"license";s:11:"license uri";s:11:"license_uri";}s:11:"ignore_tags";a:2:{i:0;s:6:"plugin";i:1;s:9:"wordpress";}s:21:"maximum_field_lengths";O:8:"stdClass":4:{s:17:"short_description";i:150;s:7:"section";i:2500;s:17:"section-changelog";i:5000;s:11:"section-faq";i:5000;}s:12:"raw_contents";s:6520:"=== Accessibility Checker Audit History ===\nContributors: equalizedigital, alh0319, stevejonesdev\nTags: accessibility, accessible, wcag, ada, a11y, section 508, audit, readability, content analysis\nRequires at least: 6.5\nTested up to: 6.8.0\nStable tag: 1.3.0\nLicense: GPLv2 or later\nLicense URI: https://www.gnu.org/licenses/gpl-2.0.html\n\nThis add-on introduces Audit History to Accessibility Checker, allowing users to monitor and review accessibility assessments over time.\n\n== Description ==\n\nAccessibility Checker Audit History is an advanced add-on for Accessibility Checker Pro, designed to enhance your accessibility assessment capabilities. This premium extension enables\nusers to systematically record and revisit accessibility evaluations, allowing for comprehensive over-time comparisons and in-depth site accessibility analysis.\n\nKey Features:\n\n* **Audit History Dashboard:** Centralized and intuitive dashboard for all your audit records.\n* **Exportable Data:** Easily export your audit history to CSV for further analysis or reporting.\n* **Visual Data Graphs:** Understand your site’s accessibility trends with clear and concise data graphs.\n* **Comprehensive Audit List:** Quickly refer to your entire audit history from a centralized list.\n* **Date Range Filters:** Customize your view and analysis by applying specific date range filters.\n* **Change Insight:** Gain valuable insight with calculated percentages showcasing changes in accessibility over time.\n* **Enhanced Accessibility Management:** With additional features aimed at providing a more holistic view of your site’s accessibility status.\n\n**Note:** Accessibility Checker Audit History is a premium add-on, and it requires the installation and activation of Accessibility Checker Pro to function properly. To purchase a\nlicense, visit the [Accessibility Checker Pro website](https://equalizedigital.com/accessibility-checker/pricing/?utm_source=EDACAuditHistory&utm_medium=software&utm_campaign=readme).\n\n== Installation ==\nThis add-on requires both Accessibility Checker Free and Accessibility Checker Pro plugins to be installed and active. You must have a small business or above license for it to work.\n\n### Installing Accessibility Checker Audit History Within WordPress\n1. Navigate to ‘Plugins > Add New’ within your WordPress dashboard.\n2. Click the "Upload Plugin" button on the Add Plugins screen.\n3. Upload and install the zipped plugin file you received via your download link.\n4. Once uploaded, activate ‘Accessibility Checker Audit History’ from your Plugins page.\n\n\n### Installing Accessibility Checker Audit History Manually\n\n1. Extract the ‘accessibility-checker-audit-history’ folder from the provided zip file.\n2. Using FTP, upload the extracted folder to the /wp-content/plugins/ directory on your web server.\n3. Activate ‘Accessibility Checker: Audit History’ from your Plugins page within the WordPress dashboard.\n\n\n\n== Frequently Asked Questions ==\n\n= What support is included? =\n\nEqualize Digital provides free personalized support on plugin usage and features via email for all license holders. This includes information about functionality and troubleshooting\nassistance. You may [open a support ticket](https://my.equalizedigital.com/support/pro-support/) at any time. Plugin support is limited to providing assistance in using the plugin but\ndoes not include support resolving any specific accessibility issues that have been identified.\n\n= Can you help me figure out how to fix an error or warning on my website? =\n\nIf you have questions about specific errors and warnings on your website or need help fixing problems, we offer remediation support during Office Hours for Small Business and Agency license holders. If you want more personalized auditing and dev help fixing problems on your website, check out our [audit and remediation plans](https://equalizedigital.com/services/website-accessibility-remediation/#pricing-plans).\n\n= Do I lose functionality if my license key is not active? =\n\nTo utilize Accessibility Checker Audit History features and receive plugin updates and support, you do need to have an active license key. If your license key has expired, you can\ncontinue to use the free version of Accessibility Checker but will lose access to Pro features.\n\n= Can I change how often the audit scan runs? =\n\nThe audit scan runs daily by default. To change the interval to something else you can use this custom filter: accessibility-checker-audit-history_audit_save_interval.\nHere is example code to change the interval to once per week:\n\n<pre>\nadd_filter( \'accessibility-checker-audit-history_audit_save_interval\' , function( $minutes ){\n    return 60 * 24 * 7; // Number of minutes in a week.\n});\n</pre>\n\n= How can I report security bugs? =\n\nYou can report security bugs through the Patchstack Vulnerability Disclosure Program. The Patchstack team helps validate, triage and handle any security vulnerabilities. [Report a security vulnerability.](https://patchstack.com/database/vdp/9e5fbe42-a7e1-4794-ad5f-db248d5ec7ee)\n\n== Changelog ==\n= 1.4.0 =\n* Improved: License messages and handling.\n* Tweaked: Set sslverify to true for license requests.\n\n= 1.3.0 =\n* Added: New filter to customize the capabilities that can see the audit history page.\n\n= 1.2.0 =\n* Added: translation files\n\n= 1.1.2 =\n* Fixes: Handle some situations the audit history page link would not appear in the menu.\n\n= 1.1.1 =\n* Fixes: Handle notifications in the plugin better.\n\n= 1.1.0 =\n* Fixes: Handle some cases where tables do not create on activation.\n\n= 1.0.4 =\n* Added: demo support\n\n= 1.0.3 =\n* Fixed: check for the existence of the Action Scheduler action at every admin_init and installs if it is not found\n\n= 1.0.2 =\n* Fixed: automatic updates not working\n* Update: php and js coding standards\n* Update: development and build scripts\n\n= 1.0.1 =\n* Fixed: invalid date error message not announced to screen readers\n* Fixed: chart "too high" message\n* Updated: chart labels with better read out for screen readers\n* Updated: chart date format\n* Updated: license admin notice flow and API logic\n* Updated: date modal apply button to not be disabled\n* Added: role and aria-label attributes to the graph\n* Updated: role attribute on modal\n* Added: explainer when plugin is first installed\n* Added: logic to only load classes and assets in admin\n* Added: Action Scheduler performance updates\n\n= 1.0.0 =\n* Everything is new and shiny.\n* We think it\'s awesome you want to make your website more accessible.\n";s:11:"description";a:1:{i:0;s:1691:"<p>Accessibility Checker Audit History is an advanced add-on for Accessibility Checker Pro, designed to enhance your accessibility assessment capabilities. This premium extension enables\nusers to systematically record and revisit accessibility evaluations, allowing for comprehensive over-time comparisons and in-depth site accessibility analysis.</p>\n<p>Key Features:</p>\n<ul>\n<li><strong>Audit History Dashboard:</strong> Centralized and intuitive dashboard for all your audit records.</li>\n<li><strong>Exportable Data:</strong> Easily export your audit history to CSV for further analysis or reporting.</li>\n<li><strong>Visual Data Graphs:</strong> Understand your site’s accessibility trends with clear and concise data graphs.</li>\n<li><strong>Comprehensive Audit List:</strong> Quickly refer to your entire audit history from a centralized list.</li>\n<li><strong>Date Range Filters:</strong> Customize your view and analysis by applying specific date range filters.</li>\n<li><strong>Change Insight:</strong> Gain valuable insight with calculated percentages showcasing changes in accessibility over time.</li>\n<li><strong>Enhanced Accessibility Management:</strong> With additional features aimed at providing a more holistic view of your site’s accessibility status.</li>\n</ul>\n<p><strong>Note:</strong> Accessibility Checker Audit History is a premium add-on, and it requires the installation and activation of Accessibility Checker Pro to function properly. To purchase a\nlicense, visit the <a href="https://equalizedigital.com/accessibility-checker/pricing/?utm_source=EDACAuditHistory&amp;utm_medium=software&amp;utm_campaign=readme">Accessibility Checker Pro website</a>.</p>";}s:12:"installation";a:1:{i:0;s:1006:"<p>This add-on requires both Accessibility Checker Free and Accessibility Checker Pro plugins to be installed and active. You must have a small business or above license for it to work.</p>\n<h3>Installing Accessibility Checker Audit History Within WordPress</h3>\n<ol>\n<li>Navigate to ‘Plugins &gt; Add New’ within your WordPress dashboard.</li>\n<li>Click the "Upload Plugin" button on the Add Plugins screen.</li>\n<li>Upload and install the zipped plugin file you received via your download link.</li>\n<li>Once uploaded, activate ‘Accessibility Checker Audit History’ from your Plugins page.</li>\n</ol>\n<h3>Installing Accessibility Checker Audit History Manually</h3>\n<ol>\n<li>Extract the ‘accessibility-checker-audit-history’ folder from the provided zip file.</li>\n<li>Using FTP, upload the extracted folder to the /wp-content/plugins/ directory on your web server.</li>\n<li>Activate ‘Accessibility Checker: Audit History’ from your Plugins page within the WordPress dashboard.</li>\n</ol>";}s:9:"changelog";a:1:{i:0;s:1802:"<h4> 1.4.0 </h4>\n<ul>\n<li>Improved: License messages and handling.</li>\n<li>Tweaked: Set sslverify to true for license requests.</li>\n</ul>\n<h4> 1.3.0 </h4>\n<ul>\n<li>Added: New filter to customize the capabilities that can see the audit history page.</li>\n</ul>\n<h4> 1.2.0 </h4>\n<ul>\n<li>Added: translation files</li>\n</ul>\n<h4> 1.1.2 </h4>\n<ul>\n<li>Fixes: Handle some situations the audit history page link would not appear in the menu.</li>\n</ul>\n<h4> 1.1.1 </h4>\n<ul>\n<li>Fixes: Handle notifications in the plugin better.</li>\n</ul>\n<h4> 1.1.0 </h4>\n<ul>\n<li>Fixes: Handle some cases where tables do not create on activation.</li>\n</ul>\n<h4> 1.0.4 </h4>\n<ul>\n<li>Added: demo support</li>\n</ul>\n<h4> 1.0.3 </h4>\n<ul>\n<li>Fixed: check for the existence of the Action Scheduler action at every admin_init and installs if it is not found</li>\n</ul>\n<h4> 1.0.2 </h4>\n<ul>\n<li>Fixed: automatic updates not working</li>\n<li>Update: php and js coding standards</li>\n<li>Update: development and build scripts</li>\n</ul>\n<h4> 1.0.1 </h4>\n<ul>\n<li>Fixed: invalid date error message not announced to screen readers</li>\n<li>Fixed: chart "too high" message</li>\n<li>Updated: chart labels with better read out for screen readers</li>\n<li>Updated: chart date format</li>\n<li>Updated: license admin notice flow and API logic</li>\n<li>Updated: date modal apply button to not be disabled</li>\n<li>Added: role and aria-label attributes to the graph</li>\n<li>Updated: role attribute on modal</li>\n<li>Added: explainer when plugin is first installed</li>\n<li>Added: logic to only load classes and assets in admin</li>\n<li>Added: Action Scheduler performance updates</li>\n</ul>\n<h4> 1.0.0 </h4>\n<ul>\n<li>Everything is new and shiny.</li>\n<li>We think it\'s awesome you want to make your website more accessible.</li>\n</ul>";}s:6:"plugin";s:75:"accessibility-checker-audit-history/accessibility-checker-audit-history.php";s:2:"id";s:75:"accessibility-checker-audit-history/accessibility-checker-audit-history.php";}}s:7:"checked";a:52:{s:85:"abbreviation-button-for-the-block-editor/abbreviation-button-for-the-block-editor.php";s:3:"0.1";s:47:"accessibility-checker/accessibility-checker.php";s:6:"1.37.0";s:75:"accessibility-checker-audit-history/accessibility-checker-audit-history.php";s:5:"1.4.0";s:55:"accessibility-checker-pro/accessibility-checker-pro.php";s:6:"1.20.0";s:71:"accessibility-new-window-warnings/accessibility-new-window-warnings.php";s:5:"1.2.0";s:37:"action-scheduler/action-scheduler.php";s:5:"3.9.3";s:27:"ai-services/ai-services.php";s:5:"0.7.4";s:19:"akismet/akismet.php";s:3:"5.6";s:29:"antispam-bee/antispam_bee.php";s:6:"2.11.8";s:29:"cimo-image-optimizer/cimo.php";s:5:"1.2.2";s:41:"create-block-theme/create-block-theme.php";s:5:"2.8.0";s:25:"auto-sizes/auto-sizes.php";s:5:"1.7.0";s:23:"filter-ai/filter-ai.php";s:5:"1.5.0";s:33:"genesis-blocks/genesis-blocks.php";s:5:"3.1.8";s:29:"gravityforms/gravityforms.php";s:6:"2.9.28";s:30:"dominant-color-im