(25, 2, 'wp_yoast_notifications', 'a:2:{i:0;a:2:{s:7:"message";s:361:"<p>You can speed up your site and get insight into your internal linking structure by letting us perform a few optimizations to the way SEO data is stored. We estimate this will take less than a minute.</p><a class="button" href="https://berkhamcouns.wpenginepowered.com/wp-admin/admin.php?page=wpseo_tools&start-indexation=true">Start SEO data optimization</a>";s:7:"options";a:11:{s:4:"type";s:7:"warning";s:2:"id";s:13:"wpseo-reindex";s:7:"user_id";i:2;s:5:"nonce";N;s:8:"priority";d:0.8;s:9:"data_json";a:0:{}s:13:"dismissal_key";N;s:12:"capabilities";s:20:"wpseo_manage_options";s:16:"capability_check";s:3:"all";s:14:"yoast_branding";b:0;s:13:"resolve_nonce";s:0:"";}}i:1;a:2:{s:7:"message";s:494:"<p><strong>Huge SEO Issue: You&#039;re blocking access to robots.</strong> If you want search engines to show this site in their results, you must <a href="https://berkhamcouns.wpenginepowered.com/wp-admin/options-reading.php">go to your Reading Settings</a> and uncheck the box for Search Engine Visibility. <button type="button" id="robotsmessage-dismiss-button" class="button-link hide-if-no-js" data-nonce="3dbbc2456c">I don&#039;t want this site to show in the search results.</button></p>";s:7:"options";a:11:{s:4:"type";s:5:"error";s:2:"id";s:32:"wpseo-search-engines-discouraged";s:7:"user_id";i:2;s:5:"nonce";N;s:8:"priority";i:1;s:9:"data_json";a:0:{}s:13:"dismissal_key";N;s:12:"capabilities";s:20:"wpseo_manage_options";s:16:"capability_check";s:3:"all";s:14:"yoast_branding";b:0;s:13:"resolve_nonce";s:0:"";}}}'),
